def _source_record_count_breakdown_intents(
    query_intents: list[dict[str, Any]] | None,
) -> list[dict[str, Any]]:
    out: list[dict[str, Any]] = []
    candidates: list[dict[str, Any]] = []
    saw_count_intent = False
    for intent in query_intents or []:
        if not isinstance(intent, dict):
            continue
        intent_type = str(intent.get("intent_type", "")).strip()
        if intent_type not in {"count", "amount_inventory", "list"}:
            continue
        candidates.append(intent)
        if intent_type == "count":
            saw_count_intent = True
        constraint_tokens = _query_intent_constraint_tokens(intent)
        raw_constraints = " ".join(str(item or "") for item in intent.get("answer_constraints", []) or [])
        raw_constraint_tokens = set(re.split(r"[^a-z0-9]+", raw_constraints.casefold()))
        if (
            constraint_tokens & _COUNT_BREAKDOWN_CONSTRAINT_TOKENS
            or raw_constraint_tokens & _COUNT_BREAKDOWN_CONSTRAINT_TOKENS
            or "_vs_" in raw_constraints.casefold()
        ):
            out.append(intent)
    if out:
        return out
    if saw_count_intent and len(_source_record_count_breakdown_target_groups(candidates)) >= 3:
        return candidates
    return []


def _source_record_count_breakdown_target_groups(intents: list[dict[str, Any]]) -> list[set[str]]:
    groups: list[set[str]] = []
    seen: set[tuple[str, ...]] = set()
    for intent in intents:
        for term in intent.get("target_terms", []) or []:
            group: set[str] = set()
            for token in _source_record_unicode_word_tokens(str(term)):
                if len(token) < 3:
                    continue
                if token in _SEMANTIC_DISPLAY_TARGET_STOP_TERMS or token in GENERIC_QUERY_PLACEHOLDERS:
                    continue
                group.add(token)
            if not group:
                continue
            key = tuple(sorted(_source_record_count_breakdown_token_concept(token) for token in group))
            if key in seen:
                continue
            seen.add(key)
            groups.append(group)
    return groups[:12]


def _source_record_unicode_word_tokens(value: str) -> set[str]:
    normalized = unicodedata.normalize("NFKC", str(value or "")).casefold()
    tokens: set[str] = set()
    current: list[str] = []
    for char in normalized:
        if char.isalnum():
            current.append(char)
            continue
        if current:
            token = "".join(current).strip()
            if token:
                tokens.add(token)
            current = []
    if current:
        token = "".join(current).strip()
        if token:
            tokens.add(token)
    return tokens


def _source_record_count_breakdown_group_match(
    *,
    target_groups: list[set[str]],
    display_tokens: set[str],
) -> dict[str, Any]:
    out: list[str] = []
    seen_concepts: set[str] = set()
    display_concepts = {_source_record_count_breakdown_token_concept(token) for token in display_tokens}
    group_count = 0
    strong_group_count = 0
    for group in target_groups:
        group_matched = 0
        group_concepts = {_source_record_count_breakdown_token_concept(token) for token in group}
        for token in sorted(group):
            concept = _source_record_count_breakdown_token_concept(token)
            if not _source_record_count_breakdown_token_matches(
                token=token,
                concept=concept,
                display_tokens=display_tokens,
                display_concepts=display_concepts,
            ):
                continue
            group_matched += 1
            if concept in seen_concepts:
                continue
            seen_concepts.add(concept)
            out.append(token)
        if group_matched:
            group_count += 1
        if len(group_concepts) >= 2 and group_matched >= min(2, len(group_concepts)):
            strong_group_count += 1
    return {
        "tokens": out,
        "group_count": group_count,
        "strong_group_count": strong_group_count,
    }


def _source_record_count_breakdown_token_matches(
    *,
    token: str,
    concept: str,
    display_tokens: set[str],
    display_concepts: set[str],
) -> bool:
    if token in display_tokens or concept in display_concepts:
        return True
    if len(concept) < 6:
        return False
    return any(
        len(display_concept) >= 6 and (concept in display_concept or display_concept in concept)
        for display_concept in display_concepts
    )


def _source_record_count_breakdown_token_concept(value: str) -> str:
    token = str(value or "").strip()
    if len(token) > 4 and token.endswith("s"):
        return token[:-1]
    return token


def _source_record_count_breakdown_numbers(value: str) -> list[str]:
    text = unicodedata.normalize("NFKC", str(value or ""))
    out: list[str] = []
    for match in re.finditer(r"(?<!\d)[+-]?\d[\d,]*(?:\.\d+)?(?!\d)", text):
        raw = match.group(0).strip()
        normalized = raw.replace(",", "")
        if not normalized or normalized in {"+", "-"}:
            continue
        out.append(raw)
    non_years: list[str] = []
    for raw in out:
        normalized = raw.replace(",", "")
        try:
            number = int(float(normalized))
        except ValueError:
            non_years.append(raw)
            continue
        if 1900 <= number <= 2099 and re.fullmatch(r"\d{4}", normalized):
            continue
        non_years.append(raw)
    if len(non_years) >= 2:
        return non_years
    if len(non_years) != len(out):
        return non_years
    return out


def _source_record_semantic_target_display_rows(
    runtime: CorePrologRuntime,
    *,
    query_intents: list[dict[str, Any]] | None = None,
) -> list[dict[str, str]]:
    targets = _source_record_semantic_display_targets(query_intents)
    if not targets:
        return []
    rows: list[dict[str, str]] = []
    seen: set[tuple[str, str, str, str]] = set()
    for source_row, surface_kind, cell_index, display in _source_record_display_surfaces(runtime):
        display_norm = _source_display_match_norm(display)
        if not display_norm:
            continue
        for target in targets:
            matched_variant = ""
            match_kind = ""
            for variant in target["variants"]:
                if variant and variant in display_norm:
                    matched_variant = variant
                    match_kind = (
                        "semantic_target_display_substring"
                        if matched_variant == target["variants"][0]
                        else "semantic_target_unicode_fragment"
                    )
                    break
            if not matched_variant:
                matched_variant = _source_record_semantic_target_token_overlap_fragment(
                    display,
                    target=target,
                )
                if matched_variant:
                    match_kind = "semantic_target_token_overlap"
                else:
                    for variant in target.get("token_variants", []):
                        if variant and variant in display_norm:
                            matched_variant = variant
                            match_kind = "semantic_target_long_token_fragment"
                            break
                    if not matched_variant:
                        continue
            key = (source_row, surface_kind, cell_index, target["target"])
            if key in seen:
                continue
            seen.add(key)
            exact_variant = target["variants"][0] if target.get("variants") else matched_variant
            score = 40 + min(len(matched_variant), 40)
            if target["kind"] == "unicode_literal":
                score += 12
            if match_kind == "semantic_target_unicode_fragment":
                score -= 16
            elif match_kind == "semantic_target_token_overlap":
                score -= 12
            elif target["kind"] == "identifier_like":
                score += 8
            rows.append(
                {
                    "SupportKind": "source_record_semantic_target_display",
                    "SupportClass": "deterministic-source-record-summary",
                    "SourceRow": source_row,
                    "SourceSurfaceKind": surface_kind,
                    "SourceCellIndex": cell_index,
                    "TargetTerm": target["target"],
                    "TargetKind": target["kind"],
                    "MatchKind": match_kind,
                    "MatchedDisplayFragment": matched_variant,
                    "SourceTextDisplay": display,
                    "Score": str(score),
                }
            )
    rows.sort(
        key=lambda row: (
            -int(row.get("Score", "0") or "0"),
            _source_row_sort_key(row.get("SourceRow", "")),
            row.get("TargetTerm", ""),
            row.get("SourceSurfaceKind", ""),
        )
    )
    return rows


_SEMANTIC_DISPLAY_TARGET_STOP_TERMS = {
    "answer",
    "article",
    "citation",
    "date",
    "deadline",
    "document",
    "entity",
    "event",
    "item",
    "legal",
    "line",
    "list",
    "name",
    "number",
    "record",
    "reference",
    "report",
    "row",
    "section",
    "source",
    "status",
    "term",
    "text",
    "type",
    "value",
}


def _source_record_semantic_display_targets(
    query_intents: list[dict[str, Any]] | None,
) -> list[dict[str, Any]]:
    out: list[dict[str, Any]] = []
    seen: set[str] = set()
    for raw in _query_intents_raw_target_terms(query_intents):
        target = _clean_source_record_semantic_target(raw)
        if not target:
            continue
        kind = _source_record_semantic_target_kind(target)
        if not kind:
            continue
        variants = _source_record_semantic_target_variants(target, kind=kind)
        if not variants:
            continue
        key = _source_display_match_norm(target)
        if key in seen:
            continue
        seen.add(key)
        out.append(
            {
                "target": target,
                "kind": kind,
                "variants": variants,
                "token_variants": _source_record_semantic_target_long_token_variants(target, kind=kind),
            }
        )
    return out[:16]


def _source_record_semantic_target_token_overlap_fragment(
    display: str,
    *,
    target: dict[str, Any],
) -> str:
    if str(target.get("kind", "")) != "phrase_literal":
        return ""
    target_tokens = [token for token in _source_display_ascii_tokens(str(target.get("target", ""))) if len(token) >= 3]
    if len(target_tokens) < 4:
        return ""
    display_tokens = set(_source_display_ascii_tokens(display))
    hits = [token for token in target_tokens if token in display_tokens]
    threshold = max(4, int((len(target_tokens) * 2 + 2) // 3))
    if len(hits) < threshold:
        return ""
    return " ".join(hits)


def _clean_source_record_semantic_target(value: str) -> str:
    text = str(value or "").strip()
    text = text.strip(" \t\r\n\"'`“”‘’")
    text = re.sub(r"\s+", " ", text)
    return text


def _source_record_semantic_target_kind(value: str) -> str:
    text = str(value or "").strip()
    if _contains_non_ascii_letter(text):
        if len(text) < 2:
            return ""
        return "unicode_literal"
    if len(text) < 3:
        return ""
    if _looks_like_ascii_snake_case_canonical(text):
        return ""
    norm = _source_display_match_norm(text)
    if not norm or norm in _SEMANTIC_DISPLAY_TARGET_STOP_TERMS:
        return ""
    tokens = _source_display_ascii_tokens(text)
    if not tokens:
        return ""
    if all(token in _SEMANTIC_DISPLAY_TARGET_STOP_TERMS or token in GENERIC_QUERY_PLACEHOLDERS for token in tokens):
        return ""
    if len(tokens) >= 2 and sum(len(token) for token in tokens) >= 8:
        return "phrase_literal"
    if re.search(r"\d", text) and len(norm) >= 4:
        return "identifier_like"
    if re.search(r"[-/#.]", text) and len(norm) >= 5:
        return "identifier_like"
    return ""


def _source_record_semantic_target_variants(value: str, *, kind: str) -> list[str]:
    norm = _source_display_match_norm(value)
    variants = [norm] if norm else []
    if kind == "unicode_literal":
        for fragment in _source_record_unicode_target_fragments(value):
            fragment_norm = _source_display_match_norm(fragment)
            if fragment_norm and fragment_norm not in variants:
                variants.append(fragment_norm)
    else:
        spaced = _source_display_match_norm(str(value or "").replace("_", " "))
        if spaced and spaced not in variants:
            variants.append(spaced)
        token_spaced = " ".join(_source_display_ascii_tokens(value))
        if token_spaced and token_spaced not in variants:
            variants.append(token_spaced)
    return variants


def _source_record_semantic_target_long_token_variants(value: str, *, kind: str) -> list[str]:
    if kind != "phrase_literal":
        return []
    tokens = _source_display_ascii_tokens(value)
    if len(tokens) < 4:
        return []
    out: list[str] = []
    for token in tokens:
        if len(token) < 8:
            continue
        if token in _SEMANTIC_DISPLAY_TARGET_STOP_TERMS or token in GENERIC_QUERY_PLACEHOLDERS:
            continue
        if token not in out:
            out.append(token)
    return out[:6]


def _source_record_unicode_target_fragments(value: str) -> list[str]:
    out: list[str] = []
    seen: set[str] = set()
    normalized = unicodedata.normalize("NFKC", str(value or "")).casefold()
    words: list[str] = []
    current: list[str] = []
    for char in normalized:
        if char.isalpha():
            current.append(char)
            continue
        if current:
            words.append("".join(current))
            current = []
    if current:
        words.append("".join(current))
    for word in words:
        if len(word) < 5 or word in seen or not any(not char.isascii() for char in word):
            continue
        seen.add(word)
        out.append(word)
        if len(out) >= 8:
            return out

    text = "".join(char for char in normalized if char.isalpha() and not char.isascii())
    if len(text) < 6:
        return out
    max_fragment_len = min(len(text) - 1, 8)
    for length in range(4, max_fragment_len + 1):
        for fragment in (text[:length], text[-length:]):
            if fragment == text or fragment in seen:
                continue
            seen.add(fragment)
            out.append(fragment)
            if len(out) >= 8:
                return out
    return out


def _source_display_match_norm(value: str) -> str:
    text = unicodedata.normalize("NFKC", str(value or ""))
    text = text.casefold()
    text = re.sub(r"\s+", " ", text)
    return text.strip()


def _source_display_ascii_tokens(value: str) -> list[str]:
    return [token for token in re.split(r"[^a-z0-9]+", _source_display_match_norm(value)) if token]


def _looks_like_ascii_snake_case_canonical(value: str) -> bool:
    text = str(value or "").strip()
    if not text or _contains_non_ascii_letter(text):
        return False
    return bool(re.fullmatch(r"[a-z][a-z0-9]*(?:_[a-z0-9]+)+", text))


def _source_record_alias_translation_query_active(
    query_intents: list[dict[str, Any]] | None,
) -> bool:
    for intent in query_intents or []:
        if not isinstance(intent, dict):
            continue
        tokens = set(_query_intent_constraint_tokens(intent))
        for term in intent.get("target_terms", []) or []:
            tokens.update(_query_atom_tokens(str(term)))
        if tokens & _ALIAS_TRANSLATION_QUERY_TOKENS:
            return True
    return False


def _query_intents_raw_target_terms(query_intents: list[dict[str, Any]] | None) -> list[str]:
    out: list[str] = []
    seen: set[str] = set()
    for intent in query_intents or []:
        if not isinstance(intent, dict):
            continue
        for term in intent.get("target_terms", []) or []:
            text = str(term or "").strip()
            if len(text) < 2:
                continue
            key = text.casefold()
            if key in seen:
                continue
            seen.add(key)
            out.append(text)
    return out


def _source_record_display_surfaces(runtime: CorePrologRuntime) -> list[tuple[str, str, str, str]]:
    out: list[tuple[str, str, str, str]] = []
    seen: set[tuple[str, str, str, str]] = set()
    display_queries = (
        ("source_record_text_display", "source_record_text_display(SourceRow, Text).", "Text"),
        ("source_record_label_display", "source_record_label_display(SourceRow, Text).", "Text"),
        ("source_record_section_display", "source_record_section_display(SourceRow, Text).", "Text"),
    )
    for predicate, query, text_key in display_queries:
        for row in _runtime_rows(runtime, query):
            source_row = str(row.get("SourceRow", "")).strip()
            cell_index = ""
            display = str(row.get(text_key, "")).strip()
            if not source_row or not display:
                continue
            key = (source_row, predicate, cell_index, display)
            if key in seen:
                continue
            seen.add(key)
            out.append(key)
    cell_queries = (
        ("source_record_cell_display", "source_record_cell_display(SourceRow, CellIndex, Text).", "Text"),
        (
            "source_record_cell_header_display",
            "source_record_cell_header_display(SourceRow, CellIndex, Text).",
            "Text",
        ),
    )
    for predicate, query, text_key in cell_queries:
        for row in _runtime_rows(runtime, query):
            source_row = str(row.get("SourceRow", "")).strip()
            cell_index = str(row.get("CellIndex", "")).strip()
            display = str(row.get(text_key, "")).strip()
            if not source_row or not display:
                continue
            key = (source_row, predicate, cell_index, display)
            if key in seen:
                continue
            seen.add(key)
            out.append(key)
    return out


def _source_record_text_display_by_row(runtime: CorePrologRuntime) -> dict[str, str]:
    out: dict[str, str] = {}
    for source_row, surface_kind, _cell_index, display in _source_record_display_surfaces(runtime):
        if surface_kind != "source_record_text_display" or source_row in out:
            continue
        out[source_row] = display
    return out


def _source_record_alias_translation_pairs_from_display(display: str) -> list[dict[str, str]]:
    text = _clean_source_record_alias_display_text(display)
    if len(text) < 5:
        return []
    rows: list[dict[str, str]] = []
    seen: set[tuple[str, str, str]] = set()
    for match in re.finditer(r"(?P<left>[^()\[\]（）［］]{1,180})[\(（\[](?P<inside>[^()\[\]（）［］]{1,90})[\)）\]]", text):
        left = _source_record_alias_left_span(match.group("left"))
        inside = _clean_source_record_alias_span(match.group("inside"))
        pair = _source_record_alias_translation_pair(left=left, inside=inside)
        if not pair:
            continue
        key = (pair["PrimaryDisplay"], pair["AliasDisplay"], pair["AliasKind"])
        if key in seen:
            continue
        seen.add(key)
        rows.append(pair)
    return rows


def _clean_source_record_alias_display_text(value: str) -> str:
    text = str(value or "").strip()
    text = re.sub(r"^\s{0,3}(?:#{1,6}\s*|[-*]\s+|[0-9ivxlcdmIVXLCDM]+[.)]\s+)", "", text)
    text = text.replace("**", "").replace("__", "")
    return re.sub(r"\s+", " ", text).strip()


def _source_record_alias_left_span(value: str) -> str:
    text = _clean_source_record_alias_span(value)
    parts = [part.strip() for part in re.split(r"[\n\r.;:!?。！？、，；：]\s*", text) if part.strip()]
    if parts:
        text = parts[-1]
    words = text.split()
    if len(words) > 12:
        text = " ".join(words[-12:])
    return _clean_source_record_alias_span(text)


def _clean_source_record_alias_span(value: str) -> str:
    text = str(value or "").strip()
    text = text.strip(" \t\r\n-–—:：;；,，.。*#\"'`")
    text = re.sub(r"\s+", " ", text)
    return text.strip()


def _source_record_alias_translation_pair(*, left: str, inside: str) -> dict[str, str] | None:
    if not _source_record_alias_span_meaningful(left) or not _source_record_alias_span_meaningful(inside):
        return None
    if _source_record_alias_span_too_noisy(left) or _source_record_alias_span_too_noisy(inside):
        return None
    left_alias = _looks_like_source_alias_span(left)
    inside_alias = _looks_like_source_alias_span(inside)
    left_ascii_translation = _looks_like_source_ascii_translation_span(left)
    inside_ascii_translation = _looks_like_source_ascii_translation_span(inside)
    left_non_ascii = _contains_non_ascii_letter(left)
    inside_non_ascii = _contains_non_ascii_letter(inside)
    if inside_alias and not left_alias:
        return {
            "PrimaryDisplay": left,
            "AliasDisplay": inside,
            "AliasKind": "parenthetical_alias",
        }
    if left_alias and not inside_alias:
        return {
            "PrimaryDisplay": inside,
            "AliasDisplay": left,
            "AliasKind": "parenthetical_alias",
        }
    if inside_ascii_translation and left_non_ascii:
        return {
            "PrimaryDisplay": left,
            "AliasDisplay": inside,
            "AliasKind": "source_stated_translation",
        }
    if left_ascii_translation and inside_non_ascii:
        return {
            "PrimaryDisplay": inside,
            "AliasDisplay": left,
            "AliasKind": "source_stated_translation",
        }
    if left_ascii_translation and inside_ascii_translation and not left_alias and not inside_alias:
        return {
            "PrimaryDisplay": left,
            "AliasDisplay": inside,
            "AliasKind": "parenthetical_equivalence",
        }
    return None


def _source_record_alias_span_meaningful(value: str) -> bool:
    text = str(value or "").strip()
    if len(text) < 2 or len(text) > 140:
        return False
    return bool(re.search(r"[^\W_]", text, flags=re.UNICODE))


def _source_record_alias_span_too_noisy(value: str) -> bool:
    text = str(value or "").strip()
    if not text:
        return True
    if text.count(",") + text.count("、") + text.count(";") + text.count("；") > 1:
        return True
    return bool(re.fullmatch(r"[\d\s./:-]+", text))


def _looks_like_source_alias_span(value: str) -> bool:
    text = str(value or "").strip()
    if not 2 <= len(text) <= 24:
        return False
    if not re.fullmatch(r"[A-Za-z0-9][A-Za-z0-9 .&/+_-]*", text):
        return False
    letters = re.findall(r"[A-Za-z]", text)
    if not letters:
        return False
    compact = re.sub(r"[^A-Za-z0-9]", "", text)
    if len(compact) <= 8 and sum(1 for char in letters if char.isupper()) >= 2:
        return True
    if re.fullmatch(r"[A-Z][A-Za-z]?[0-9][A-Za-z0-9-]*", compact):
        return True
    return False


def _looks_like_source_ascii_translation_span(value: str) -> bool:
    text = str(value or "").strip()
    if not 3 <= len(text) <= 90:
        return False
    if not re.fullmatch(r"[A-Za-z0-9][A-Za-z0-9 ,.'&/+_-]*", text):
        return False
    tokens = re.findall(r"[A-Za-z][A-Za-z0-9-]*", text)
    if not tokens:
        return False
    if len(tokens) == 1 and _looks_like_source_alias_span(text):
        return False
    return True


def _contains_non_ascii_letter(value: str) -> bool:
    return any(char.isalpha() and not char.isascii() for char in str(value or ""))


def _source_record_alias_translation_match_score(
    *,
    pair: dict[str, str],
    source_display: str,
    target_tokens: set[str],
    raw_targets: list[str],
) -> int:
    value = " ".join(
        [
            pair.get("PrimaryDisplay", ""),
            pair.get("AliasDisplay", ""),
            source_display,
        ]
    )
    value_tokens = _loose_atom_token_set(value)
    score = len(target_tokens & value_tokens)
    display_fold = value.casefold()
    for target in raw_targets:
        target_fold = target.casefold()
        if target_fold and target_fold in display_fold:
            score += max(1, len(_query_atom_tokens(target)))
    return score


def _source_record_definition_entry_from_text_atom(
    text_atom: str,
    *,
    target_tokens: set[str],
) -> dict[str, str] | None:
    tokens = _query_atom_tokens(text_atom)
    if len(tokens) < 4:
        return None
    label = tokens[0]
    if not re.fullmatch(r"[a-z]{1,3}|[ivxlcdm]{1,8}", label):
        return None
    connector_index = None
    for index, token in enumerate(tokens[1:24], start=1):
        if token in {"means", "mean"}:
            connector_index = index
            break
        if token == "defined" and index + 1 < len(tokens) and tokens[index + 1] == "as":
            connector_index = index
            break
    if connector_index is None or connector_index <= 1:
        return None
    term_tokens = [token for token in tokens[1:connector_index] if token not in {"or", "and"}]
    term_token_set = set(term_tokens)
    matched = target_tokens & term_token_set
    if not matched:
        return None
    if len(target_tokens) >= 2 and len(matched) < min(2, len(target_tokens)):
        return None
    definition_start = connector_index + 1
    if tokens[connector_index] == "defined" and definition_start < len(tokens) and tokens[definition_start] == "as":
        definition_start += 1
    definition_tokens = tokens[definition_start:]
    if not definition_tokens:
        return None
    term_atom = "_".join(term_tokens)
    definition_atom = "_".join(definition_tokens)
    return {
        "EntryLabelAtom": label,
        "EntryLabelDisplay": f"({label})",
        "DefinedTermAtom": term_atom,
        "DefinedTermDisplay": _display_source_phrase(term_atom),
        "DefinitionTextAtom": definition_atom,
        "DefinitionDisplay": _display_source_phrase(definition_atom),
        "MatchedTargetTokens": ",".join(sorted(matched)),
        "MatchedTargetTokenCount": str(len(matched)),
    }


def _source_record_under_heading_companion(
    runtime: CorePrologRuntime,
    *,
    utterance: str,
    query_intents: list[dict[str, Any]] | None = None,
) -> dict[str, Any] | None:
    intent = _first_query_intent(query_intents, "heading_scope")
    if not intent:
        source_location_intent = _first_query_intent(query_intents, "source_location")
        if _query_intent_has_constraint(source_location_intent, "under_heading", "enclosing_heading", "nearest_heading"):
            intent = source_location_intent
    if not intent:
        return None
    target_tokens = _query_intent_target_tokens(intent)
    if not target_tokens:
        return None
    ordered = _source_record_ordered_rows(runtime)
    if not ordered:
        return None
    heading_indexes = [
        index
        for index, row in enumerate(ordered)
        if _source_record_row_looks_like_heading(row)
    ]
    if not heading_indexes:
        return None

    candidates: list[tuple[int, int, dict[str, Any], dict[str, Any]]] = []
    for index, row in enumerate(ordered):
        if _source_record_row_looks_like_heading(row):
            continue
        row_tokens = set(row["Tokens"])
        overlap = target_tokens & row_tokens
        if not overlap:
            continue
        min_overlap = 2 if len(target_tokens) >= 2 else 1
        if len(overlap) < min_overlap:
            continue
        previous_heading = None
        for heading_index in heading_indexes:
            if heading_index < index:
                previous_heading = ordered[heading_index]
            else:
                break
        if not previous_heading:
            continue
        score = len(overlap) * 12
        if target_tokens <= row_tokens:
            score += 24
        candidates.append((score, int(row["Line"]), previous_heading, row))
    if not candidates:
        return None
    candidates.sort(key=lambda item: (-item[0], item[1]))
    rows: list[dict[str, str]] = []
    seen: set[tuple[str, str]] = set()
    for _score, _line, heading, target in candidates[:8]:
        key = (str(heading["SourceRow"]), str(target["SourceRow"]))
        if key in seen:
            continue
        seen.add(key)
        rows.append(
            {
                "SupportKind": "source_record_under_heading",
                "HeadingSourceRow": str(heading["SourceRow"]),
                "HeadingLine": str(heading["Line"]),
                "HeadingAtom": str(heading["TextAtom"]),
                "HeadingDisplay": _display_source_phrase(str(heading["TextAtom"])),
                "TargetSourceRow": str(target["SourceRow"]),
                "TargetLine": str(target["Line"]),
                "TargetTextAtom": str(target["TextAtom"]),
                "TargetDisplay": _display_source_phrase(str(target["TextAtom"])),
                "MatchedTargetTokens": ",".join(sorted(target_tokens & set(target["Tokens"]))),
                "SupportClass": "deterministic-source-record-summary",
            }
        )
    if not rows:
        return None
    return {
        "query": "source_record_under_heading_support(HeadingSourceRow, TargetSourceRow, HeadingAtom, TargetTextAtom).",
        "result": {
            "predicate": "source_record_under_heading_support",
            "prolog_query": (
                "source_record_under_heading_support"
                "(HeadingSourceRow, TargetSourceRow, HeadingAtom, TargetTextAtom)."
            ),
            "result_type": "table",
            "status": "success",
            "num_rows": len(rows),
            "variables": _row_variable_names(rows),
            "rows": rows,
            "reasoning_basis": {
                "kind": "core-local",
                "note": (
                    "query-only heading-scope support found source rows matching structured intent target "
                    "tokens and returned their nearest preceding admitted heading-like row; no "
                    "durable fact was written"
                ),
                "query_intent": intent,
            },
        },
        "derived_from_queries": [
            "source_record_row(SourceRow, Kind, Line, SectionAtom, Label).",
            "source_record_text_atom(SourceRow, TextAtom).",
        ],
    }


def _source_record_named_section_window_companion(
    runtime: CorePrologRuntime,
    *,
    utterance: str,
    query_intents: list[dict[str, Any]] | None = None,
) -> dict[str, Any] | None:
    intent = _first_query_intent(query_intents, "heading_scope", "source_location")
    list_derived = False
    if not _query_intent_has_constraint(intent, "section_window", "bounded_section", "section_contents"):
        list_intent = _first_query_intent(query_intents, "list", "ordered_labeled_entry")
        if _query_intent_target_token_groups(list_intent):
            intent = list_intent
            list_derived = True
        else:
            return None

    section_targets = _query_intent_target_token_groups(intent)
    if not section_targets:
        return None

    text_rows = _runtime_rows(runtime, "source_record_text_atom(SourceRow, TextAtom).")
    text_by_row = {
        str(row.get("SourceRow", "")): _normalize_text_filter_atom(str(row.get("TextAtom", "")))
        for row in text_rows
        if isinstance(row, dict)
    }
    ordered = _source_record_ordered_rows(runtime, text_by_row=text_by_row)
    if not ordered:
        return None
    heading_indexes = [
        index
        for index, row in enumerate(ordered)
        if _source_record_row_looks_like_heading(row)
    ]
    if not heading_indexes:
        return None

    candidates: list[tuple[int, int, int]] = []
    for heading_index in heading_indexes:
        row = ordered[heading_index]
        row_tokens = set(row["Tokens"])
        for target_index, target_tokens in enumerate(section_targets):
            overlap = row_tokens & target_tokens
            if not overlap:
                continue
            if list_derived and not _section_window_target_strongly_matches_heading(
                target_tokens=target_tokens,
                heading_tokens=row_tokens,
            ):
                continue
            score = len(overlap) * 12
            if target_tokens <= row_tokens:
                score += 24
            if str(row["TextAtom"]) == "_".join(sorted(target_tokens)):
                score += 6
            candidates.append((score, target_index, heading_index))
    if not candidates:
        return None
    candidates.sort(key=lambda item: (-item[0], item[1], int(ordered[item[2]]["Line"])))

    _score, _target_index, heading_index = candidates[0]
    heading = ordered[heading_index]
    next_heading_line = None
    for later_index in heading_indexes:
        if later_index > heading_index:
            next_heading_line = int(ordered[later_index]["Line"])
            break

    section_rows: list[dict[str, str]] = []
    for row in ordered[heading_index:]:
        line = int(row["Line"])
        if line < int(heading["Line"]):
            continue
        if next_heading_line is not None and line >= next_heading_line:
            break
        if line - int(heading["Line"]) > 80:
            break
        if row["Kind"] in {"blank", "separator"}:
            continue
        section_rows.append(
            {
                "SupportKind": "source_record_named_section_window",
                "SectionSourceRow": str(heading["SourceRow"]),
                "SectionLine": str(heading["Line"]),
                "SectionAtom": str(heading["TextAtom"]),
                "SectionDisplay": _display_source_phrase(str(heading["TextAtom"])),
                "SourceRow": str(row["SourceRow"]),
                "Line": str(row["Line"]),
                "Kind": str(row["Kind"]),
                "Label": str(row["Label"]),
                "TextAtom": str(row["TextAtom"]),
                "DisplayText": _display_source_phrase(str(row["TextAtom"])),
                "SupportClass": "deterministic-source-record-summary",
            }
        )
        if len(section_rows) >= 18:
            break
    if not section_rows:
        return None
    return {
        "query": "source_record_named_section_window_support(SectionSourceRow, SourceRow, TextAtom).",
        "result": {
            "predicate": "source_record_named_section_window_support",
            "prolog_query": "source_record_named_section_window_support(SectionSourceRow, SourceRow, TextAtom).",
            "result_type": "table",
            "status": "success",
            "num_rows": len(section_rows),
            "variables": _row_variable_names(section_rows),
            "rows": section_rows,
            "reasoning_basis": {
                "kind": "core-local",
                "note": (
                    "query-only named-section support matched an admitted source-record heading "
                    "from structured query-intent target terms and returned the bounded source rows until the next heading; "
                    "no durable fact was written"
                ),
                "query_intent": intent,
            },
        },
        "derived_from_queries": [
            "source_record_row(SourceRow, Kind, Line, SectionAtom, Label).",
            "source_record_text_atom(SourceRow, TextAtom).",
        ],
    }


def _section_window_target_strongly_matches_heading(
    *,
    target_tokens: set[str],
    heading_tokens: set[str],
) -> bool:
    if not target_tokens or not heading_tokens:
        return False
    overlap = target_tokens & heading_tokens
    if target_tokens <= heading_tokens:
        return True
    if len(target_tokens) >= 2 and len(overlap) >= 2:
        return True
    return len(target_tokens) == 1 and bool(overlap)


def _source_record_quote_heading_locator_companion(
    runtime: CorePrologRuntime,
    *,
    utterance: str,
    query_intents: list[dict[str, Any]] | None = None,
) -> dict[str, Any] | None:
    intent = _first_query_intent(query_intents, "heading_scope")
    if not intent:
        source_location_intent = _first_query_intent(query_intents, "source_location")
        if _query_intent_has_constraint(source_location_intent, "quote_heading_locator", "enclosing_heading", "quote_location"):
            intent = source_location_intent
    if not intent:
        return None
    quote_targets = [
        tokens
        for tokens in _query_intent_target_token_groups(intent)
        if len(tokens) >= 3 and not {"section", "heading"} & tokens
    ]
    if not quote_targets:
        return None

    text_rows = _runtime_rows(runtime, "source_record_text_atom(SourceRow, TextAtom).")
    text_by_row = {
        str(row.get("SourceRow", "")): _normalize_text_filter_atom(str(row.get("TextAtom", "")))
        for row in text_rows
        if isinstance(row, dict)
    }
    ordered = _source_record_ordered_rows(runtime, text_by_row=text_by_row)
    headings = [row for row in ordered if _source_record_row_looks_like_heading(row)]
    if not ordered or not headings:
        return None

    candidates: list[tuple[int, dict[str, Any], set[str]]] = []
    for row in ordered:
        row_tokens = set(row["Tokens"])
        for target_tokens in quote_targets:
            overlap = row_tokens & target_tokens
            min_overlap = max(3, math.ceil(len(target_tokens) * 0.6))
            if len(overlap) < min(min_overlap, len(target_tokens)):
                continue
            score = len(overlap) * 12
            if target_tokens <= row_tokens:
                score += 24
            candidates.append((score, row, overlap))
    if not candidates:
        return None
    candidates.sort(key=lambda item: (-item[0], int(item[1]["Line"])))

    out_rows: list[dict[str, str]] = []
    seen: set[tuple[str, str]] = set()
    for _score, target, overlap in candidates[:4]:
        target_line = int(target["Line"])
        previous_heading = None
        for heading in headings:
            if int(heading["Line"]) <= target_line:
                previous_heading = heading
            else:
                break
        if not previous_heading:
            continue
        previous_context = _nearest_source_record_context_before(ordered, target_line)
        key = (str(previous_heading["SourceRow"]), str(target["SourceRow"]))
        if key in seen:
            continue
        seen.add(key)
        out_rows.append(
            {
                "SupportKind": "source_record_quote_heading_locator",
                "HeadingSourceRow": str(previous_heading["SourceRow"]),
                "HeadingLine": str(previous_heading["Line"]),
                "HeadingAtom": str(previous_heading["TextAtom"]),
                "HeadingDisplay": _display_source_phrase(str(previous_heading["TextAtom"])),
                "MatchedSourceRow": str(target["SourceRow"]),
                "MatchedLine": str(target["Line"]),
                "MatchedTextAtom": str(target["TextAtom"]),
                "MatchedDisplayText": _display_source_phrase(str(target["TextAtom"])),
                "PreviousContextTextAtom": str(previous_context.get("TextAtom", "")) if previous_context else "",
                "PreviousContextDisplay": (
                    _display_source_phrase(str(previous_context.get("TextAtom", ""))) if previous_context else ""
                ),
                "MatchedQuoteTokens": ",".join(sorted(overlap)),
                "SupportClass": "deterministic-source-record-summary",
            }
        )
    if not out_rows:
        return None
    return {
        "query": "source_record_quote_heading_locator_support(HeadingSourceRow, MatchedSourceRow, HeadingAtom, MatchedTextAtom).",
        "result": {
            "predicate": "source_record_quote_heading_locator_support",
            "prolog_query": (
                "source_record_quote_heading_locator_support"
                "(HeadingSourceRow, MatchedSourceRow, HeadingAtom, MatchedTextAtom)."
            ),
            "result_type": "table",
            "status": "success",
            "num_rows": len(out_rows),
            "variables": _row_variable_names(out_rows),
            "rows": out_rows,
            "reasoning_basis": {
                "kind": "core-local",
                "note": (
                    "query-only quote-heading support located a quoted phrase in admitted source-record "
                    "text and returned the nearest preceding admitted heading-like row; no durable fact "
                    "was written"
                ),
                "query_intent": intent,
            },
        },
        "derived_from_queries": [
            "source_record_row(SourceRow, Kind, Line, SectionAtom, Label).",
            "source_record_text_atom(SourceRow, TextAtom).",
        ],
    }


def _source_record_ordered_rows(
    runtime: CorePrologRuntime,
    *,
    text_by_row: dict[str, str] | None = None,
) -> list[dict[str, Any]]:
    if text_by_row is None:
        text_rows = _runtime_rows(runtime, "source_record_text_atom(SourceRow, TextAtom).")
        text_by_row = {
            str(row.get("SourceRow", "")): _normalize_text_filter_atom(str(row.get("TextAtom", "")))
            for row in text_rows
            if isinstance(row, dict)
        }
    ordered: list[dict[str, Any]] = []
    for source_row, meta in _source_record_row_metadata(runtime).items():
        line = _safe_int(meta.get("Line"))
        if line is None:
            continue
        label = _normalize_text_filter_atom(str(meta.get("Label", "")))
        section = _normalize_text_filter_atom(str(meta.get("SectionAtom", "")))
        text_atom = text_by_row.get(source_row, label)
        combined = "_".join(part for part in (str(meta.get("Kind", "")), label, text_atom, section) if part)
        ordered.append(
            {
                "SourceRow": source_row,
                "Line": line,
                "Kind": str(meta.get("Kind", "")),
                "Section": str(meta.get("SectionAtom", "")),
                "Label": label,
                "TextAtom": text_atom,
                "Tokens": set(_query_atom_tokens(combined)),
            }
        )
    ordered.sort(key=lambda row: int(row["Line"]))
    return ordered


def _source_record_row_looks_like_heading(row: dict[str, Any]) -> bool:
    kind = str(row.get("Kind", "")).strip()
    label = _normalize_text_filter_atom(str(row.get("Label", "")))
    text_atom = _normalize_text_filter_atom(str(row.get("TextAtom", "")))
    tokens = set(row.get("Tokens", set()))
    if kind == "heading" or "heading" in tokens:
        return True
    if kind == "labeled_line" and label and label == text_atom:
        return True
    return False


def _nearest_source_record_context_before(
    ordered: list[dict[str, Any]],
    target_line: int,
) -> dict[str, Any] | None:
    for row in reversed(ordered):
        line = int(row["Line"])
        if line >= target_line:
            continue
        if str(row.get("Kind", "")) in {"paragraph_line", "anchored_line", "labeled_line"}:
            return row
    return None


def _asks_for_source_record_overlap_support(utterance: str) -> bool:
    text = str(utterance or "").casefold()
    return bool(
        re.search(
            r"\b(?:which|what|when|why|list|after|before|between|records?|reconciled|recusal|"
            r"protected|discrepanc|dissent|commit|status|application|notice|turn)\b",
            text,
        )
    )


def _source_record_overlap_question_tokens(utterance: str) -> set[str]:
    stopwords = {
        "the",
        "a",
        "an",
        "and",
        "or",
        "of",
        "to",
        "for",
        "with",
        "from",
        "on",
        "in",
        "by",
        "all",
        "any",
        "which",
        "what",
        "when",
        "why",
        "did",
        "does",
        "was",
        "were",
        "is",
        "are",
        "be",
        "been",
        "should",
        "system",
        "record",
        "records",
    }
    tokens = set(_query_atom_tokens(utterance))
    tokens.update(_source_text_question_needles(utterance)[:12])
    if "recusal" in tokens:
        tokens.add("recused")
    if "dissent" in tokens:
        tokens.add("dissented")
    if "reconciliation" in tokens:
        tokens.add("reconciled")
    return {token for token in tokens if len(token) >= 3 and token not in stopwords and token not in GENERIC_QUERY_PLACEHOLDERS}


def _source_record_overlap_identifier_keys(utterance: str) -> list[str]:
    out: list[str] = []
    for match in re.finditer(r"\b[A-Za-z]+(?:[-_][A-Za-z0-9]+){1,}\b|#\s*\d+\b|\b\d{4}[-_/]\d{2}[-_/]\d{2}\b", str(utterance or "")):
        key = _compact_identifier_key(match.group(0))
        if key and key not in out:
            out.append(key)
    return out[:12]


def _turn_section_targets_from_utterance(utterance: str) -> set[str]:
    numbers = [int(match.group(1)) for match in re.finditer(r"\bturn\s+(\d{1,3})\b", str(utterance or ""), re.IGNORECASE)]
    if not numbers:
        return set()
    if len(numbers) >= 2:
        start, end = min(numbers[:2]), max(numbers[:2])
        if end - start <= 16:
            return {f"turn_{value:02d}" for value in range(start, end + 1)}
    return {f"turn_{value:02d}" for value in numbers}


def _source_record_row_metadata(runtime: CorePrologRuntime) -> dict[str, dict[str, Any]]:
    rows = _runtime_rows(runtime, "source_record_row(SourceRow, Kind, Line, SectionAtom, Label).")
    out: dict[str, dict[str, Any]] = {}
    for row in rows:
        if not isinstance(row, dict):
            continue
        source_row = str(row.get("SourceRow", "")).strip()
        if source_row:
            out[source_row] = row
    return out


def _source_record_list_window_companion(
    runtime: CorePrologRuntime,
    *,
    utterance: str,
) -> dict[str, Any] | None:
    text = str(utterance or "").casefold()
    if not re.search(r"\b(?:list|which|what)\b", text) or not re.search(r"\b(?:all|ids?|items?|codes?)\b", text):
        return None
    question_tokens = _source_record_overlap_question_tokens(utterance)
    text_rows = _runtime_rows(runtime, "source_record_text_atom(SourceRow, TextAtom).")
    row_meta = _source_record_row_metadata(runtime)
    text_by_row = {
        str(row.get("SourceRow", "")): _normalize_text_filter_atom(str(row.get("TextAtom", "")))
        for row in text_rows
        if isinstance(row, dict)
    }
    normalized: list[dict[str, Any]] = []
    for source_row, meta in row_meta.items():
        line = _safe_int(meta.get("Line"))
        if line is None:
            continue
        text_atom = text_by_row.get(source_row, _normalize_text_filter_atom(str(meta.get("Label", ""))))
        normalized.append(
            {
                "SourceRow": source_row,
                "Line": line,
                "Kind": str(meta.get("Kind", "")),
                "Section": str(meta.get("SectionAtom", "")),
                "Label": str(meta.get("Label", "")),
                "TextAtom": text_atom,
                "Tokens": set(_query_atom_tokens("_".join([text_atom, str(meta.get("Label", "")), str(meta.get("SectionAtom", ""))]))),
            }
        )
    if not normalized:
        return None
    normalized.sort(key=lambda row: int(row["Line"]))
    candidates: list[dict[str, str]] = []
    for index, row in enumerate(normalized):
        row_tokens = set(row["Tokens"])
        if not ({"listed", "list", "original", "protected", "current"} & row_tokens):
            continue
        if len(question_tokens & row_tokens) < 2 and not ({"listed", "list"} & row_tokens and question_tokens & row_tokens):
            continue
        section = str(row["Section"])
        for follower in normalized[index + 1 : index + 12]:
            if str(follower["Section"]) != section:
                break
            if str(follower["Kind"]) not in {"table_row", "continuation_line", "anchored_line"}:
                if int(follower["Line"]) - int(row["Line"]) > 3:
                    break
            item_id = _source_record_list_item_id(follower["TextAtom"], follower["Label"])
            if not item_id:
                continue
            candidates.append(
                {
                    "SupportKind": "source_record_list_window",
                    "SourceRow": str(follower["SourceRow"]),
                    "HeaderSourceRow": str(row["SourceRow"]),
                    "Line": str(follower["Line"]),
                    "Section": section,
                    "ItemId": item_id,
                    "DisplayItemId": _display_source_record_item_id(item_id),
                    "TextAtom": str(follower["TextAtom"]),
                    "HeaderTextAtom": str(row["TextAtom"]),
                }
            )
    for row in normalized:
        text_atom = str(row["TextAtom"])
        for match in re.finditer(r"(?:^|_)(?:plus|add(?:ed)?|including)_([a-z]+_\d{1,4}|v_\d{1,4})(?:_|$)", text_atom):
            candidates.append(
                {
                    "SupportKind": "source_record_list_delta",
                    "SourceRow": str(row["SourceRow"]),
                    "HeaderSourceRow": "",
                    "Line": str(row["Line"]),
                    "Section": str(row["Section"]),
                    "ItemId": match.group(1),
                    "DisplayItemId": _display_source_record_item_id(match.group(1)),
                    "TextAtom": text_atom,
                    "HeaderTextAtom": "",
                }
            )
    if not candidates:
        return None
    seen: set[tuple[str, str]] = set()
    out_rows: list[dict[str, str]] = []
    for row in candidates:
        key = (row["SourceRow"], row["ItemId"])
        if key in seen:
            continue
        seen.add(key)
        out_rows.append(row)
    if not out_rows:
        return None
    return {
        "query": "source_record_list_window_support(SourceRow, HeaderSourceRow, ItemId, TextAtom).",
        "result": {
            "predicate": "source_record_list_window_support",
            "prolog_query": "source_record_list_window_support(SourceRow, HeaderSourceRow, ItemId, TextAtom).",
            "result_type": "table",
            "status": "success",
            "num_rows": len(out_rows[:24]),
            "variables": list(out_rows[0].keys()),
            "rows": out_rows[:24],
            "reasoning_basis": {
                "kind": "core-local",
                "note": "query-only list-window support followed admitted source list/table headers and delta rows; no durable fact was written",
                "utterance": utterance,
            },
        },
        "derived_from_queries": [
            "source_record_text_atom(SourceRow, TextAtom).",
            "source_record_row(SourceRow, Kind, Line, SectionAtom, Label).",
        ],
    }


def _source_record_ordered_labeled_entry_companion(
    runtime: CorePrologRuntime,
    *,
    utterance: str,
    query_intents: list[dict[str, Any]] | None = None,
) -> dict[str, Any] | None:
    intent = _first_query_intent(query_intents, "ordered_labeled_entry")
    if not intent:
        return None

    ordered = _source_record_ordered_rows(runtime)
    entries = [
        row
        for row in ordered
        if str(row.get("Kind", "")) == "labeled_line"
        and str(row.get("TextAtom", "")).strip()
        and str(row.get("Label", "")).strip()
        and str(row.get("Label", "")).strip() != "no_label"
    ]
    if len(entries) < 2 or len(entries) > 80:
        return None

    rows: list[dict[str, str]] = []
    for entry in entries:
        rows.append(
            {
                "SupportKind": "source_record_ordered_labeled_entry",
                "SourceRow": str(entry["SourceRow"]),
                "Line": str(entry["Line"]),
                "SectionAtom": str(entry.get("Section", "")),
                "SectionDisplay": _display_source_phrase(str(entry.get("Section", ""))),
                "LabelAtom": str(entry.get("Label", "")),
                "LabelDisplay": _display_source_phrase(str(entry.get("Label", ""))),
                "TextAtom": str(entry.get("TextAtom", "")),
                "TextDisplay": _display_source_phrase(str(entry.get("TextAtom", ""))),
                "SupportClass": "deterministic-source-record-summary",
            }
        )
