def _source_record_section_list_detail_companion(
    runtime: CorePrologRuntime,
    *,
    utterance: str,
    query_intents: list[dict[str, Any]] | None = None,
) -> dict[str, Any] | None:
    intent = _first_query_intent(query_intents, "ordered_labeled_entry", "list", "heading_scope")
    has_section_list_constraint = _query_intent_has_constraint(
        intent,
        "section_list_detail",
        "source_order",
        "section_rows",
    )
    list_cue_tokens = {
        "configuration",
        "fatally",
        "include",
        "included",
        "injured",
        "occupants",
        "packages",
        "people",
        "persons",
        "payments",
        "benefits",
        "compensation",
        "severance",
        "violation",
        "violations",
    }

    target_tokens = _query_intent_target_tokens(intent)
    if not target_tokens:
        return None
    if not has_section_list_constraint and not (target_tokens & list_cue_tokens):
        return None
    text_rows = _runtime_rows(runtime, "source_record_text_atom(SourceRow, TextAtom).")
    row_meta = _source_record_row_metadata(runtime)
    text_by_row = {
        str(row.get("SourceRow", "")): _normalize_text_filter_atom(str(row.get("TextAtom", "")))
        for row in text_rows
        if isinstance(row, dict)
    }
    ordered: list[dict[str, Any]] = []
    for source_row, meta in row_meta.items():
        line = _safe_int(meta.get("Line"))
        if line is None:
            continue
        text_atom = text_by_row.get(source_row, _normalize_text_filter_atom(str(meta.get("Label", ""))))
        tokens = set(_query_atom_tokens("_".join([text_atom, str(meta.get("Label", "")), str(meta.get("SectionAtom", ""))])))
        ordered.append(
            {
                "SourceRow": source_row,
                "Line": line,
                "Kind": str(meta.get("Kind", "")),
                "Section": str(meta.get("SectionAtom", "")),
                "Label": str(meta.get("Label", "")),
                "TextAtom": text_atom,
                "Tokens": tokens,
            }
        )
    if not ordered:
        return None
    ordered.sort(key=lambda row: int(row["Line"]))

    groups: list[dict[str, Any]] = []
    for index, row in enumerate(ordered):
        if row["Kind"] == "list_row":
            continue
        overlap = target_tokens & set(row["Tokens"])
        if len(overlap) < 2:
            continue
        if not (overlap & list_cue_tokens or has_section_list_constraint):
            continue
        section = str(row["Section"])
        followers: list[dict[str, Any]] = []
        last_line = int(row["Line"])
        for follower in ordered[index + 1 : index + 20]:
            if str(follower["Section"]) != section:
                break
            gap = int(follower["Line"]) - last_line
            if gap > 8 and followers:
                break
            if int(follower["Line"]) - int(row["Line"]) > 35:
                break
            if str(follower["Kind"]) in {"list_row", "table_row"}:
                followers.append(follower)
                last_line = int(follower["Line"])
                continue
            if followers and str(follower["Kind"]) not in {"list_row", "table_row", "continuation_line"}:
                break
        if not followers:
            continue
        score = len(overlap) * 10 + len(followers)
        groups.append({"score": score, "header": row, "followers": followers, "overlap": sorted(overlap)})
    if not groups:
        return None
    groups.sort(
        key=lambda item: (
            -int(item["score"]),
            _source_row_sort_key(str(item["header"]["SourceRow"])),
        )
    )
    best = groups[0]
    out_rows: list[dict[str, str]] = []
    for position, row in enumerate(best["followers"], start=1):
        out_rows.append(
            {
                "SupportKind": "source_record_section_list_detail",
                "Position": str(position),
                "SourceRow": str(row["SourceRow"]),
                "HeaderSourceRow": str(best["header"]["SourceRow"]),
                "Line": str(row["Line"]),
                "Section": str(row["Section"]),
                "HeaderTextAtom": str(best["header"]["TextAtom"]),
                "TextAtom": str(row["TextAtom"]),
                "DisplayText": _display_source_phrase(str(row["TextAtom"])),
                "MatchedQuestionTokens": ",".join(str(token) for token in best["overlap"]),
                "SupportClass": "deterministic-source-record-summary",
            }
        )
    return {
        "query": "source_record_section_list_detail_support(Position, SourceRow, TextAtom).",
        "result": {
            "predicate": "source_record_section_list_detail_support",
            "prolog_query": "source_record_section_list_detail_support(Position, SourceRow, TextAtom).",
            "result_type": "table",
            "status": "success",
            "num_rows": len(out_rows[:24]),
            "variables": list(out_rows[0].keys()),
            "rows": out_rows[:24],
            "reasoning_basis": {
                "kind": "core-local",
                "note": (
                    "query-only source-section list detail support followed an admitted "
                    "query-intent-matched source-record header to same-section list rows; no durable fact was written"
                ),
                "query_intent": intent,
            },
        },
        "derived_from_queries": [
            "source_record_row(SourceRow, Kind, Line, SectionAtom, Label).",
            "source_record_text_atom(SourceRow, TextAtom).",
        ],
    }


def _source_record_list_item_id(text_atom: str, label: str) -> str:
    for value in (str(label or ""), str(text_atom or "")):
        match = re.search(r"\b([a-z]+_\d{1,4})\b", value)
        if match:
            return match.group(1)
        match = re.search(r"\b(?:tree_|item_|tag_|code_|v_)?(\d{1,4})\b", value)
        if match:
            prefix = "v" if re.search(r"\bv_\d", value) else "item"
            return f"{prefix}_{int(match.group(1))}"
    return ""


def _display_source_record_item_id(item_id: str) -> str:
    match = re.fullmatch(r"(?:v|tree|item)_(\d{1,4})", str(item_id or ""))
    if match:
        return f"#{int(match.group(1))}"
    return str(item_id or "")


def _source_record_speaker_window_companion(
    runtime: CorePrologRuntime,
    *,
    utterance: str,
) -> dict[str, Any] | None:
    speaker = _speaker_name_from_why_question(utterance)
    if not speaker:
        return None
    text_rows = _runtime_rows(runtime, "source_record_text_atom(SourceRow, TextAtom).")
    row_meta = _source_record_row_metadata(runtime)
    ordered: list[dict[str, Any]] = []
    text_by_row: dict[str, str] = {}
    for row in text_rows:
        if not isinstance(row, dict):
            continue
        source_row = str(row.get("SourceRow", ""))
        text_atom = _normalize_text_filter_atom(str(row.get("TextAtom", "")))
        text_by_row[source_row] = text_atom
    for source_row, meta in row_meta.items():
        line = _safe_int(meta.get("Line"))
        if line is None:
            continue
        ordered.append(
            {
                "SourceRow": source_row,
                "Line": line,
                "Section": str(meta.get("SectionAtom", "")),
                "Label": str(meta.get("Label", "")),
                "TextAtom": text_by_row.get(source_row, _normalize_text_filter_atom(str(meta.get("Label", "")))),
            }
        )
    ordered.sort(key=lambda row: int(row["Line"]))
    speaker_key = _compact_identifier_key(speaker)
    question_tokens = _source_record_overlap_question_tokens(utterance)
    selected: list[dict[str, str]] = []
    for index, row in enumerate(ordered):
        combined_key = _compact_identifier_key("_".join([str(row["Label"]), str(row["TextAtom"])]))
        if speaker_key not in combined_key:
            continue
        window = ordered[max(0, index - 3) : min(len(ordered), index + 4)]
        for item in window:
            item_tokens = set(_query_atom_tokens("_".join([str(item["TextAtom"]), str(item["Label"]), str(item["Section"])])))
            selected.append(
                {
                    "SupportKind": "source_record_speaker_window",
                    "Speaker": speaker,
                    "SourceRow": str(item["SourceRow"]),
                    "Line": str(item["Line"]),
                    "Section": str(item["Section"]),
                    "Label": str(item["Label"]),
                    "TextAtom": str(item["TextAtom"]),
                    "QuestionOverlap": ",".join(sorted(question_tokens & item_tokens)),
                }
            )
    if not selected:
        return None
    seen: set[str] = set()
    out_rows: list[dict[str, str]] = []
    for row in selected:
        key = row["SourceRow"]
        if key in seen:
            continue
        seen.add(key)
        out_rows.append(row)
    return {
        "query": "source_record_speaker_window_support(Speaker, SourceRow, TextAtom, QuestionOverlap).",
        "result": {
            "predicate": "source_record_speaker_window_support",
            "prolog_query": "source_record_speaker_window_support(Speaker, SourceRow, TextAtom, QuestionOverlap).",
            "result_type": "table",
            "status": "success",
            "num_rows": len(out_rows[:24]),
            "variables": list(out_rows[0].keys()),
            "rows": out_rows[:24],
            "reasoning_basis": {
                "kind": "core-local",
                "note": "query-only speaker-window support returned admitted source rows around named-speaker rows; no durable fact was written",
                "utterance": utterance,
            },
        },
        "derived_from_queries": [
            "source_record_text_atom(SourceRow, TextAtom).",
            "source_record_row(SourceRow, Kind, Line, SectionAtom, Label).",
        ],
    }


def _speaker_name_from_why_question(utterance: str) -> str:
    match = re.search(r"\bwhy\s+did\s+([A-Z][A-Za-z0-9_.-]*)\b", str(utterance or ""), re.IGNORECASE)
    if match:
        return _simple_query_atom(match.group(1))
    match = re.search(r"\bwhat\s+did\s+([A-Z][A-Za-z0-9_.-]*)\s+say\b", str(utterance or ""), re.IGNORECASE)
    if match:
        return _simple_query_atom(match.group(1))
    return ""


