def _source_record_elapsed_date_duration_companion(
    runtime: CorePrologRuntime,
    *,
    utterance: str,
    query_intents: list[dict[str, Any]] | None = None,
) -> dict[str, Any] | None:
    text = str(utterance or "").casefold()
    intent_active = _source_record_elapsed_date_duration_intent_active(query_intents)
    if not intent_active and not re.search(r"\b(?:elapsed|how many days|duration|between)\b", text):
        return None
    if not intent_active and not re.search(r"\b(?:date|day|days|deadline|issuance|issued|opened|closed|published|report)\b", text):
        return None

    spans = _date_duration_question_spans(utterance)
    candidates = _source_record_date_duration_candidates(runtime)
    if len(candidates) < 2:
        return None

    utterance_dates = _date_atoms_from_free_text(utterance)
    support_rows: list[dict[str, str]] = []
    seen: set[tuple[str, str, str, str]] = set()

    def add_row(
        *,
        start: dict[str, str],
        end: dict[str, str],
        start_role: str,
        end_role: str,
        score: int,
        support_kind: str,
    ) -> None:
        elapsed_days = _elapsed_days_between_date_atoms(start["Date"], end["Date"])
        if elapsed_days is None or elapsed_days < 0:
            return
        if elapsed_days == 0 and not re.search(r"\b(?:same date|same day|also)\b", text):
            return
        if support_kind == "source_record_context_date_duration" and score < 4:
            return
        key = (start["Date"], end["Date"], start.get("SourceRow", ""), end.get("SourceRow", ""))
        if key in seen:
            return
        seen.add(key)
        support_rows.append(
            {
                "SupportKind": support_kind,
                "StartRole": start_role,
                "StartRoleDisplay": _display_source_phrase(start_role),
                "StartDate": start["Date"],
                "StartDateDisplay": _display_source_date_atom(start["Date"]),
                "StartSourceRow": start.get("SourceRow", ""),
                "StartSourceField": start.get("Field", ""),
                "StartSourceDisplay": start.get("Display", ""),
                "EndRole": end_role,
                "EndRoleDisplay": _display_source_phrase(end_role),
                "EndDate": end["Date"],
                "EndDateDisplay": _display_source_date_atom(end["Date"]),
                "EndSourceRow": end.get("SourceRow", ""),
                "EndSourceField": end.get("Field", ""),
                "EndSourceDisplay": end.get("Display", ""),
                "ElapsedDays": str(elapsed_days),
                "Duration": f"{elapsed_days} day{'s' if elapsed_days != 1 else ''}",
                "MatchScore": str(score),
                "SupportClass": "deterministic-source-record-summary",
            }
        )

    if len(utterance_dates) >= 2:
        start_date, end_date = utterance_dates[0], utterance_dates[-1]
        start_matches = [candidate for candidate in candidates if candidate["Date"] == start_date]
        end_matches = [candidate for candidate in candidates if candidate["Date"] == end_date]
        if start_matches and end_matches:
            start = sorted(start_matches, key=lambda row: _source_row_sort_key(row.get("SourceRow", "")))[0]
            end = sorted(end_matches, key=lambda row: _source_row_sort_key(row.get("SourceRow", "")))[0]
            add_row(
                start=start,
                end=end,
                start_role="utterance_start_date",
                end_role="utterance_end_date",
                score=100,
                support_kind="source_record_explicit_date_duration",
            )

    start_span, end_span = spans
    start_tokens = _date_duration_span_tokens(start_span)
    end_tokens = _date_duration_span_tokens(end_span)
    if start_tokens and end_tokens:
        for start in candidates:
            start_score = _date_duration_candidate_score(start, start_tokens)
            if start_score <= 0:
                continue
            for end in candidates:
                if start is end:
                    continue
                end_score = _date_duration_candidate_score(end, end_tokens)
                if end_score <= 0:
                    continue
                add_row(
                    start=start,
                    end=end,
                    start_role=_compact_role_from_span(start_span) or "start_date",
                    end_role=_compact_role_from_span(end_span) or "end_date",
                    score=start_score + end_score,
                    support_kind="source_record_context_date_duration",
                )

    if intent_active:
        for support_row in _source_record_elapsed_date_duration_rows_from_intents(
            runtime=runtime,
            candidates=candidates,
            query_intents=query_intents,
        ):
            key = (
                support_row["StartDate"],
                support_row["EndDate"],
                support_row.get("StartSourceRow", ""),
                support_row.get("EndSourceField", ""),
            )
            if key in seen:
                continue
            seen.add(key)
            support_rows.append(support_row)

    if not support_rows:
        return None
    support_rows.sort(
        key=lambda row: (
            -int(row.get("MatchScore", "0")),
            int(row.get("ElapsedDays", "0")),
            _source_row_sort_key(row.get("StartSourceRow", "")),
            _source_row_sort_key(row.get("EndSourceRow", "")),
        )
    )
    return {
        "query": "source_record_elapsed_date_duration_support(StartDate, EndDate, ElapsedDays, Duration).",
        "result": {
            "status": "success",
            "predicate": "source_record_elapsed_date_duration_support",
            "prolog_query": "source_record_elapsed_date_duration_support(StartDate, EndDate, ElapsedDays, Duration).",
            "result_type": "table",
            "num_rows": len(support_rows),
            "variables": _row_variable_names(support_rows),
            "rows": support_rows[:40],
            "reasoning_basis": {
                "kind": "core-local",
                "note": (
                    "query-only elapsed-date support matched question date roles to admitted "
                    "source-record or direct date facts and computed calendar-day differences; no durable "
                    "duration fact was written"
                ),
                "utterance": utterance,
                "query_intents": query_intents or [],
            },
        },
        "derived_from_queries": [
            "source_record_field(SourceRow, Field, DateValue).",
            "source_record_field_item(SourceRow, Field, DateValue).",
            "source_record_date_alias(SourceRow, DateValue, CanonicalDate).",
            "source_record_text_atom(SourceRow, TextAtom).",
            "direct admitted predicates with date-valued arguments",
        ],
    }


def _source_record_elapsed_date_duration_intent_active(
    query_intents: list[dict[str, Any]] | None,
) -> bool:
    duration_markers = {
        "calendar",
        "day",
        "days",
        "duration",
        "elapsed",
        "interval",
        "period",
    }
    for intent in query_intents or []:
        if not isinstance(intent, dict):
            continue
        intent_type = str(intent.get("intent_type", "")).strip()
        target_tokens = {
            token
            for value in [
                *(intent.get("target_terms", []) or []),
                *(intent.get("answer_constraints", []) or []),
            ]
            for token in _query_atom_tokens(str(value))
        }
        if intent_type not in {"date", "duration", "document_chronology", "unknown"}:
            continue
        if _query_intent_has_constraint(
            intent,
            "interval_duration",
            "elapsed_days",
            "days",
            "duration",
        ):
            return True
        if intent_type in {"date", "duration", "document_chronology"} and target_tokens & duration_markers:
            return True
        if intent_type == "unknown" and (
            {"date", "interval"} <= target_tokens
            or {"elapsed", "days"} <= target_tokens
            or "duration" in target_tokens
        ):
            return True
    return False


def _source_record_elapsed_date_duration_rows_from_intents(
    *,
    runtime: CorePrologRuntime,
    candidates: list[dict[str, str]],
    query_intents: list[dict[str, Any]] | None,
) -> list[dict[str, str]]:
    target_rows = _source_record_semantic_target_display_rows(runtime, query_intents=query_intents)
    if not target_rows:
        return []
    target_source_rows = {
        str(row.get("SourceRow", "")).strip()
        for row in target_rows
        if str(row.get("SourceRow", "")).strip()
    }
    if not target_source_rows:
        return []
    source_candidates = [
        candidate
        for candidate in candidates
        if candidate.get("SourceRow", "") in target_source_rows
    ]
    admitted_candidates = [
        candidate
        for candidate in candidates
        if not candidate.get("SourceRow", "")
    ]
    if not source_candidates or not admitted_candidates:
        return []
    rows: list[dict[str, str]] = []
    seen: set[tuple[str, str, str, str]] = set()
    for start in sorted(
        source_candidates,
        key=lambda row: (
            _source_row_sort_key(row.get("SourceRow", "")),
            _date_atom_sort_key(row.get("Date", "")) or (9999, 99, 99),
        ),
    ):
        for end in sorted(
            admitted_candidates,
            key=lambda row: _date_atom_sort_key(row.get("Date", "")) or (9999, 99, 99),
        ):
            elapsed_days = _elapsed_days_between_date_atoms(start.get("Date", ""), end.get("Date", ""))
            if elapsed_days is None or elapsed_days <= 0:
                continue
            key = (start["Date"], end["Date"], start.get("SourceRow", ""), end.get("Field", ""))
            if key in seen:
                continue
            seen.add(key)
            rows.append(
                {
                    "SupportKind": "source_record_semantic_target_date_duration",
                    "StartRole": "semantic_target_source_date",
                    "StartRoleDisplay": "semantic target source date",
                    "StartDate": start["Date"],
                    "StartDateDisplay": _display_source_date_atom(start["Date"]),
                    "StartSourceRow": start.get("SourceRow", ""),
                    "StartSourceField": start.get("Field", ""),
                    "StartSourceDisplay": start.get("Display", ""),
                    "EndRole": "admitted_document_date",
                    "EndRoleDisplay": "admitted document date",
                    "EndDate": end["Date"],
                    "EndDateDisplay": _display_source_date_atom(end["Date"]),
                    "EndSourceRow": end.get("SourceRow", ""),
                    "EndSourceField": end.get("Field", ""),
                    "EndSourceDisplay": end.get("Display", ""),
                    "ElapsedDays": str(elapsed_days),
                    "Duration": f"{elapsed_days} day{'s' if elapsed_days != 1 else ''}",
                    "MatchScore": "80",
                    "SupportClass": "deterministic-source-record-summary",
                }
            )
            break
    return rows


def _date_duration_question_spans(utterance: str) -> tuple[str, str]:
    text = str(utterance or "").strip()
    match = re.search(
        r"\bbetween\b(?P<start>.+?)\band\b(?P<end>.+?)(?:[?.]|$)",
        text,
        flags=re.IGNORECASE | re.DOTALL,
    )
    if match:
        return match.group("start"), match.group("end")
    match = re.search(
        r"\bfrom\b(?P<start>.+?)\bto\b(?P<end>.+?)(?:[?.]|$)",
        text,
        flags=re.IGNORECASE | re.DOTALL,
    )
    if match:
        return match.group("start"), match.group("end")
    match = re.search(
        r"(?P<start>.+?)\band\b(?P<end>.+?)\b(?:differ|differs|difference)\b",
        text,
        flags=re.IGNORECASE | re.DOTALL,
    )
    if match:
        return match.group("start"), match.group("end")
    return "", ""


def _date_duration_span_tokens(value: str) -> set[str]:
    return {
        normalized
        for token in _query_atom_tokens(value)
        for normalized in [_date_duration_normalize_token(token)]
        if normalized
        if token not in _DATE_DURATION_STOP_TOKENS
        and token not in _SOURCE_MONTHS
        and not re.fullmatch(r"\d{1,4}", token)
    }


def _compact_role_from_span(value: str) -> str:
    tokens = [token for token in _date_duration_span_tokens(value) if len(token) > 1]
    return "_".join(tokens[:8])


def _source_record_date_duration_candidates(runtime: CorePrologRuntime) -> list[dict[str, str]]:
    date_aliases = _source_record_date_aliases(runtime)
    context_by_row: dict[str, list[str]] = {}
    for source_row, text_atom in _source_record_text_atoms(runtime):
        context_by_row.setdefault(source_row, []).append(text_atom)
    for fact in _runtime_fact_rows(runtime):
        predicate = str(fact.get("predicate", "")).strip()
        if predicate not in {"source_record_label", "source_record_section", "source_record_row_context"}:
            continue
        args = [str(item).strip() for item in fact.get("args", [])]
        if len(args) < 2:
            continue
        context_by_row.setdefault(args[0], []).extend(args[1:])
    text_by_row = {source_row: " ".join(parts) for source_row, parts in context_by_row.items()}
    candidates: list[dict[str, str]] = []
    seen: set[tuple[str, str, str]] = set()

    def add(*, source_row: str, date_value: str, field: str = "", text_atom: str = "") -> None:
        date = str(date_value or "").strip().removeprefix("v_")
        if _date_atom_sort_key(date) is None:
            return
        context_atom = text_atom or text_by_row.get(source_row, "")
        context = " ".join(item for item in [field, context_atom] if item)
        key = (source_row, field, date)
        if key in seen:
            return
        seen.add(key)
        display_parts = []
        if field:
            display_parts.append(_display_source_phrase(field))
        display_parts.append(_display_source_date_atom(date))
        candidates.append(
            {
                "SourceRow": source_row,
                "Field": field,
                "Date": date,
                "TextAtom": context_atom,
                "Context": context,
                "Display": " / ".join(part for part in display_parts if part),
            }
        )

    for fact in _runtime_fact_rows(runtime):
        predicate = str(fact.get("predicate", "")).strip()
        args = [str(item).strip() for item in fact.get("args", [])]
        if predicate in {"source_record_field", "source_record_field_item"} and len(args) >= 3:
            source_row, field, value = args[:3]
            canonical = date_aliases.get((source_row, value)) or _canonical_date_from_source_atom(value)
            if canonical:
                add(source_row=source_row, field=field, date_value=canonical)
        elif predicate == "source_record_date_alias" and len(args) >= 3:
            add(source_row=args[0], field="source_record_date_alias", date_value=args[2])
        elif not predicate.startswith("source_record_"):
            for index, value in enumerate(args):
                canonical = _canonical_admitted_date_atom(value)
                if not canonical:
                    continue
                field = _admitted_date_argument_role(predicate, index)
                context = " ".join([predicate, field, *args])
                key = (f"admitted:{predicate}:{index}", field, canonical)
                if key in seen:
                    continue
                seen.add(key)
                candidates.append(
                    {
                        "SourceRow": "",
                        "Field": field,
                        "Date": canonical,
                        "TextAtom": "",
                        "Context": context,
                        "Display": f"{_display_source_phrase(field)} / {_display_source_date_atom(canonical)}",
                    }
                )

    for source_row, text_atom in text_by_row.items():
        for date_value in _date_atoms_from_free_text(text_atom):
            add(source_row=source_row, date_value=date_value, text_atom=text_atom)
    default_year = _source_record_runtime_default_year(runtime)
    for source_row, display in _source_record_text_display_by_row(runtime).items():
        for date_value in _date_atoms_from_source_display(display, default_year=default_year):
            add(
                source_row=source_row,
                field="source_record_text_display",
                date_value=date_value,
                text_atom=display,
            )
    return candidates


def _source_record_runtime_default_year(runtime: CorePrologRuntime) -> str:
    years: list[str] = []
    for fact in _runtime_fact_rows(runtime):
        predicate = str(fact.get("predicate", "")).strip()
        args = [str(item).strip() for item in fact.get("args", [])]
        if predicate.startswith("source_record_"):
            continue
        for arg in args:
            match = re.search(r"(?:^|_)((?:19|20)\d{2})(?:_|$)", arg)
            if match:
                years.append(match.group(1))
    for display in _source_record_text_display_by_row(runtime).values():
        for match in re.finditer(r"(?:19|20)\d{2}", unicodedata.normalize("NFKC", str(display or ""))):
            years.append(match.group(0))
    if not years:
        return ""
    return Counter(years).most_common(1)[0][0]


def _date_atoms_from_source_display(value: str, *, default_year: str = "") -> list[str]:
    text = unicodedata.normalize("NFKC", str(value or ""))
    matches: list[tuple[int, str]] = []

    def add(start: int, year: int, month: str, day: str) -> None:
        if not str(month).isdigit() or not str(day).isdigit():
            return
        date_atom = f"{int(year):04d}_{int(month):02d}_{int(day):02d}"
        if _date_atom_sort_key(date_atom) is None:
            return
        matches.append((start, date_atom))

    for match in re.finditer(
        r"(?P<year>(?:19|20)\d{2})\s*\u5E74\s*(?P<month>\d{1,2})\s*"
        r"\u6708\s*(?P<day>\d{1,2})\s*\u65E5",
        text,
    ):
        add(match.start(), int(match.group("year")), match.group("month"), match.group("day"))
    for match in re.finditer(
        r"\u4EE4\u548C\s*(?P<year>\d{1,2})\s*\u5E74\s*(?P<month>\d{1,2})\s*"
        r"\u6708\s*(?P<day>\d{1,2})\s*\u65E5",
        text,
    ):
        add(match.start(), 2018 + int(match.group("year")), match.group("month"), match.group("day"))
    if default_year and default_year.isdigit():
        for match in re.finditer(
            r"(?<!\d)(?P<month>\d{1,2})\s*\u6708\s*(?P<day>\d{1,2})\s*\u65E5",
            text,
        ):
            add(match.start(), int(default_year), match.group("month"), match.group("day"))

    out: list[str] = []
    for _, date_atom in sorted(matches, key=lambda item: item[0]):
        if date_atom in out:
            continue
        out.append(date_atom)
    return out


def _canonical_admitted_date_atom(value: str) -> str:
    text = str(value or "").strip().removeprefix("v_")
    return text if _date_atom_sort_key(text) is not None else ""


def _admitted_date_argument_role(predicate: str, index: int) -> str:
    name = str(predicate or "").strip()
    if name == "inspection_period":
        if index == 1:
            return "inspection_period_start_date"
        if index == 2:
            return "inspection_period_end_date"
    if name in {"letter_date", "document_date", "filing_date"}:
        return name
    if name.endswith("_date"):
        return name
    if name.endswith("_event"):
        return f"{name}_date"
    return f"{name}_date_arg_{index}"


def _date_duration_candidate_score(candidate: dict[str, str], span_tokens: set[str]) -> int:
    if not span_tokens:
        return 0
    context_tokens = _date_duration_relevance_tokens(candidate.get("Context", ""))
    field_tokens = _date_duration_relevance_tokens(candidate.get("Field", ""))
    overlap = span_tokens & context_tokens
    field_overlap = span_tokens & field_tokens
    return len(overlap) + len(field_overlap)


def _date_duration_relevance_tokens(value: str) -> set[str]:
    out: set[str] = set()
    for token in _query_atom_tokens(value):
        if token in _DATE_DURATION_STOP_TOKENS or token in _SOURCE_MONTHS or re.fullmatch(r"\d{1,4}", token):
            continue
        normalized = _date_duration_normalize_token(token)
        if normalized:
            out.add(normalized)
    return out


def _date_duration_normalize_token(token: str) -> str:
    text = str(token or "").strip().casefold()
    if not text:
        return ""
    if text in {"abate", "abated", "abatement", "abating"}:
        return "abat"
    if text in {"close", "closed", "closing", "closure"}:
        return "clos"
    if text in {"issue", "issued", "issuance", "issuing"}:
        return "issu"
    if text in {"publish", "published", "publication", "public"}:
        return "publish"
    if text in {"release", "released"}:
        return "release"
    if text in {"inspect", "inspected", "inspection"}:
        return "inspect"
    if text in {"respond", "response", "reviewed", "review"}:
        return text.removesuffix("ed")
    return text


def _date_atoms_from_free_text(value: str) -> list[str]:
    text = str(value or "").casefold()
    matches: list[tuple[int, str]] = []
    month_pattern = "|".join(re.escape(month) for month in _SOURCE_MONTHS)
    patterns = [
        re.compile(
            rf"(?:^|[^a-z0-9])(?P<month>{month_pattern})[\s_]+(?P<day>\d{{1,2}})(?:st|nd|rd|th)?(?:,)?[\s_]+(?P<year>(?:19|20)\d{{2}})(?:[^a-z0-9]|$)"
        ),
        re.compile(
            r"(?:^|[^a-z0-9])(?P<month>\d{1,2})[/_-](?P<day>\d{1,2})[/_-](?P<year>(?:19|20)?\d{2})(?:[^a-z0-9]|$)"
        ),
        re.compile(r"(?:^|_)(?:v_)?(?P<year>(?:19|20)\d{2})_(?P<month>\d{2})_(?P<day>\d{2})(?:_|$)"),
    ]
    for pattern in patterns:
        for match in pattern.finditer(text):
            if "year" not in match.groupdict():
                continue
            year = int(match.group("year"))
            if year < 100:
                year += 2000 if year < 70 else 1900
            month_text = match.group("month")
            month = _SOURCE_MONTHS.get(month_text, month_text)
            day = match.group("day")
            if not str(month).isdigit() or not str(day).isdigit():
                continue
            date_atom = f"{year:04d}_{int(month):02d}_{int(day):02d}"
            if _date_atom_sort_key(date_atom) is None:
                continue
            matches.append((match.start(), date_atom))
    out: list[str] = []
    for _, date_atom in sorted(matches, key=lambda item: item[0]):
        if date_atom in out:
            continue
        out.append(date_atom)
    return out


def _source_record_agreement_counterparty_companion(
    runtime: CorePrologRuntime,
    *,
    utterance: str,
) -> dict[str, Any] | None:
    text = str(utterance or "").casefold()
    if "counterparty" not in text:
        return None
    if not re.search(r"\b(?:agreement|amendment|contract|loan|filing)\b", text):
        return None
    query_tokens = set(_query_atom_tokens(text))
    if not (query_tokens & {"agreement", "amendment", "contract", "loan"}):
        return None

    agreements: list[tuple[str, str, str]] = []
    roles: list[tuple[str, str, str]] = []
    for fact in _runtime_fact_rows(runtime):
        predicate = str(fact.get("predicate", "")).strip()
        args = [str(item).strip() for item in fact.get("args", [])]
        if predicate == "entered_agreement" and len(args) >= 3:
            agreements.append((args[0], args[1], args[2]))
        elif predicate == "entity_role" and len(args) >= 3:
            roles.append((args[0], args[1], args[2]))
    if not agreements:
        return None

    target_agreements: list[tuple[str, str, str]] = []
    for agreement, date_value, parties in agreements:
        agreement_tokens = set(_query_atom_tokens(agreement))
        parties_tokens = set(_query_atom_tokens(parties))
        overlap = len((agreement_tokens | parties_tokens) & query_tokens)
        if overlap <= 0:
            continue
        if query_tokens & {"second", "amendment"} and not ({"second", "amendment"} & agreement_tokens):
            continue
        target_agreements.append((agreement, date_value, parties))
    if not target_agreements:
        return None

    text_atoms = _source_record_text_atoms(runtime)
    support_rows: list[dict[str, str]] = []
    seen: set[tuple[str, str, str]] = set()
    counterparty_roles = {"counterparty", "lender", "seller", "buyer", "vendor", "lessor", "lessee", "agent", "bank"}
    for agreement, date_value, parties in target_agreements:
        agreement_tokens = set(_query_atom_tokens(agreement))
        parties_tokens = set(_query_atom_tokens(parties))
        for entity, role, context in roles:
            role_tokens = set(_query_atom_tokens(role))
            if not (role_tokens & counterparty_roles):
                continue
            entity_tokens = set(_query_atom_tokens(entity))
            context_tokens = set(_query_atom_tokens(context))
            context_matches = (
                context == agreement
                or bool(context_tokens & agreement_tokens)
                or bool(entity_tokens & parties_tokens)
                or bool(context_tokens & parties_tokens)
            )
            source_matches = [
                (source_row, text_atom)
                for source_row, text_atom in text_atoms
                if entity_tokens
                and entity_tokens <= set(_query_atom_tokens(text_atom))
                and agreement_tokens
                and bool(agreement_tokens & set(_query_atom_tokens(text_atom)))
            ]
            if not context_matches and not source_matches:
                continue
            source_row = source_matches[0][0] if source_matches else ""
            source_text_atom = source_matches[0][1] if source_matches else ""
            key = (agreement, entity, source_row)
            if key in seen:
                continue
            seen.add(key)
            support_rows.append(
                {
                    "SupportKind": "agreement_counterparty",
                    "Agreement": agreement,
                    "AgreementDisplay": _display_source_phrase(agreement),
                    "AgreementDate": date_value,
                    "Parties": parties,
                    "CounterpartyEntity": entity,
                    "CounterpartyDisplay": _source_record_counterparty_display(entity, source_text_atom),
                    "CounterpartyRole": role,
                    "RoleContext": context,
                    "SourceRow": source_row,
                    "SourceTextAtom": source_text_atom,
                    "SourceTextDisplay": _display_source_phrase(source_text_atom),
                    "SupportClass": "deterministic-source-record-summary",
                }
            )
    if not support_rows:
        return None
    support_rows.sort(
        key=lambda row: (
            0 if set(_query_atom_tokens(row["Agreement"])) & {"second", "amendment"} else 1,
            0 if row.get("SourceRow") else 1,
            row.get("Agreement", ""),
            row.get("CounterpartyEntity", ""),
        )
    )
    return {
        "query": "source_record_agreement_counterparty_support(Agreement, CounterpartyEntity, CounterpartyRole).",
        "result": {
            "status": "success",
            "predicate": "source_record_agreement_counterparty_support",
            "prolog_query": "source_record_agreement_counterparty_support(Agreement, CounterpartyEntity, CounterpartyRole).",
            "result_type": "table",
            "num_rows": len(support_rows),
            "variables": _row_variable_names(support_rows),
            "rows": support_rows[:20],
            "reasoning_basis": {
                "kind": "core-local",
                "note": (
                    "query-only agreement counterparty companion joined admitted entered_agreement, "
                    "entity_role, and source_record_text_atom rows for counterparty questions"
                ),
                "utterance": utterance,
            },
        },
        "derived_from_queries": [
            "entered_agreement(Agreement, Date, Parties).",
            "entity_role(Entity, Role, Context).",
            "source_record_text_atom(SourceRow, TextAtom).",
        ],
    }


def _source_record_distinct_field_count_companion(
    runtime: CorePrologRuntime,
    *,
    utterance: str,
) -> dict[str, Any] | None:
    text = str(utterance or "").casefold()
    if not ("distinct" in text and _utterance_asks_for_count(text)):
        return None
    field = _best_source_record_field_for_tokens(runtime, text)
    if not field:
        return None
    values_by_row = _source_record_field_values(runtime, field=field, include_items=True, prefer_items=True)
    distinct_values = sorted(
        {
            display_value
            for values in values_by_row.values()
            for value in values
            for display_value in _source_record_distinct_display_values(field=field, value=value)
        }
    )
    if not distinct_values:
        return None
    support_rows: list[dict[str, str]] = [
        {
            "SupportKind": "distinct_field_count",
            "Field": field,
            "DistinctCount": str(len(distinct_values)),
            "DistinctValues": ",".join(distinct_values),
            "SourceRowCount": str(len(values_by_row)),
            "SupportClass": "deterministic-source-record-summary",
        }
    ]
    for source_row, values in sorted(values_by_row.items(), key=lambda item: _source_row_sort_key(item[0]))[:80]:
        normalized = sorted(
            {
                display_value
                for value in values
                for display_value in _source_record_distinct_display_values(field=field, value=value)
            }
        )
        if not normalized:
            continue
        support_rows.append(
            {
                "SupportKind": "distinct_field_member",
                "Field": field,
                "SourceRow": source_row,
                "Values": ",".join(normalized),
                "SupportClass": "deterministic-source-record-summary",
            }
        )
    return {
        "query": "source_record_distinct_field_count_support(Field, DistinctCount, DistinctValues).",
        "result": {
            "status": "success",
            "predicate": "source_record_distinct_field_count_support",
            "prolog_query": "source_record_distinct_field_count_support(Field, DistinctCount, DistinctValues).",
            "result_type": "table",
            "num_rows": len(support_rows),
            "variables": list(support_rows[0].keys()),
            "rows": support_rows,
            "reasoning_basis": {
                "kind": "core-local",
                "note": (
                    "query-only source-record aggregate counted distinct admitted field/item values "
                    "for a count-distinct question; no durable aggregate fact was written"
                ),
                "utterance": utterance,
            },
        },
        "derived_from_queries": [
            "source_record_field(SourceRow, Field, Value).",
            "source_record_field_item(SourceRow, Field, Value).",
        ],
    }


def _source_record_identifier_set_companion(
    runtime: CorePrologRuntime,
    *,
    utterance: str,
    query_intents: list[dict[str, Any]] | None = None,
) -> dict[str, Any] | None:
    if not _source_record_identifier_set_active(utterance=utterance, query_intents=query_intents):
        return None

    support_rows: list[dict[str, str]] = []
    seen: set[tuple[str, str, str]] = set()

    def append_row(
        *,
        source_row: str,
        label: str,
        value: str,
        source_predicate: str,
        text_atom: str = "",
        source_text_display: str = "",
        display_override: str = "",
    ) -> None:
        display = display_override or _source_record_identifier_display(label=label, value=value, text_atom=text_atom)
        if not display:
            return
        key = (source_row, label, display)
        if key in seen:
            return
        seen.add(key)
        support_rows.append(
            {
                "SupportKind": "source_record_identifier",
                "IdentifierKind": label,
                "IdentifierValue": value,
                "IdentifierDisplay": display,
                "SourceRow": source_row,
                "SourcePredicate": source_predicate,
                **({"SourceTextAtom": text_atom} if text_atom else {}),
                **({"SourceTextDisplay": source_text_display} if source_text_display else {}),
                "SupportClass": "deterministic-source-record-summary",
            }
        )

    text_atoms_by_row = {source_row: atom for source_row, atom in _source_record_text_atoms(runtime)}
    text_display_by_row = _source_record_text_display_by_row(runtime)
    surfaces_by_row = _source_record_surface_mentions_by_row(runtime)
    query_label = _source_record_identifier_label_from_query_intents(query_intents)
    labels_by_row: dict[str, str] = {}
    numeric_by_row: dict[str, list[str]] = {}
    for fact in _runtime_fact_rows(runtime):
        predicate = str(fact.get("predicate", "")).strip()
        args = [str(item).strip() for item in fact.get("args", [])]
        if predicate == "source_record_label" and len(args) >= 2:
            labels_by_row[args[0]] = args[1]
        if predicate == "source_record_numeric_token" and len(args) >= 2:
            numeric_by_row.setdefault(args[0], []).append(args[1])

    for fact in _runtime_fact_rows(runtime):
        predicate = str(fact.get("predicate", "")).strip()
        args = [str(item).strip() for item in fact.get("args", [])]
        if predicate in {"source_record_field", "source_record_field_item", "source_record_inline_field"} and len(args) >= 3:
            source_row, field, value = args[:3]
            if _source_record_identifier_label(field) or _source_record_identifier_label(value):
                append_row(
                    source_row=source_row,
                    label=field,
                    value=value,
                    source_predicate=predicate,
                    text_atom=text_atoms_by_row.get(source_row, ""),
                    source_text_display=text_display_by_row.get(source_row, ""),
                )
        elif predicate in {"source_record_field_item_pair", "source_record_cell_item_pair"} and len(args) >= 5:
            source_row, left_field, left_value, right_field, right_value = args[:5]
            for label, value in ((left_field, left_value), (right_field, right_value)):
                if _source_record_identifier_label(label) or _source_record_identifier_label(value):
                    append_row(
                        source_row=source_row,
                        label=label,
                        value=value,
                        source_predicate=predicate,
                        text_atom=text_atoms_by_row.get(source_row, ""),
                        source_text_display=text_display_by_row.get(source_row, ""),
                    )

    for source_row, text_atom in text_atoms_by_row.items():
        row_label = labels_by_row.get(source_row, "")
        label = _source_record_identifier_label(row_label) or _source_record_identifier_label(text_atom)
        if not label:
            continue
        label_value_display = _source_record_identifier_label_value_display(label=row_label, text_atom=text_atom)
        if label_value_display:
            append_row(
                source_row=source_row,
                label=row_label or label,
                value=_source_record_identifier_value_from_label(row_label, text_atom) or text_atom,
                source_predicate="source_record_text_atom",
                text_atom=text_atom,
                source_text_display=text_display_by_row.get(source_row, ""),
                display_override=label_value_display,
            )
            continue
        values = numeric_by_row.get(source_row, [])
        if not values and re.search(r"\d", text_atom):
            values = [text_atom]
        for value in values:
            append_row(
                source_row=source_row,
                label=label,
                value=value,
                source_predicate="source_record_text_atom",
                text_atom=text_atom,
                source_text_display=text_display_by_row.get(source_row, ""),
            )

    for source_row, surface_mentions in sorted(surfaces_by_row.items(), key=lambda item: _source_row_sort_key(item[0])):
        row_label = labels_by_row.get(source_row, "")
        row_text_atom = text_atoms_by_row.get(source_row, "")
        label = (
            _source_record_identifier_label(row_label)
            or _source_record_identifier_label(row_text_atom)
            or query_label
            or "identifier"
        )
        for atom, display in surface_mentions:
            if not _source_record_identifier_surface_candidate(atom=atom, display=display):
                continue
            append_row(
                source_row=source_row,
                label=label,
                value=atom,
                source_predicate="source_record_surface_mention",
                text_atom=row_text_atom,
                source_text_display=text_display_by_row.get(source_row, ""),
                display_override=display,
            )

    if not support_rows:
        return None
    support_rows.sort(key=lambda row: (_source_row_sort_key(row.get("SourceRow", "")), row.get("IdentifierKind", "")))
    return {
        "query": "source_record_identifier_set_support(IdentifierKind, IdentifierValue, IdentifierDisplay, SourceRow).",
        "result": {
            "status": "success",
            "predicate": "source_record_identifier_set_support",
            "prolog_query": "source_record_identifier_set_support(IdentifierKind, IdentifierValue, IdentifierDisplay, SourceRow).",
            "result_type": "table",
            "num_rows": len(support_rows),
            "variables": _row_variable_names(support_rows),
            "rows": support_rows[:80],
            "reasoning_basis": {
                "kind": "core-local",
                "note": (
                    "query-only identifier support collected identifier/reference-number rows from admitted "
                    "source_record_* surfaces; no durable identifier fact was written"
                ),
                "utterance": utterance,
            },
        },
        "derived_from_queries": [
            "source_record_field(SourceRow, Field, Value).",
            "source_record_field_item(SourceRow, Field, Value).",
            "source_record_field_item_pair(SourceRow, LeftField, LeftValue, RightField, RightValue).",
            "source_record_numeric_token(SourceRow, Value).",
            "source_record_text_atom(SourceRow, TextAtom).",
            "source_record_surface_mention(SourceRow, MentionAtom, MentionDisplay).",
        ],
    }


def _source_record_identifier_set_active(
    *,
    utterance: str,
    query_intents: list[dict[str, Any]] | None = None,
) -> bool:
    del utterance
    tokens = _query_intents_target_tokens(query_intents)
    for intent in query_intents or []:
        if not isinstance(intent, dict):
            continue
        tokens.update(_query_intent_constraint_tokens(intent))
        intent_type = str(intent.get("intent_type", "")).strip()
        tokens.update(token for token in _query_atom_tokens(intent_type) if len(token) >= 3)
    identifier_tokens = {
        "case",
        "control",
        "docket",
        "document",
        "fei",
        "file",
        "id",
        "identifier",
        "identifiers",
        "inspection",
        "investigation",
        "letter",
        "number",
        "numbers",
        "reference",
        "report",
        "tracking",
    }
    return bool(tokens & identifier_tokens and (tokens & {"id", "identifier", "identifiers", "number", "numbers", "reference"}))


def _source_record_identifier_label_from_query_intents(query_intents: list[dict[str, Any]] | None) -> str:
    for intent in query_intents or []:
        if not isinstance(intent, dict):
            continue
        fields = [
            *[str(item or "") for item in intent.get("target_terms", []) or []],
            *[str(item or "") for item in intent.get("answer_constraints", []) or []],
            str(intent.get("intent_type", "") or ""),
        ]
        for field in fields:
            label = _source_record_identifier_label(field)
            if label:
                return label
    return ""


def _source_record_identifier_surface_candidate(*, atom: str, display: str) -> bool:
    shown = str(display or "").strip()
    normalized = _normalize_source_record_display_value(atom or shown)
    if not shown or not re.search(r"\d", shown + normalized):
        return False
    shown_key = _compact_identifier_key(shown)
    normalized_key = _compact_identifier_key(normalized)
    if not shown_key and not normalized_key:
        return False
    lower_display = shown.casefold()
    if re.search(r"\b(?:january|february|march|april|may|june|july|august|september|october|november|december)\b", lower_display):
        return False
    if re.fullmatch(r"\d{1,2}[/-]\d{1,2}[/-]\d{2,4}", shown):
        return False
    if re.fullmatch(r"\d{4}[-_/]\d{1,2}[-_/]\d{1,2}", shown):
        return False
    has_letter_digit = bool(re.search(r"[a-zA-Z]", shown + normalized)) and bool(re.search(r"\d", shown + normalized))
    has_identifier_punctuation = bool(re.search(r"[#./-]", shown)) or "_" in normalized
    return has_letter_digit and has_identifier_punctuation


def _source_record_identifier_label(value: str) -> str:
    tokens = set(_source_record_field_name_tokens(value))
    if not tokens:
        return ""
    if {"document", "control", "number"} <= tokens:
        return "document_control_number"
    if {"control", "number"} <= tokens:
        return "control_number"
    if {"incorporation", "state", "country", "code"} <= tokens:
        return "incorporation_state_country_code"
    if {"file", "number"} <= tokens:
        return "file_number"
    if {"tax", "identification"} <= tokens or {"tax", "identifier"} <= tokens:
        return "tax_identification_number"
    if "address" in tokens:
        if {"line", "1"} <= tokens:
            return "address_line_1"
        if {"line", "2"} <= tokens:
            return "address_line_2"
        if {"city", "town"} & tokens:
            return "address_city_or_town"
        if {"state", "province"} & tokens:
            return "address_state_or_province"
        if {"postal", "zip", "code"} & tokens:
            return "address_postal_zip_code"
    if {"security", "title"} <= tokens:
        return "security_title"
    if {"trading", "symbol"} <= tokens:
        return "trading_symbol"
    if {"exchange", "name"} <= tokens:
        return "exchange_name"
    if {"marcs", "cms"} <= tokens:
        return "marcs_cms"
    if {"warning", "letter"} <= tokens:
        return "warning_letter"
    if {"report", "id"} <= tokens:
        return "report_id"
    if {"inspection", "nr"} <= tokens or {"inspection", "number"} <= tokens:
        return "inspection_nr"
    if {"investigation", "nr"} <= tokens or {"investigation", "number"} <= tokens:
        return "investigation_nr"
    if {"accident", "summary", "nr"} <= tokens:
        return "accident_summary_nr"
    if {"activity", "nr"} <= tokens:
        return "activity_nr"
    if {"case", "id"} <= tokens:
        return "case_id"
    if {"fei"} & tokens:
        return "fei"
    if {"identifier", "identifiers", "id", "nr"} & tokens:
        return "_".join(sorted(tokens & {"identifier", "identifiers", "id", "nr"}))
    return ""


def _source_record_identifier_label_value_display(*, label: str, text_atom: str) -> str:
    label_atom = _normalize_text_filter_atom(label)
    value_atom = _source_record_identifier_value_from_label(label_atom, text_atom)
    if not label_atom or not value_atom:
        return ""
    match = re.search(
        r"(?P<start>\d{4}_\d{2}_\d{2})_to_(?P<end>\d{4}_\d{2}_\d{2})(?:_|$)",
        label_atom,
    )
    field_atom = label_atom[: match.start()].strip("_") if match else label_atom
    field_display = _display_source_phrase(field_atom)
    value_display = _source_record_identifier_value_display(field_atom=field_atom, value_atom=value_atom)
    if not field_display or not value_display:
        return ""
    if match:
        start = _display_source_date_atom(match.group("start"))
        end = _display_source_date_atom(match.group("end"))
        return f"{field_display} ({start} to {end}): {value_display}"
    return f"{field_display}: {value_display}"


def _source_record_identifier_value_from_label(label: str, text_atom: str) -> str:
    label_atom = _normalize_text_filter_atom(label)
    atom = _normalize_text_filter_atom(text_atom)
    if not label_atom or not atom:
        return ""
    if atom == label_atom:
        return ""
    if atom.startswith(f"{label_atom}_"):
        return atom[len(label_atom) + 1 :].strip("_")
    return ""


def _source_record_identifier_value_display(*, field_atom: str, value_atom: str) -> str:
    field_tokens = set(_source_record_field_name_tokens(field_atom))
    value = _normalize_source_record_display_value(value_atom)
    if not value:
        return ""
    if {"file", "number"} <= field_tokens:
        return _first_identifier_number(value).replace(".", "-") or _display_source_phrase(value)
    if {"tax", "identification"} <= field_tokens:
        return _joined_identifier_number(value)
    if {"postal", "zip", "code"} & field_tokens:
        return _first_identifier_number(value) or _display_source_phrase(value)
    if {"security", "title"} <= field_tokens:
        return _display_source_phrase(value).replace("0 01", "$0.01")
    return _display_source_phrase(value)


def _source_record_identifier_display(*, label: str, value: str, text_atom: str = "") -> str:
    label = _source_record_identifier_label(label) or str(label or "").strip()
    raw_value = str(value or "").strip()
    raw_text = str(text_atom or "").strip()
    normalized = _normalize_source_record_display_value(raw_value)
    if not normalized:
        return ""
    if label == "marcs_cms":
        number = _first_identifier_number(normalized) or _first_identifier_number(raw_text)
        return f"{_source_record_identifier_label_display(label)} {number}" if number else _display_source_phrase(raw_text or raw_value)
    if label == "warning_letter":
        number = _joined_identifier_number(normalized) or _joined_identifier_number(raw_text)
        return f"Warning Letter {number}" if number else _display_source_phrase(raw_text or raw_value)
    if label in {"inspection_nr", "investigation_nr", "accident_summary_nr"}:
        number = _dotted_identifier_number(normalized)
        title = {
            "inspection_nr": "Inspection Nr",
            "investigation_nr": "Investigation Nr",
            "accident_summary_nr": "Accident Summary Nr",
        }[label]
        return f"{title} {number}" if number else _display_source_phrase(raw_value)
    if label == "report_id":
        number = _first_identifier_number(normalized)
        return f"Report ID {number}" if number else _display_source_phrase(raw_value)
    if label == "activity_nr":
        number = _first_identifier_number(normalized)
        return f"Activity Nr {number}" if number else _display_source_phrase(raw_value)
    if label == "fei":
        number = _first_identifier_number(normalized)
        return f"{_source_record_identifier_label_display(label)} {number}" if number else _display_source_phrase(raw_value)
    return _display_source_phrase(raw_value)


def _source_record_identifier_label_display(label: str) -> str:
    parts = [part for part in _normalize_text_filter_atom(label).split("_") if part]
    if not parts:
        return ""
    if all(1 < len(part) <= 5 for part in parts):
        return "-".join(part.upper() for part in parts)
    return _display_source_phrase("_".join(parts))


def _source_record_same_day_case_disposition_companion(
    runtime: CorePrologRuntime,
    *,
    utterance: str,
    query_intents: list[dict[str, Any]] | None = None,
) -> dict[str, Any] | None:
    if not _source_record_same_day_case_disposition_active(utterance=utterance, query_intents=query_intents):
        return None
    surfaces_by_row = _source_record_surface_mentions_by_row(runtime)
    support_rows: list[dict[str, str]] = []
    for source_row, display in sorted(_source_record_text_display_by_row(runtime).items(), key=lambda item: _source_row_sort_key(item[0])):
        text = unicodedata.normalize("NFKC", str(display or ""))
        lowered = text.casefold()
        if not (
            re.search(r"\b(?:also|same)\s+decid(?:e|ed)\s+(?:today|the same day)\b", lowered)
            or re.search(r"\bsame\s+day\b", lowered)
        ):
            continue
        if not re.search(r"\b(?:affirm(?:ing|ed)?|uphold(?:ing|s|held)?|deny|denied|grant(?:ed)?|dismiss(?:ed)?)\b", lowered):
            continue
        case_display = _source_record_same_day_case_identifier_display(
            text=text,
            surface_mentions=surfaces_by_row.get(source_row, []),
        )
        if not case_display:
            continue
        support_rows.append(
            {
                "SupportKind": "source_record_same_day_case_disposition",
                "SourceRow": source_row,
                "CaseDisplay": case_display,
                "DispositionDisplay": _source_record_same_day_case_disposition_excerpt(text),
                "SourceTextDisplay": text,
                "SupportClass": "deterministic-source-record-summary",
            }
        )
    if not support_rows:
        return None
    return {
        "query": "source_record_same_day_case_disposition_support(SourceRow, CaseDisplay, DispositionDisplay).",
        "result": {
            "status": "success",
            "predicate": "source_record_same_day_case_disposition_support",
            "prolog_query": "source_record_same_day_case_disposition_support(SourceRow, CaseDisplay, DispositionDisplay).",
            "result_type": "table",
            "num_rows": len(support_rows),
            "variables": _row_variable_names(support_rows),
            "rows": support_rows[:40],
            "reasoning_basis": {
                "kind": "core-local",
                "note": (
                    "query-only same-day companion-case support preserved admitted source-record text "
                    "that links another case identifier to a same-day disposition"
                ),
                "utterance": utterance,
                "query_intents": query_intents or [],
            },
        },
        "derived_from_queries": [
            "source_record_text_display(SourceRow, Text).",
            "source_record_surface_mention(SourceRow, MentionAtom, MentionDisplay).",
        ],
    }


def _source_record_same_day_case_disposition_active(
    *,
    utterance: str,
    query_intents: list[dict[str, Any]] | None = None,
) -> bool:
    del utterance
    tokens = _query_intents_target_tokens(query_intents)
    for intent in query_intents or []:
        if not isinstance(intent, dict):
            continue
        tokens.update(_query_intent_constraint_tokens(intent))
        tokens.update(token for token in _query_atom_tokens(str(intent.get("intent_type", ""))) if len(token) >= 3)
    return bool({"case", "companion"} & tokens and {"disposition", "status", "same", "date", "decided"} & tokens)


def _source_record_same_day_case_identifier_display(
    *,
    text: str,
    surface_mentions: list[tuple[str, str]],
) -> str:
    for _atom, display in surface_mentions:
        shown = str(display or "").strip()
        if re.fullmatch(r"(?:No\.\s*)?(?:\d{4}-\d+(?:\.\d+)?)", shown, flags=re.IGNORECASE):
            return shown if shown.casefold().startswith("no.") else f"No. {shown}"
    match = re.search(r"\bNo\.\s*(?P<number>\d{4}-\d+(?:\.\d+)?)\b", text, flags=re.IGNORECASE)
    if match:
        return f"No. {match.group('number')}"
    return ""


def _source_record_same_day_case_disposition_excerpt(text: str) -> str:
    value = unicodedata.normalize("NFKC", str(text or ""))
    if not value:
        return ""
    for pattern in (
        r"[^.]*\b(?:also|same)\s+decid(?:e|ed)\s+(?:today|the same day)\b[^.]*\.",
        r"[^.]*\bsame\s+day\b[^.]*\.",
    ):
        match = re.search(pattern, value, flags=re.IGNORECASE)
        if match:
            return re.sub(r"\s+", " ", match.group(0)).strip()
    return re.sub(r"\s+", " ", value).strip()


def _compiled_case_identifier_location_roster_companion(
    runtime: CorePrologRuntime,
    *,
    query_intents: list[dict[str, Any]] | None = None,
) -> dict[str, Any] | None:
    if not _compiled_case_identifier_location_roster_active(query_intents):
        return None

    case_ids = _compiled_case_ids(runtime)
    if not case_ids:
        return None
    direct_locations = _compiled_case_locations(runtime)
    text_atoms = _source_record_text_atoms(runtime)
    if not text_atoms:
        return None
    surfaces_by_row = _source_record_surface_mentions_by_row(runtime)

    support_rows: list[dict[str, str]] = []
    seen: set[tuple[str, str]] = set()
    for source_row, text_atom in sorted(text_atoms, key=lambda item: _source_row_sort_key(item[0])):
        row_case_ids = [
            case_id
            for case_id in case_ids
            if _source_record_row_contains_case_id(
                case_id=case_id,
                text_atom=text_atom,
                surface_mentions=surfaces_by_row.get(source_row, []),
            )
        ]
        if not row_case_ids:
            continue
        row_location_atoms = [
            direct_locations[case_id]
            for case_id in row_case_ids
            if case_id in direct_locations and direct_locations[case_id]
        ]
        if not row_location_atoms:
            row_location_atoms = _source_record_row_location_like_atoms(surfaces_by_row.get(source_row, []))
        if not row_location_atoms:
            continue
        location_display = "; ".join(
            _source_record_surface_or_atom_display(
                atom=location_atom,
                surface_mentions=surfaces_by_row.get(source_row, []),
            )
            for location_atom in _dedupe_preserve_order(row_location_atoms)
        )
        identifier_display = "; ".join(
            _source_record_case_identifier_display(
                case_id,
                surface_mentions=surfaces_by_row.get(source_row, []),
                text_atom=text_atom,
            )
            for case_id in row_case_ids
        )
        key = (source_row, ",".join(row_case_ids))
        if key in seen:
            continue
        seen.add(key)
        support_rows.append(
            {
                "SupportKind": "compiled_case_identifier_location_roster_item",
                "SourceRow": source_row,
                "CaseIDAtoms": ",".join(row_case_ids),
                "CaseIDDisplay": identifier_display,
                "LocationAtoms": ",".join(_dedupe_preserve_order(row_location_atoms)),
                "LocationDisplay": location_display,
                "SourceTextAtom": text_atom,
                "SourceTextDisplay": _display_source_phrase(text_atom),
                "SupportClass": "deterministic-source-record-summary",
            }
        )

    if not support_rows:
        return None
    summary_display = "; ".join(
        f"{row['CaseIDDisplay']} - {row['LocationDisplay']}" for row in support_rows
    )
    rows = [
        *support_rows,
        {
            "SupportKind": "compiled_case_identifier_location_roster_summary",
            "SourceRow": "compiled_case_identifier_location_roster",
            "EntryCount": str(len(support_rows)),
            "RosterDisplay": summary_display,
            "SupportClass": "deterministic-source-record-summary",
        },
    ]
    return {
        "query": "compiled_case_identifier_location_roster_support(SourceRow, CaseIDAtoms, LocationAtoms).",
        "result": {
            "status": "success",
            "predicate": "compiled_case_identifier_location_roster_support",
            "prolog_query": "compiled_case_identifier_location_roster_support(SourceRow, CaseIDAtoms, LocationAtoms).",
            "result_type": "table",
            "num_rows": len(rows),
            "variables": _row_variable_names(rows),
            "rows": rows[:80],
            "reasoning_basis": {
                "kind": "core-local",
                "note": (
                    "query-only case identifier/location roster support grouped admitted case_id rows by "
                    "admitted source-record rows and location evidence; no durable case or location fact was written"
                ),
                "query_intents": query_intents or [],
            },
        },
        "derived_from_queries": [
            "case_id(CaseID).",
            "case_location(CaseID, Location).",
            "source_record_text_atom(SourceRow, TextAtom).",
            "source_record_surface_mention(SourceRow, MentionAtom, MentionDisplay).",
        ],
    }


def _compiled_case_identifier_location_roster_active(query_intents: list[dict[str, Any]] | None) -> bool:
    intent = _first_query_intent(query_intents, "list", "source_location")
    if not intent:
        return False
    tokens = _query_intents_target_tokens(query_intents) | _query_intent_constraint_tokens(intent)
    identifier_tokens = {
        "case",
        "cases",
        "citation",
        "citations",
        "docket",
        "identifier",
        "identifiers",
        "number",
        "numbers",
    }
    location_tokens = {"geographic", "location", "locations", "place", "venue"}
    return bool(tokens & identifier_tokens) and bool(tokens & location_tokens)


def _compiled_case_ids(runtime: CorePrologRuntime) -> list[str]:
    out: list[str] = []
    for row in _runtime_rows(runtime, "case_id(CaseID)."):
        case_id = str(row.get("CaseID", "")).strip()
        if case_id and case_id not in out:
            out.append(case_id)
    return out


def _compiled_case_locations(runtime: CorePrologRuntime) -> dict[str, str]:
    out: dict[str, str] = {}
    for row in _runtime_rows(runtime, "case_location(CaseID, Location)."):
        case_id = str(row.get("CaseID", "")).strip()
        location = str(row.get("Location", "")).strip()
        if case_id and location and case_id not in out:
            out[case_id] = location
    return out


def _source_record_surface_mentions_by_row(runtime: CorePrologRuntime) -> dict[str, list[tuple[str, str]]]:
    out: dict[str, list[tuple[str, str]]] = {}
    for fact in _runtime_fact_rows(runtime):
        if str(fact.get("predicate", "")).strip() != "source_record_surface_mention":
            continue
        args = [str(item).strip() for item in fact.get("args", [])]
        if len(args) < 3:
            continue
        out.setdefault(args[0], []).append((args[1], args[2].strip("'")))
    return out


def _source_record_row_contains_case_id(
    *,
    case_id: str,
    text_atom: str,
    surface_mentions: list[tuple[str, str]],
) -> bool:
    case_key = _compact_identifier_key(case_id)
    if not case_key:
        return False
    if case_key in _compact_identifier_key(text_atom):
        return True
    for atom, display in surface_mentions:
        if case_key in _compact_identifier_key(atom) or case_key in _compact_identifier_key(display):
            return True
    return False


def _source_record_case_identifier_display(
    case_id: str,
    *,
    surface_mentions: list[tuple[str, str]],
    text_atom: str,
) -> str:
    case_key = _compact_identifier_key(case_id)
    for atom, display in surface_mentions:
        atom_key = _compact_identifier_key(atom)
        display_key = _compact_identifier_key(display)
        normalized_atom_key = _compact_identifier_key(_normalize_source_record_display_value(atom))
        if case_key and case_key in {atom_key, display_key, normalized_atom_key}:
            return display
    return _display_case_identifier_atom(case_id, text_atom=text_atom)


def _display_case_identifier_atom(case_id: str, *, text_atom: str = "") -> str:
    atom = _normalize_source_record_display_value(case_id)
    reporter_match = re.fullmatch(r"(?P<volume>\d+)_(?P<reporter>[a-z][a-z0-9]*)_no_(?P<number>\d+)", atom)
    if reporter_match:
        return (
            f"{reporter_match.group('volume')} "
            f"{reporter_match.group('reporter').upper()} No. "
            f"{reporter_match.group('number')}"
        )
    if re.fullmatch(r"\d{2}_[a-z]{2}_\d{5,6}", atom):
        parts = atom.split("_", 2)
        return f"{parts[0]}-{parts[1].upper()}-{parts[2]}"
    if atom and atom in _normalize_text_filter_atom(text_atom):
        return _display_source_phrase(atom)
    return _display_source_phrase(atom)


def _source_record_surface_or_atom_display(*, atom: str, surface_mentions: list[tuple[str, str]]) -> str:
    atom_key = _compact_identifier_key(atom)
    for surface_atom, display in surface_mentions:
        surface_key = _compact_identifier_key(surface_atom)
        normalized_surface_key = _compact_identifier_key(_normalize_source_record_display_value(surface_atom))
        if atom_key and atom_key in {surface_key, normalized_surface_key}:
            return display
    return _display_source_phrase(atom)


def _source_record_row_location_like_atoms(surface_mentions: list[tuple[str, str]]) -> list[str]:
    out: list[str] = []
    for atom, _display in surface_mentions:
        normalized = _normalize_source_record_display_value(atom)
        if re.fullmatch(r"\d+(?:st|nd|rd|th)_cir", normalized) and normalized not in out:
            out.append(normalized)
    return out


def _dedupe_preserve_order(values: list[str]) -> list[str]:
    out: list[str] = []
    for value in values:
        if value and value not in out:
            out.append(value)
    return out


def _source_record_citation_list_companion(
    runtime: CorePrologRuntime,
    *,
    utterance: str,
) -> dict[str, Any] | None:
    text = str(utterance or "").casefold()
    if not re.search(r"\b(?:cfr|citation|citations|section|sections|subpart|violations?)\b", text):
        return None
    if "cfr" not in text and "code of federal regulations" not in text:
        return None

    support_rows: list[dict[str, str]] = []
    seen: set[str] = set()
    text_atoms = _source_record_text_atoms(runtime)
    if re.search(r"\b(?:cgmp|violation|violations)\b", text):
        violation_atoms = [
            (source_row, text_atom)
            for source_row, text_atom in text_atoms
            if re.search(r"(?:^|_)v_\d+_", _normalize_text_filter_atom(text_atom))
        ]
        if violation_atoms:
            text_atoms = violation_atoms
    for source_row, text_atom in text_atoms:
        citations = _source_record_cfr_citations_from_atom(text_atom)
        for citation in citations:
            key = citation["CitationDisplay"]
            if key in seen:
                continue
            seen.add(key)
            support_rows.append(
                {
                    "SupportKind": "source_record_citation_list",
                    "CitationKind": "cfr",
                    "CitationValue": citation["CitationValue"],
                    "CitationDisplay": citation["CitationDisplay"],
                    "CitationOrder": str(len(support_rows) + 1),
                    "SourceRow": source_row,
                    "SourceTextAtom": text_atom,
                    "SupportClass": "deterministic-source-record-summary",
                }
            )
    if not support_rows:
        return None
    list_display = "; ".join(row["CitationDisplay"] for row in support_rows)
    support_rows.append(
        {
            "SupportKind": "source_record_citation_list_summary",
            "CitationKind": "cfr",
            "CitationValue": ",".join(row["CitationValue"] for row in support_rows if row.get("CitationValue")),
            "CitationDisplay": list_display,
            "CitationOrder": "summary",
            "CitationCount": str(len(support_rows)),
            "SourceRow": "source_record_citation_list",
            "SupportClass": "deterministic-source-record-summary",
        }
    )
    return {
        "query": "source_record_citation_list_support(CitationKind, CitationValue, CitationDisplay, CitationOrder, SourceRow).",
        "result": {
            "status": "success",
            "predicate": "source_record_citation_list_support",
            "prolog_query": "source_record_citation_list_support(CitationKind, CitationValue, CitationDisplay, CitationOrder, SourceRow).",
            "result_type": "table",
            "num_rows": len(support_rows),
            "variables": _row_variable_names(support_rows),
            "rows": support_rows[:80],
            "reasoning_basis": {
                "kind": "core-local",
                "note": (
                    "query-only citation-list support collected ordered code citations from admitted "
                    "source_record_text_atom rows; no durable citation fact was written"
                ),
                "utterance": utterance,
            },
        },
        "derived_from_queries": ["source_record_text_atom(SourceRow, TextAtom)."],
    }


def _source_record_cfr_citations_from_atom(text_atom: str) -> list[dict[str, str]]:
    text = _normalize_text_filter_atom(text_atom)
    out: list[dict[str, str]] = []
    seen: set[str] = set()
    pattern = re.compile(
        r"(?:^|_)(?P<title>\d+)_cfr_(?:(?P<section>\d+_\d+)(?:_(?P<letter>[a-z]))?|"
        r"(?:part_)?(?P<part>\d+)(?:_subpart_(?P<subpart>[a-z]))?)(?=$|_)"
    )
    for match in pattern.finditer(text):
        title = match.group("title")
        part = match.group("part")
        subpart = match.group("subpart")
        section = match.group("section")
        letter = match.group("letter")
        if part and subpart:
            value = f"{title}_cfr_part_{part}_subpart_{subpart}"
            display = f"{title} {_source_record_code_label_display('cfr')} Part {part}, Subpart {subpart.upper()}"
        elif section:
            section_display = section.replace("_", ".")
            suffix = f"({letter})" if letter else ""
            value = f"{title}_cfr_{section}{'_' + letter if letter else ''}"
            display = f"{title} {_source_record_code_label_display('cfr')} {section_display}{suffix}"
        elif part:
            value = f"{title}_cfr_part_{part}"
            display = f"{title} {_source_record_code_label_display('cfr')} Part {part}"
        else:
            continue
        if value in seen:
            continue
        seen.add(value)
        out.append({"CitationValue": value, "CitationDisplay": display})
    return out


def _source_record_exhibit_index_companion(
    runtime: CorePrologRuntime,
    *,
    utterance: str,
) -> dict[str, Any] | None:
    text = str(utterance or "").casefold()
    if not re.search(r"\b(?:exhibit|exhibits|filed|furnished|embedded)\b", text):
        return None
    if not re.search(r"\b(?:list|which|what|filed|furnished|contains?|with)\b", text):
        return None

    text_atoms = _source_record_text_atoms(runtime)
    text_by_row = {source_row: _normalize_text_filter_atom(atom) for source_row, atom in text_atoms}
    all_atoms = [atom for _source_row, atom in text_atoms]
    row_meta = _source_record_row_metadata(runtime)
    field_values_by_row = _source_record_all_field_values_by_row(runtime, include_items=False)
    exhibit_rows: list[dict[str, str]] = []
    seen: set[str] = set()

    for source_row, meta in row_meta.items():
        kind = str(meta.get("Kind", "") or "")
        if kind not in {"table_row", "list_row"}:
            continue
        label = _normalize_text_filter_atom(str(meta.get("Label", "") or ""))
        atom = text_by_row.get(source_row, label)
        fields = field_values_by_row.get(source_row, {})
        exhibit_atom = (
            _source_record_exhibit_atom(label)
            or _source_record_exhibit_atom(atom)
            or _source_record_exhibit_atom_from_fields(fields)
        )
        if not exhibit_atom or exhibit_atom in seen:
            continue
        description = _source_record_exhibit_description_from_fields(fields) or _source_record_exhibit_description_atom(
            exhibit_atom,
            atom,
        )
        filing_status = _source_record_exhibit_filing_status(exhibit_atom, all_atoms)
        if not filing_status and "embedded_within" in description:
            filing_status = "embedded"
        row = {
            "SupportKind": "source_record_exhibit_index_item",
            "SourceRow": source_row,
            "Line": str(meta.get("Line", "")),
            "Exhibit": exhibit_atom,
            "ExhibitDisplay": _display_source_record_exhibit(exhibit_atom),
            "DescriptionAtom": description,
            "DescriptionDisplay": _display_source_phrase(description),
            "FilingStatus": filing_status,
            "FilingStatusDisplay": _display_source_phrase(filing_status),
            "FullAnswerDisplay": _source_record_exhibit_full_answer(
                exhibit_atom=exhibit_atom,
                description_atom=description,
                filing_status=filing_status,
            ),
            "SourceTextAtom": atom,
            "SourceTextDisplay": _display_source_phrase(atom),
            "SupportClass": "deterministic-source-record-summary",
        }
        seen.add(exhibit_atom)
        exhibit_rows.append(row)

    if not exhibit_rows:
        return None
    exhibit_rows.sort(key=lambda row: _source_row_sort_key(row.get("SourceRow", "")))
    summary = {
        "SupportKind": "source_record_exhibit_index_summary",
        "ExhibitCount": str(len(exhibit_rows)),
        "ExhibitsDisplay": "; ".join(row["FullAnswerDisplay"] for row in exhibit_rows),
        "SourceRow": "source_record_exhibit_index",
        "SupportClass": "deterministic-source-record-summary",
    }
    support_rows = [*exhibit_rows, summary]
    return {
        "query": "source_record_exhibit_index_support(Exhibit, Description, FilingStatus, SourceRow).",
        "result": {
            "status": "success",
            "predicate": "source_record_exhibit_index_support",
            "prolog_query": "source_record_exhibit_index_support(Exhibit, Description, FilingStatus, SourceRow).",
            "result_type": "table",
            "num_rows": len(support_rows),
            "variables": _row_variable_names(support_rows),
            "rows": support_rows[:80],
            "reasoning_basis": {
                "kind": "core-local",
                "note": (
                    "query-only exhibit-index support collected admitted source-record exhibit "
                    "table/list rows and cross-checked filed/furnished wording from admitted source text; "
                    "no durable exhibit fact was written"
                ),
                "utterance": utterance,
            },
        },
        "derived_from_queries": [
            "source_record_row(SourceRow, Kind, Line, SectionAtom, Label).",
            "source_record_text_atom(SourceRow, TextAtom).",
        ],
    }


def _source_record_exhibit_atom(*values: str) -> str:
    for value in values:
        text = _normalize_text_filter_atom(value)
        match = re.search(r"(?:^|_)(exhibit_\d+(?:_\d+)?)(?:_|$)", text)
        if match:
            return match.group(1)
    return ""


def _source_record_exhibit_atom_from_fields(fields: dict[str, list[str]]) -> str:
    for field, values in sorted(fields.items()):
        field_tokens = set(_source_record_field_name_tokens(field))
        if "exhibit" not in field_tokens:
            continue
        for value in values:
            text = _normalize_text_filter_atom(value)
            match = re.fullmatch(r"v_(\d+)(?:_(\d+))?", text)
            if match:
                suffix = f"_{match.group(2)}" if match.group(2) else ""
                return f"exhibit_{match.group(1)}{suffix}"
            exhibit = _source_record_exhibit_atom(text)
            if exhibit:
                return exhibit
    return ""


def _source_record_exhibit_description_from_fields(fields: dict[str, list[str]]) -> str:
    for field, values in sorted(fields.items()):
        field_tokens = set(_source_record_field_name_tokens(field))
        if not ({"description", "title", "document"} & field_tokens):
            continue
        for value in values:
            normalized = _normalize_text_filter_atom(value)
            if normalized:
                return normalized
    return ""


def _source_record_exhibit_description_atom(exhibit_atom: str, text_atom: str) -> str:
    text = _normalize_text_filter_atom(text_atom)
    exhibit = _normalize_text_filter_atom(exhibit_atom)
    if exhibit and text.startswith(f"{exhibit}_"):
        return text[len(exhibit) + 1 :].strip("_")
    if exhibit:
        return re.sub(rf"(?:^|_){re.escape(exhibit)}(?:_|$)", "_", text, count=1).strip("_")
    return text


def _source_record_exhibit_filing_status(exhibit_atom: str, text_atoms: list[str]) -> str:
    exhibit = _normalize_text_filter_atom(exhibit_atom)
    status = ""
    for raw_atom in text_atoms:
        atom = _normalize_text_filter_atom(raw_atom)
        if exhibit not in atom:
            continue
        if re.search(rf"(?:^|_)furnished(?:_[a-z0-9]+){{0,4}}_as_{re.escape(exhibit)}(?:_|$)", atom):
            return "furnished"
        if re.search(rf"(?:^|_)filed(?:_[a-z0-9]+){{0,4}}_as_{re.escape(exhibit)}(?:_|$)", atom):
            status = "filed"
        elif "embedded_within" in atom and not status:
            status = "embedded"
    return status


def _display_source_record_exhibit(exhibit_atom: str) -> str:
    text = _normalize_text_filter_atom(exhibit_atom)
    match = re.fullmatch(r"exhibit_(\d+)(?:_(\d+))?", text)
    if not match:
        return _display_source_phrase(exhibit_atom)
    suffix = f".{match.group(2)}" if match.group(2) else ""
    return f"Exhibit {match.group(1)}{suffix}"


def _source_record_exhibit_full_answer(
    *,
    exhibit_atom: str,
    description_atom: str,
    filing_status: str,
) -> str:
    parts = [_display_source_record_exhibit(exhibit_atom)]
    if description_atom:
        parts.append(_display_source_phrase(description_atom))
    if filing_status:
        parts.append(f"({_display_source_phrase(filing_status)})")
    return ": ".join(parts[:2]) + (f" {parts[2]}" if len(parts) > 2 else "")


_BIOGRAPHY_DATE_PATTERN = (
    r"(?:january|february|march|april|may|june|july|august|september|october|november|december)"
    r"(?:_\d{1,2})?_\d{4}|\d{4}"
)


def _source_record_biography_history_companion(
    runtime: CorePrologRuntime,
    *,
    utterance: str,
    query_intents: list[dict[str, Any]] | None = None,
) -> dict[str, Any] | None:
    intent = _source_record_biography_history_intent(query_intents)
    if not intent:
        return None
    constraints = _query_intent_constraints(intent)
    asks_prior_employer = bool(constraints & {"prior_employer", "prior_employers", "employer_history"})
    asks_role_history = bool(constraints & {"role_history", "roles", "positions", "titles"})
    include_all_history = not (asks_prior_employer or asks_role_history) or bool(
        constraints & {"all", "biographical_paragraph"}
    )

    query_tokens = _query_intent_target_tokens(intent)
    support_rows: list[dict[str, str]] = []
    seen: set[tuple[str, str, str, str, str]] = set()

    for source_row, text_atom in _source_record_text_atoms(runtime):
        atom = _normalize_text_filter_atom(text_atom)
        if not _source_record_biography_history_signal(atom):
            continue
        if not _source_record_biography_row_matches_question(atom=atom, query_tokens=query_tokens):
            continue
        entries = _source_record_biography_history_entries(atom)
        selected_entries = [
            entry
            for entry in entries
            if (
                asks_prior_employer
                and entry.get("Employer")
                and entry.get("HistoryKind") in {"prior_employer", "prior_employer_role", "prior_employer_group"}
            )
            or (asks_role_history and entry.get("HistoryKind") in {"appointment_role", "current_role", "role_history"})
            or (include_all_history and (entry.get("Employer") or entry.get("Role")))
        ]
        for entry in selected_entries:
            key = (
                source_row,
                entry.get("HistoryKind", ""),
                entry.get("Employer", ""),
                entry.get("Role", ""),
                entry.get("StartDate", ""),
            )
            if key in seen:
                continue
            seen.add(key)
            full_answer = _source_record_biography_entry_display(entry)
            support_rows.append(
                {
                    "SupportKind": "source_record_biography_history_item",
                    "HistoryKind": entry.get("HistoryKind", ""),
                    "SourceRow": source_row,
                    "Employer": entry.get("Employer", ""),
                    "EmployerDisplay": _display_source_phrase(entry.get("Employer", "")),
                    "Role": entry.get("Role", ""),
                    "RoleDisplay": _display_source_phrase(entry.get("Role", "")),
                    "StartDate": entry.get("StartDate", ""),
                    "StartDateDisplay": _source_record_biography_date_display(entry.get("StartDate", "")),
                    "EndDate": entry.get("EndDate", ""),
                    "EndDateDisplay": _source_record_biography_date_display(entry.get("EndDate", "")),
                    "Qualifier": entry.get("Qualifier", ""),
                    "QualifierDisplay": _display_source_phrase(entry.get("Qualifier", "")),
                    "FullAnswerDisplay": full_answer,
                    "SourceTextAtom": text_atom,
                    "SourceTextDisplay": _display_source_phrase(text_atom),
                    "SupportClass": "deterministic-source-record-summary",
                }
            )

    if not support_rows:
        return None
    _source_record_biography_attach_transition_dates(support_rows)
    support_rows.sort(
        key=lambda row: (
            _source_row_sort_key(row.get("SourceRow", "")),
            _source_record_biography_date_sort_key(row.get("StartDate", "")),
            row.get("Role", ""),
            row.get("Employer", ""),
        )
    )
    summary = {
        "SupportKind": "source_record_biography_history_summary",
        "SourceRow": "source_record_biography_history",
        "HistoryItemCount": str(len(support_rows)),
        "RoleHistoryDisplay": "; ".join(
            row["FullAnswerDisplay"] for row in support_rows if row.get("RoleDisplay")
        ),
        "PriorEmployerDisplay": "; ".join(
            row["FullAnswerDisplay"] for row in support_rows if row.get("EmployerDisplay")
        ),
        "SupportClass": "deterministic-source-record-summary",
    }
    rows = [*support_rows, summary]
    return {
        "query": "source_record_employment_history_support(HistoryKind, Employer, Role, SourceRow).",
        "result": {
            "status": "success",
            "predicate": "source_record_employment_history_support",
            "prolog_query": "source_record_employment_history_support(HistoryKind, Employer, Role, SourceRow).",
            "result_type": "table",
            "num_rows": len(rows),
            "variables": _row_variable_names(rows),
            "rows": rows[:80],
            "reasoning_basis": {
                "kind": "core-local",
                "note": (
                    "query-only biography/employment-history support summarized role and prior-employer "
                    "phrases from admitted source_record_text_atom rows after structured query-intent activation; "
                    "no durable employment fact was written"
                ),
                "query_intent": intent,
            },
        },
        "derived_from_queries": ["source_record_text_atom(SourceRow, TextAtom)."],
    }


def _source_record_biography_history_intent(query_intents: list[dict[str, Any]] | None) -> dict[str, Any] | None:
    intent = _first_query_intent(query_intents, "biography_history", "employment_history")
    if intent:
        return intent
    for item in query_intents or []:
        if not isinstance(item, dict):
            continue
        if str(item.get("intent_type", "")).strip() != "date":
            continue
        if not _query_intent_has_constraint(
            item,
            "start_date",
            "start_dates",
            "since_date",
            "effective_start",
        ):
            continue
        if _query_intent_target_tokens(item):
            return item
    return None


def _source_record_biography_history_signal(atom: str) -> bool:
    text = _normalize_text_filter_atom(atom)
    return bool(
        re.search(
            r"(?:^|_)(?:has_served_as|served_as|previously|prior_to_joining|employed_by|before_that|"
            r"earlier_in_his_career|earlier_in_her_career|held_several|held_senior|appointed)(?:_|$)",
            text,
        )
    )


def _source_record_biography_row_matches_question(*, atom: str, query_tokens: set[str]) -> bool:
    if not query_tokens:
        return True
    row_tokens = set(_query_atom_tokens(atom))
    focus_tokens = {
        token
        for token in query_tokens
        if len(token) >= 4
        and token
        not in {
            "biographical",
            "chronological",
            "date",
            "dates",
            "document",
            "employer",
            "employers",
            "every",
            "held",
            "list",
            "mentioned",
            "named",
            "order",
            "paragraph",
            "prior",
            "role",
            "roles",
            "start",
            "with",
        }
    }
    return bool(focus_tokens & row_tokens) or bool({"prior", "previously", "served", "employed"} & row_tokens)


def _source_record_biography_history_entries(atom: str) -> list[dict[str, str]]:
    text = _normalize_text_filter_atom(atom)
    entries: list[dict[str, str]] = []
    seen: set[tuple[str, str, str, str, str]] = set()

    def add(
        *,
        history_kind: str,
        employer: str = "",
        role: str = "",
        start_date: str = "",
        end_date: str = "",
        qualifier: str = "",
    ) -> None:
        employer_atom = _source_record_biography_clean_phrase(employer, kind="employer")
        role_atom = _source_record_biography_clean_phrase(role, kind="role")
        qualifier_atom = _source_record_biography_clean_phrase(qualifier, kind="qualifier")
        if not employer_atom and not role_atom:
            return
        if role_atom and re.search(r"(?:^|_)(?:since|previously|prior_to_joining)(?:_|$)", role_atom):
            return
        if role_atom:
            for existing in entries:
                if (
                    existing.get("HistoryKind") == history_kind
                    and existing.get("Employer") == employer_atom
                    and existing.get("StartDate") == start_date
                    and existing.get("EndDate") == end_date
                ):
                    existing_role = str(existing.get("Role", ""))
                    if role_atom != existing_role and role_atom in existing_role:
                        return
        key = (history_kind, employer_atom, role_atom, start_date, end_date)
        if key in seen:
            return
        seen.add(key)
        entries.append(
            {
                "HistoryKind": history_kind,
                "Employer": employer_atom,
                "Role": role_atom,
                "StartDate": start_date,
                "EndDate": end_date,
                "Qualifier": qualifier_atom,
            }
        )

    for match in re.finditer(
        rf"(?:^|_)(?:has_)?served_as_(?P<role>[a-z0-9_]{{3,140}}?)_since_(?P<start>{_BIOGRAPHY_DATE_PATTERN})(?:_|$)",
        text,
    ):
        add(history_kind="current_role", role=match.group("role"), start_date=match.group("start"))

    prior_boundary_candidates = [
        index
        for marker in ("_prior_to_joining_", "_employed_by_", "_before_that_")
        for index in [text.find(marker)]
        if index >= 0
    ]
    prior_boundary = min(prior_boundary_candidates) if prior_boundary_candidates else -1

    for match in re.finditer(
        rf"(?=(?:^|_)(?:served_as|and)_(?P<role>[a-z0-9_]{{3,180}}?)_from_(?P<start>{_BIOGRAPHY_DATE_PATTERN})"
        rf"_to_(?P<end>{_BIOGRAPHY_DATE_PATTERN})(?:_|$))",
        text,
    ):
        if prior_boundary >= 0 and match.start() > prior_boundary:
            continue
        if not _source_record_biography_phrase_starts_like_role(match.group("role")):
            continue
        add(
            history_kind="role_history",
            role=match.group("role"),
            start_date=match.group("start"),
            end_date=match.group("end"),
        )

    for match in re.finditer(
        rf"(?:^|_)employed_by_(?P<employer>[a-z0-9_]{{2,100}}?)_as_(?P<role>[a-z0-9_]{{3,140}}?)_from_"
        rf"(?P<start>{_BIOGRAPHY_DATE_PATTERN})_to_(?P<end>{_BIOGRAPHY_DATE_PATTERN})(?:_|$)",
        text,
    ):
        add(
            history_kind="prior_employer_role",
            employer=match.group("employer"),
            role=match.group("role"),
            start_date=match.group("start"),
            end_date=match.group("end"),
        )

    for match in re.finditer(
        rf"(?:^|_)served_as_(?P<role>[a-z0-9_]{{3,140}}?)_at_(?P<employer>[a-z0-9_]{{2,100}}?)_from_"
        rf"(?P<start>{_BIOGRAPHY_DATE_PATTERN})_to_(?P<end>{_BIOGRAPHY_DATE_PATTERN})(?:_|$)",
        text,
    ):
        add(
            history_kind="prior_employer_role",
            employer=match.group("employer"),
            role=match.group("role"),
            start_date=match.group("start"),
            end_date=match.group("end"),
        )

    for match in re.finditer(
        rf"(?:^|_)and_(?P<employer>[a-z][a-z0-9_]{{2,80}}?)_from_(?P<start>{_BIOGRAPHY_DATE_PATTERN})"
        rf"_to_(?P<end>{_BIOGRAPHY_DATE_PATTERN})(?:_|$)",
        text,
    ):
        candidate = match.group("employer")
        if not _source_record_biography_phrase_looks_like_role(candidate):
            add(
                history_kind="prior_employer",
                employer=candidate,
                start_date=match.group("start"),
                end_date=match.group("end"),
            )

    for match in re.finditer(
        r"(?:^|_)spent_(?:more_than_)?(?:[a-z]+|\d+)_years_at_(?P<employer>[a-z0-9_]{2,140}?)(?:_including_|_helping_|_where_|$)",
        text,
    ):
        add(history_kind="prior_employer", employer=match.group("employer"), qualifier="multi_year_tenure")

    for match in re.finditer(
        rf"(?:^|_)(?:held_several|held_senior|previously_held_senior).*?_(?:roles|positions)_at_(?P<employers>[a-z0-9_]+?)"
        rf"(?:_from_(?P<start>{_BIOGRAPHY_DATE_PATTERN})_to_(?P<end>{_BIOGRAPHY_DATE_PATTERN})|_where_|$)",
        text,
    ):
        for employer in _source_record_biography_split_employers(match.group("employers")):
            add(
                history_kind="prior_employer_group",
                employer=employer,
                role="management_positions" if "management_positions" in match.group(0) else "senior_leadership_roles",
                start_date=match.group("start") or "",
                end_date=match.group("end") or "",
            )

    for match in re.finditer(
        rf"(?:^|_)appointed_(?:[a-z0-9_]{{0,80}}?)_as_(?:the_[a-z0-9_]+_s_)?(?P<role>[a-z0-9_]{{3,80}}?)"
        rf"_effective_(?P<start>{_BIOGRAPHY_DATE_PATTERN})(?:_|$)",
        text,
    ):
        add(history_kind="appointment_role", role=match.group("role"), start_date=match.group("start"))

    return entries


def _source_record_biography_attach_transition_dates(rows: list[dict[str, str]]) -> None:
    appointment_rows = [
        row
        for row in rows
        if row.get("HistoryKind") == "appointment_role" and row.get("StartDate") and row.get("Role")
    ]
    if not appointment_rows:
        return
    appointment_rows.sort(key=lambda row: _source_record_biography_date_sort_key(row.get("StartDate", "")))
    for row in rows:
        if row.get("HistoryKind") != "current_role" or row.get("EndDate") or not row.get("StartDate"):
            continue
        start_key = _source_record_biography_date_sort_key(row.get("StartDate", ""))
        next_rows = [
            appointment
            for appointment in appointment_rows
            if _source_record_biography_date_sort_key(appointment.get("StartDate", "")) >= start_key
        ]
        if not next_rows:
            continue
        appointment = next_rows[0]
        transition_date = appointment.get("StartDate", "")
        transition_role = appointment.get("Role", "")
        row["TransitionDate"] = transition_date
        row["TransitionDateDisplay"] = _source_record_biography_date_display(transition_date)
        row["TransitionRole"] = transition_role
        row["TransitionRoleDisplay"] = _display_source_phrase(transition_role)
        if row["TransitionDateDisplay"]:
            row["FullAnswerDisplay"] = (
                f"{row.get('FullAnswerDisplay', '')}; next role "
                f"{row['TransitionRoleDisplay']} effective {row['TransitionDateDisplay']}"
            ).strip("; ")


def _source_record_biography_phrase_looks_like_role(value: str) -> bool:
    tokens = set(_query_atom_tokens(value))
    return bool(
        tokens
        & {
            "chief",
            "counsel",
            "director",
            "executive",
            "finance",
            "financial",
            "manager",
            "management",
            "officer",
            "operations",
            "president",
            "strategy",
            "vice",
        }
    )


def _source_record_biography_phrase_starts_like_role(value: str) -> bool:
    tokens = _query_atom_tokens(value)
    return bool(tokens) and tokens[0] in {
        "chief",
        "director",
        "executive",
        "interim",
        "manager",
        "management",
        "president",
        "senior",
        "vice",
    }


def _source_record_biography_split_employers(value: str) -> list[str]:
    text = _source_record_biography_clean_phrase(value, kind="employer_list")
    if not text:
        return []
    parts = [part for part in re.split(r"_and_", text) if part]
    out: list[str] = []
    for part in parts:
        part = part.strip("_")
        if not part:
            continue
        out.extend(_source_record_biography_split_employer_part(part))
    return _ordered_atom_unique(
        [
            cleaned
            for item in out
            for cleaned in [_source_record_biography_clean_phrase(item, kind="employer")]
            if cleaned
        ]
    )


def _source_record_biography_split_employer_part(value: str) -> list[str]:
    part = _normalize_text_filter_atom(value).strip("_")
    if not part:
        return []
    if "_acquired_by_" in part:
        primary, acquired_tail = part.split("_acquired_by_", 1)
        out = [primary]
        out.extend(_source_record_biography_trailing_employers_after_acquirer(acquired_tail))
        return [item for item in out if item]
    split_match = re.fullmatch(r"(?P<first>[a-z0-9_]+?_international)_(?P<second>[a-z0-9_]+)", part)
    if split_match:
        return [split_match.group("first"), split_match.group("second")]
    return [part]


def _source_record_biography_trailing_employers_after_acquirer(value: str) -> list[str]:
    tokens = [token for token in _query_atom_tokens(value) if token]
    if len(tokens) < 4:
        return []
    marker_indexes = [
        index
        for index, token in enumerate(tokens)
        if token
        in {
            "clinical",
            "corporation",
            "group",
            "health",
            "healthcare",
            "holdings",
            "inc",
            "international",
            "laboratories",
            "labs",
            "llc",
            "medical",
            "networks",
            "pharmaceuticals",
            "scientific",
            "services",
            "systems",
            "technologies",
            "therapeutics",
        }
    ]
    if not marker_indexes:
        return []
    terminal_marker = marker_indexes[-1]
    if terminal_marker != len(tokens) - 1:
        return []
    start = max(1, len(tokens) - 4)
    while start < len(tokens) - 1 and tokens[start] in {"the", "a", "an", "and", "of"}:
        start += 1
    candidate = "_".join(tokens[start:])
    if candidate and len(candidate.split("_")) >= 2:
        return [candidate]
    return []


def _source_record_biography_clean_phrase(value: str, *, kind: str) -> str:
    text = _normalize_text_filter_atom(value)
    if not text:
        return ""
    text = re.sub(
        r"^(?:mr|ms|mrs|dr|he|she|they|previously|before_that|prior_to_joining|the_company_s|the_company|company_s)_+",
        "",
        text,
    )
    text = re.sub(r"_+(?:where|helping|including|from|to|and)$", "", text)
    text = re.sub(r"_+", "_", text).strip("_")
    if kind == "employer":
        text = re.sub(r"_acquired_by_[a-z0-9_]+$", "", text)
    if kind == "role":
        text = re.sub(r"^(?:as|served_as|has_served_as|and)_+", "", text)
    return text[:180]


def _source_record_biography_entry_display(entry: dict[str, str]) -> str:
    parts: list[str] = []
    employer = _display_source_phrase(entry.get("Employer", ""))
    role = _display_source_phrase(entry.get("Role", ""))
    start = _source_record_biography_date_display(entry.get("StartDate", ""))
    end = _source_record_biography_date_display(entry.get("EndDate", ""))
    qualifier = _display_source_phrase(entry.get("Qualifier", ""))
    if employer:
        parts.append(employer)
    if role:
        parts.append(role)
    if start and end:
        parts.append(f"{start} to {end}")
    elif start:
        parts.append(f"since/effective {start}")
    if qualifier:
        parts.append(qualifier)
    return " - ".join(part for part in parts if part)


def _source_record_biography_date_display(value: str) -> str:
    text = _normalize_text_filter_atom(value)
    if not text:
        return ""
    month_pattern = "|".join(re.escape(month) for month in _SOURCE_MONTHS)
    match = re.fullmatch(rf"(?P<month>{month_pattern})_(?P<day>\d{{1,2}})_(?P<year>\d{{4}})", text)
    if match:
        return f"{match.group('month').title()} {int(match.group('day'))}, {match.group('year')}"
    match = re.fullmatch(rf"(?P<month>{month_pattern})_(?P<year>\d{{4}})", text)
    if match:
        return f"{match.group('month').title()} {match.group('year')}"
    if re.fullmatch(r"\d{4}", text):
        return text
    return _display_source_phrase(text)


def _source_record_biography_date_sort_key(value: str) -> tuple[int, int, int]:
    text = _normalize_text_filter_atom(value)
    if re.fullmatch(r"\d{4}", text):
        return (int(text), 0, 0)
    month_pattern = "|".join(re.escape(month) for month in _SOURCE_MONTHS)
    match = re.fullmatch(rf"(?P<month>{month_pattern})_(?P<day>\d{{1,2}})_(?P<year>\d{{4}})", text)
    if match:
        return (int(match.group("year")), int(_SOURCE_MONTHS.get(match.group("month"), "0")), int(match.group("day")))
    match = re.fullmatch(rf"(?P<month>{month_pattern})_(?P<year>\d{{4}})", text)
    if match:
        return (int(match.group("year")), int(_SOURCE_MONTHS.get(match.group("month"), "0")), 0)
    return (9999, 99, 99)


