def _compiled_value_set_exclusion_companion(
    *,
    query_intents: list[dict[str, Any]] | None,
    query_results: list[dict[str, Any]] | None,
) -> dict[str, Any] | None:
    target_tokens = _compiled_value_set_target_tokens(query_intents)
    if not target_tokens:
        return None
    rows: list[dict[str, str]] = []
    seen: set[tuple[str, str]] = set()
    for query_result in query_results or []:
        result = query_result.get("result") if isinstance(query_result, dict) else None
        if not isinstance(result, dict) or result.get("status") != "success":
            continue
        predicate = str(result.get("predicate", "")).strip()
        if not predicate or predicate.startswith("source_record_"):
            continue
        predicate_tokens = set(_query_atom_tokens(predicate))
        if not predicate_tokens or not (predicate_tokens & target_tokens):
            continue
        values = _compiled_value_set_result_values(result)
        if not values:
            continue
        value_tokens = set().union(*(set(_query_atom_tokens(value)) for value in values))
        requested_tokens = sorted(
            token
            for token in target_tokens - predicate_tokens - _VALUE_SET_EXCLUSION_GENERIC_TARGET_TOKENS
            if len(token) >= 3
        )
        if not requested_tokens:
            continue
        matched_tokens = sorted(set(requested_tokens) & value_tokens)
        if matched_tokens:
            continue
        key = (predicate, ",".join(requested_tokens))
        if key in seen:
            continue
        seen.add(key)
        returned_values_display = "; ".join(_display_source_phrase(value) for value in values[:24])
        requested_display = ", ".join(requested_tokens)
        rows.append(
            {
                "SupportKind": "compiled_value_set_exclusion",
                "SupportClass": "deterministic-compiled-value-set",
                "Predicate": predicate,
                "PredicateDisplay": _display_source_phrase(predicate),
                "RequestedTokens": requested_display,
                "ReturnedValues": ", ".join(values[:24]),
                "ReturnedValuesDisplay": returned_values_display,
                "FullAnswerDisplay": (
                    f"{_display_source_phrase(predicate)} returned values: {returned_values_display}. "
                    f"No returned value matched requested target tokens: {requested_display}."
                ),
            }
        )
    if not rows:
        return None
    return {
        "query": "compiled_value_set_exclusion_support(Predicate, RequestedTokens, ReturnedValues).",
        "result": {
            "status": "success",
            "predicate": "compiled_value_set_exclusion_support",
            "prolog_query": (
                "compiled_value_set_exclusion_support"
                "(Predicate, RequestedTokens, ReturnedValues)."
            ),
            "result_type": "table",
            "num_rows": len(rows),
            "variables": _row_variable_names(rows),
            "rows": rows[:24],
            "reasoning_basis": {
                "kind": "core-local",
                "note": (
                    "query-only value-set exclusion support compared structured query-intent "
                    "target tokens with already-returned compiled predicate values; it does "
                    "not inspect raw utterance text, parse source prose, or write durable facts"
                ),
                "query_intents": query_intents or [],
            },
        },
        "derived_from_queries": ["already-returned compiled predicate query results"],
    }


def _compiled_value_set_target_tokens(
    query_intents: list[dict[str, Any]] | None,
) -> set[str]:
    tokens: set[str] = set()
    for intent in query_intents or []:
        if not isinstance(intent, dict):
            continue
        intent_type = str(intent.get("intent_type", "")).strip()
        if intent_type not in {"list", "premise_check", "verification", "verify", "scope_question"}:
            continue
        tokens.update(_query_intent_target_tokens(intent))
    return {token for token in tokens if len(token) >= 3}


def _compiled_value_set_result_values(result: dict[str, Any]) -> list[str]:
    rows = result.get("rows") or []
    variables = [
        str(variable).strip()
        for variable in result.get("variables", [])
        if str(variable).strip() and not str(variable).strip().startswith("BoundArg")
    ]
    if len(variables) != 1:
        return []
    variable = variables[0]
    values: list[str] = []
    seen: set[str] = set()
    for row in rows:
        if not isinstance(row, dict):
            continue
        value = str(row.get(variable, "")).strip()
        if not value or value in seen:
            continue
        seen.add(value)
        values.append(value)
    return values


_RETURNED_ACTION_SECTION_TRIGGER_TOKENS = {
    "action",
    "actions",
    "basis",
    "legal",
    "order",
    "orders",
    "regulatory",
    "requirement",
    "requirements",
    "sanction",
    "sanctions",
}

def _source_record_returned_action_section_companion(
    runtime: CorePrologRuntime,
    *,
    query_intents: list[dict[str, Any]] | None,
    query_results: list[dict[str, Any]] | None,
) -> dict[str, Any] | None:
    if not _source_record_returned_action_section_active(query_intents):
        return None
    trigger = _source_record_returned_action_section_trigger(query_results)
    if not trigger:
        return None
    row_meta = _source_record_row_metadata(runtime)
    display_by_row = _source_record_text_display_by_row(runtime)
    section_display_by_row = _source_record_section_display_by_row(runtime)
    if not row_meta or not display_by_row:
        return None
    basis_tokens = set(trigger.get("basis_tokens") or [])
    rows: list[dict[str, str]] = []
    seen: set[str] = set()
    for source_row, meta in row_meta.items():
        kind = str(meta.get("Kind", "")).strip()
        if kind not in {"list_row", "anchored_line"}:
            continue
        section_atom = str(meta.get("SectionAtom", "")).strip()
        section_tokens = set(_query_atom_tokens(section_atom))
        matched_tokens = sorted(section_tokens & basis_tokens)
        if not matched_tokens:
            continue
        display = display_by_row.get(source_row, "")
        if not display or source_row in seen:
            continue
        seen.add(source_row)
        rows.append(
            {
                "SupportKind": "source_record_returned_action_section",
                "SupportClass": "deterministic-source-record-summary",
                "SourceRow": source_row,
                "RowKind": kind,
                "SectionAtom": section_atom,
                "SectionDisplay": section_display_by_row.get(source_row, ""),
                "MatchedReturnedTokens": ", ".join(matched_tokens),
                "SourceTextDisplay": display,
                "FullAnswerDisplay": _source_record_returned_action_section_full_display(
                    section_display_by_row.get(source_row, ""),
                    display,
                ),
            }
        )
    if not rows:
        return None
    rows.sort(
        key=lambda row: (
            _source_row_sort_key(row.get("SourceRow", "")),
            row.get("SectionAtom", ""),
        )
    )
    return {
        "query": "source_record_returned_action_section_support(SectionAtom, SourceRow, SourceTextDisplay).",
        "result": {
            "status": "success",
            "predicate": "source_record_returned_action_section_support",
            "prolog_query": (
                "source_record_returned_action_section_support"
                "(SectionAtom, SourceRow, SourceTextDisplay)."
            ),
            "result_type": "table",
            "num_rows": len(rows),
            "variables": _row_variable_names(rows),
            "rows": rows[:48],
            "reasoning_basis": {
                "kind": "core-local",
                "note": (
                    "query-only returned-action section support followed already-returned "
                    "regulatory/action/legal-basis predicate values into source_record sections "
                    "with matching normalized section tokens, then exposed admitted list rows; "
                    "no raw utterance parsing, source-prose parsing, or durable fact write was used"
                ),
                "query_intents": query_intents or [],
                "trigger": trigger,
            },
        },
        "derived_from_queries": [
            "already-returned compiled action/legal-basis predicate query results",
            "source_record_row(SourceRow, Kind, Line, SectionAtom, Label).",
            "source_record_text_display(SourceRow, Text).",
            "source_record_section_display(SourceRow, Text).",
        ],
    }


def _source_record_returned_action_section_active(
    query_intents: list[dict[str, Any]] | None,
) -> bool:
    for intent in query_intents or []:
        if not isinstance(intent, dict):
            continue
        if str(intent.get("intent_type", "")).strip() in {"list", "comparison", "scope_question"}:
            return True
    return False


def _source_record_returned_action_section_trigger(
    query_results: list[dict[str, Any]] | None,
) -> dict[str, Any] | None:
    basis_tokens: set[str] = set()
    predicates: list[str] = []
    for query_result in query_results or []:
        result = query_result.get("result") if isinstance(query_result, dict) else None
        if not isinstance(result, dict) or result.get("status") != "success":
            continue
        predicate = str(result.get("predicate", "")).strip()
        if not predicate or predicate.startswith("source_record_"):
            continue
        predicate_tokens = set(_query_atom_tokens(predicate))
        if not (predicate_tokens & _RETURNED_ACTION_SECTION_TRIGGER_TOKENS):
            continue
        row_tokens: set[str] = set()
        for result_row in result.get("rows") or []:
            if not isinstance(result_row, dict):
                continue
            for value in _iter_scalar_values(result_row):
                row_tokens.update(_query_atom_tokens(str(value)))
        filtered_tokens = {token for token in row_tokens if token.isdigit() and len(token) >= 2}
        if not filtered_tokens:
            continue
        predicates.append(predicate)
        basis_tokens.update(filtered_tokens)
    if not basis_tokens:
        return None
    return {
        "predicates": sorted(set(predicates))[:12],
        "basis_tokens": sorted(basis_tokens)[:80],
    }


def _source_record_section_display_by_row(runtime: CorePrologRuntime) -> dict[str, str]:
    out: dict[str, str] = {}
    for row in _runtime_rows(runtime, "source_record_section_display(SourceRow, Text)."):
        source_row = str(row.get("SourceRow", "")).strip()
        display = str(row.get("Text", "")).strip()
        if source_row and display and source_row not in out:
            out[source_row] = display
    return out


def _source_record_returned_action_section_full_display(section_display: str, display: str) -> str:
    section_display = str(section_display or "").strip()
    display = str(display or "").strip()
    if section_display and display:
        return f"{section_display} - {display}"
    return display or section_display


def _source_record_obligation_bundle_fact_rows(
    facts: list[dict[str, Any]],
) -> list[dict[str, str]]:
    rows: list[dict[str, str]] = []
    seen: set[tuple[str, tuple[str, ...]]] = set()
    for fact in facts:
        predicate = str(fact.get("predicate", "")).strip()
        args = [str(item).strip() for item in fact.get("args", [])]
        if not predicate or not args:
            continue
        if predicate.startswith("source_record_") or predicate.startswith("world_"):
            continue
        predicate_tokens = set(_query_atom_tokens(predicate))
        if not predicate_tokens & _OBLIGATION_BUNDLE_FACT_TOKENS:
            continue
        if len(args) > 6:
            continue
        key = (predicate, tuple(args))
        if key in seen:
            continue
        seen.add(key)
        subject = args[0] if args else ""
        argument_display = "; ".join(_display_source_phrase(arg) for arg in args)
        predicate_display = _display_source_phrase(predicate)
        rows.append(
            {
                "SupportKind": "compiled_obligation_fact",
                "SupportClass": "deterministic-source-record-summary",
                "SourceRow": "",
                "Predicate": predicate,
                "PredicateDisplay": predicate_display,
                "SubjectAtom": subject,
                "SubjectDisplay": _display_source_phrase(subject),
                "ArgumentsAtom": ", ".join(args),
                "ArgumentsDisplay": argument_display,
                "FullAnswerDisplay": f"{predicate_display}: {argument_display}",
                "SupportScore": str(20 + len(predicate_tokens & _OBLIGATION_BUNDLE_FACT_TOKENS)),
            }
        )
    rows.sort(
        key=lambda row: (
            row.get("SubjectAtom", ""),
            row.get("Predicate", ""),
            row.get("ArgumentsAtom", ""),
        )
    )
    return rows


def _source_record_obligation_bundle_display_rows(
    runtime: CorePrologRuntime,
) -> list[dict[str, str]]:
    rows: list[dict[str, str]] = []
    seen: set[tuple[str, str, str]] = set()
    for source_row, surface_kind, cell_index, display in _source_record_display_surfaces(runtime):
        if surface_kind not in {"source_record_text_display", "source_record_cell_display"}:
            continue
        score, quantity_kind = _source_record_obligation_display_score(display)
        if score <= 0:
            continue
        key = (source_row, cell_index, display)
        if key in seen:
            continue
        seen.add(key)
        rows.append(
            {
                "SupportKind": "source_record_obligation_quantity_display",
                "SupportClass": "deterministic-source-record-summary",
                "SourceRow": source_row,
                "SourceSurfaceKind": surface_kind,
                "SourceCellIndex": cell_index,
                "Predicate": "source_record_display",
                "QuantityKind": quantity_kind,
                "SourceTextDisplay": display,
                "FullAnswerDisplay": display,
                "SupportScore": str(score),
            }
        )
    rows.sort(
        key=lambda row: (
            -int(row.get("SupportScore", "0") or "0"),
            _source_row_sort_key(row.get("SourceRow", "")),
            _safe_int(row.get("SourceCellIndex")) or 9999,
        )
    )
    return rows


def _source_record_obligation_display_score(display: str) -> tuple[int, str]:
    text = unicodedata.normalize("NFKC", str(display or ""))
    if not re.search(r"\d", text):
        return 0, ""
    score = 0
    kinds: list[str] = []
    if re.search(r"[%€$£¥]", text):
        score += 32
        kinds.append("currency_or_percent")
    if re.search(r"(?<!\d)\d{1,3}(?:[.,]\d{3})+(?:[.,]\d+)?(?!\d)", text):
        score += 24
        kinds.append("grouped_numeric")
    if re.search(r"(?<!\d)\d+(?:[.,]\d+)?\s*[^\W\d_]{2,}", text, flags=re.UNICODE):
        score += 16
        kinds.append("unit_quantity")
    if len(text) <= 320:
        score += 4
    if not kinds:
        return 0, ""
    return score, "+".join(kinds)


def _source_record_amount_inventory_companion(
    runtime: CorePrologRuntime,
    *,
    utterance: str,
    query_intents: list[dict[str, Any]] | None = None,
) -> dict[str, Any] | None:
    intent = _first_query_intent(query_intents, "amount_inventory")
    if not intent:
        return None

    support_rows: list[dict[str, str]] = []
    seen: set[tuple[str, str, str, str]] = set()
    for source_row, text_atom in _source_record_text_atoms(runtime):
        atom = _normalize_text_filter_atom(text_atom)
        if not _source_record_amount_context_signal(atom):
            continue
        for amount in _source_record_amount_mentions(atom):
            key = (source_row, amount["AmountKind"], amount["AmountValue"], amount["ReferentAtom"])
            if key in seen:
                continue
            seen.add(key)
            support_rows.append(
                {
                    "SupportKind": "source_record_amount_inventory_item",
                    "AmountKind": amount["AmountKind"],
                    "AmountValue": amount["AmountValue"],
                    "AmountDisplay": amount["AmountDisplay"],
                    "ReferentAtom": amount["ReferentAtom"],
                    "ReferentDisplay": _display_source_phrase(amount["ReferentAtom"]),
                    "SourceRow": source_row,
                    "SourceTextAtom": text_atom,
                    "SourceTextDisplay": _display_source_phrase(text_atom),
                    "FullAnswerDisplay": (
                        f"{amount['AmountDisplay']} - {_display_source_phrase(amount['ReferentAtom'])}"
                    ),
                    "SupportClass": "deterministic-source-record-summary",
                }
            )
    if not support_rows:
        return None
    support_rows.sort(
        key=lambda row: (
            _source_row_sort_key(row.get("SourceRow", "")),
            0 if row.get("AmountKind") == "money" else 1,
            row.get("AmountValue", ""),
            row.get("ReferentAtom", ""),
        )
    )
    summary = {
        "SupportKind": "source_record_amount_inventory_summary",
        "SourceRow": "source_record_amount_inventory",
        "AmountCount": str(len(support_rows)),
        "AmountsDisplay": "; ".join(row["FullAnswerDisplay"] for row in support_rows),
        "SupportClass": "deterministic-source-record-summary",
    }
    rows = [*support_rows, summary]
    return {
        "query": "source_record_amount_inventory_support(AmountKind, AmountValue, Referent, SourceRow).",
        "result": {
            "status": "success",
            "predicate": "source_record_amount_inventory_support",
            "prolog_query": "source_record_amount_inventory_support(AmountKind, AmountValue, Referent, SourceRow).",
            "result_type": "table",
            "num_rows": len(rows),
            "variables": _row_variable_names(rows),
            "rows": rows[:100],
            "reasoning_basis": {
                "kind": "core-local",
                "note": (
                    "query-only amount-inventory support paired amount-like numeric tokens with nearby "
                    "admitted source-record context after structured query-intent activation; "
                    "no durable amount fact was written"
                ),
                "query_intent": intent,
            },
        },
        "derived_from_queries": ["source_record_text_atom(SourceRow, TextAtom)."],
    }


def _source_record_table_delta_check_companion(
    runtime: CorePrologRuntime,
    *,
    utterance: str,
    query_intents: list[dict[str, Any]] | None = None,
) -> dict[str, Any] | None:
    del utterance
    intent = _source_record_table_delta_check_intent(query_intents)
    if not intent:
        return None

    rows: list[dict[str, str]] = []
    seen: set[tuple[str, str, str]] = set()
    for source_row, surface_kind, cell_index, display in _source_record_display_surfaces(runtime):
        candidate = _source_record_table_delta_check_row(
            source_row=source_row,
            surface_kind=surface_kind,
            cell_index=cell_index,
            display=display,
        )
        if candidate is None:
            continue
        key = (
            candidate["SourceRow"],
            candidate["SourceSurfaceKind"],
            candidate["SourceTextDisplay"],
        )
        if key in seen:
            continue
        seen.add(key)
        rows.append(candidate)
    if not rows:
        return None
    rows.sort(
        key=lambda row: (
            0 if row.get("DeltaAgreement") == "false" else 1,
            _source_row_sort_key(row.get("SourceRow", "")),
            row.get("SourceSurfaceKind", ""),
        )
    )
    summary = {
        "SupportKind": "source_record_table_delta_check_summary",
        "SourceRow": "source_record_table_delta_check",
        "DeltaRowCount": str(len(rows)),
        "DiscrepancyCount": str(sum(1 for row in rows if row.get("DeltaAgreement") == "false")),
        "DeltaChecksDisplay": "; ".join(row.get("FullAnswerDisplay", "") for row in rows[:8]),
        "SupportClass": "deterministic-source-record-summary",
    }
    return {
        "query": "source_record_table_delta_check_support(SourceRow, PriorValue, CurrentValue, DerivedDelta).",
        "result": {
            "status": "success",
            "predicate": "source_record_table_delta_check_support",
            "prolog_query": (
                "source_record_table_delta_check_support"
                "(SourceRow, PriorValue, CurrentValue, DerivedDelta)."
            ),
            "result_type": "table",
            "num_rows": len(rows) + 1,
            "variables": _row_variable_names([summary, *rows]),
            "rows": [summary, *rows[:80]],
            "reasoning_basis": {
                "kind": "core-local",
                "note": (
                    "query-only table delta support compared three numeric cells in admitted "
                    "source-record display rows after structured change-amount intent activation; "
                    "derived deltas are labeled calculations and no durable arithmetic fact was written"
                ),
                "query_intent": intent,
            },
        },
        "derived_from_queries": [
            "source_record_text_display(SourceRow, Text).",
            "source_record_cell_display(SourceRow, CellIndex, Text).",
        ],
    }


def _source_record_table_delta_check_intent(
    query_intents: list[dict[str, Any]] | None,
) -> dict[str, Any] | None:
    for intent in query_intents or []:
        if not isinstance(intent, dict):
            continue
        intent_type = str(intent.get("intent_type", "")).strip()
        if intent_type not in {"amount_inventory", "ratio_calculation"}:
            continue
        constraints = {
            token
            for value in intent.get("answer_constraints", []) or []
            for token in _query_atom_tokens(str(value))
        }
        if constraints & {
            "change",
            "compare",
            "comparison",
            "delta",
            "difference",
            "increase",
            "decrease",
            "variance",
            "yoy",
        }:
            return intent
    return None


def _source_record_table_delta_check_row(
    *,
    source_row: str,
    surface_kind: str,
    cell_index: str,
    display: str,
) -> dict[str, str] | None:
    text = unicodedata.normalize("NFKC", str(display or "")).strip()
    if "|" not in text:
        return None
    cells = [_clean_source_record_table_delta_cell(cell) for cell in text.strip().strip("|").split("|")]
    numeric_cells: list[tuple[int, str, float]] = []
    for index, cell in enumerate(cells):
        parsed = _source_record_table_delta_cell_number(cell)
        if parsed is None:
            continue
        numeric_cells.append((index, cell, parsed))
    if len(numeric_cells) != 3:
        return None
    prior_index, prior_cell, prior_value = numeric_cells[0]
    current_index, current_cell, current_value = numeric_cells[1]
    stated_index, stated_cell, stated_delta = numeric_cells[2]
    if prior_index >= current_index or current_index >= stated_index:
        return None
    derived_delta = current_value - prior_value
    difference = derived_delta - stated_delta
    tolerance = max(1.0, abs(derived_delta) * 0.02)
    if abs(difference) > tolerance:
        return None
    percent = (derived_delta / prior_value * 100.0) if prior_value else None
    row_label = " ".join(cell for index, cell in enumerate(cells) if index < prior_index).strip()
    derived_display = _source_record_table_delta_number_display(derived_delta, signed=True)
    stated_display = _source_record_table_delta_number_display(stated_delta, signed=True)
    percent_display = ""
    if percent is not None:
        rounded_percent = round(percent, 1)
        truncated_percent = int(percent * 10) / 10
        percent_display = (
            f"{percent:.4f}%"
            f" (1dp rounded {_source_record_table_delta_percent_display(rounded_percent)}, "
            f"1dp truncated {_source_record_table_delta_percent_display(truncated_percent)})"
        )
    agreement = abs(difference) < 0.0001
    full_answer = (
        f"{row_label + '; ' if row_label else ''}"
        f"prior {_source_record_table_delta_number_display(prior_value)}; "
        f"current {_source_record_table_delta_number_display(current_value)}; "
        f"source-stated change {stated_display}; "
        f"derived change {derived_display}"
    )
    if percent_display:
        full_answer = f"{full_answer}; derived percent {percent_display}"
    if not agreement:
        full_answer = (
            f"{full_answer}; source-stated/derived delta difference "
            f"{_source_record_table_delta_number_display(difference, signed=True)}"
        )
    return {
        "SupportKind": "source_record_table_delta_check",
        "SourceRow": source_row,
        "SourceSurfaceKind": surface_kind,
        "SourceCellIndex": cell_index,
        "SourceTextDisplay": text,
        "RowLabelDisplay": row_label,
        "PriorValue": _source_record_table_delta_number_display(prior_value),
        "CurrentValue": _source_record_table_delta_number_display(current_value),
        "SourceStatedDelta": stated_display,
        "DerivedDelta": derived_display,
        "DeltaAgreement": str(agreement).lower(),
        "DeltaDifference": _source_record_table_delta_number_display(difference, signed=True),
        "DerivedPercentDisplay": percent_display,
        "FullAnswerDisplay": full_answer,
        "SupportClass": "deterministic-source-record-summary",
    }


def _clean_source_record_table_delta_cell(value: str) -> str:
    text = unicodedata.normalize("NFKC", str(value or "")).strip()
    text = re.sub(r"[*_`]+", "", text)
    return re.sub(r"\s+", " ", text).strip()


def _source_record_table_delta_cell_number(value: str) -> float | None:
    text = _clean_source_record_table_delta_cell(value)
    if not text or text in {"-", "－", "—", "–"}:
        return None
    negative = "△" in text or text.startswith("(")
    match = re.search(r"[-+]?\d{1,3}(?:,\d{3})+(?:\.\d+)?|[-+]?\d+(?:\.\d+)?", text)
    if match is None:
        return None
    raw = match.group(0).replace(",", "")
    try:
        value = float(raw)
    except ValueError:
        return None
    if negative and value > 0:
        value = -value
    return value


def _source_record_table_delta_number_display(value: float, *, signed: bool = False) -> str:
    sign = ""
    if signed and value > 0:
        sign = "+"
    if abs(value - round(value)) < 0.0001:
        return f"{sign}{int(round(value)):,}"
    return f"{sign}{value:,.4f}".rstrip("0").rstrip(".")


def _source_record_table_delta_percent_display(value: float) -> str:
    return f"{value:.1f}%"


def _source_record_ratio_calculation_companion(
    runtime: CorePrologRuntime,
    *,
    utterance: str,
    query_intents: list[dict[str, Any]] | None = None,
) -> dict[str, Any] | None:
    intent = _first_query_intent(query_intents, "ratio_calculation")
    if not intent:
        return None
    query_tokens = _query_intent_target_tokens(intent)
    money_entries: list[dict[str, Any]] = []
    count_entries: list[dict[str, Any]] = []
    for source_row, text_atom in _source_record_text_atoms(runtime):
        atom = _normalize_text_filter_atom(text_atom)
        money_entries.extend(_source_record_ratio_money_entries(source_row=source_row, text_atom=atom, query_tokens=query_tokens))
        count_entries.extend(_source_record_ratio_count_entries(source_row=source_row, text_atom=atom, query_tokens=query_tokens))
    if not money_entries or not count_entries:
        return None

    rows: list[dict[str, str]] = []
    seen_calculations: set[tuple[str, str, str, str]] = set()
    for money in money_entries:
        for count in count_entries:
            if float(count["Value"]) <= 0:
                continue
            quotient = float(money["Value"]) / float(count["Value"])
            score = int(money["Score"]) + int(count["Score"])
            if score <= 0:
                continue
            rounded = int(round(quotient))
            qualifier = str(count.get("Qualifier", ""))
            bound_note = "upper bound because the denominator is source-qualified as over/at least" if qualifier in {"over", "at_least"} else ""
            unit_display = str(count.get("UnitDisplay", "") or "unit")
            calculation_key = (
                str(int(round(float(money["Value"])))),
                str(int(round(float(count["Value"])))),
                str(count.get("UnitAtom", "")),
                qualifier,
            )
            if calculation_key in seen_calculations:
                continue
            seen_calculations.add(calculation_key)
            rows.append(
                {
                    "SupportKind": "source_record_ratio_calculation",
                    "NumeratorSourceRow": str(money["SourceRow"]),
                    "NumeratorValue": str(int(round(float(money["Value"])))),
                    "NumeratorDisplay": _source_record_ratio_money_display(float(money["Value"])),
                    "DenominatorSourceRow": str(count["SourceRow"]),
                    "DenominatorValue": str(int(round(float(count["Value"])))),
                    "DenominatorDisplay": f"{_source_record_ratio_count_display(float(count['Value']), qualifier=qualifier)} {unit_display}".strip(),
                    "DenominatorQualifier": qualifier,
                    "UnitAtom": str(count.get("UnitAtom", "")),
                    "UnitDisplay": unit_display,
                    "QuotientValue": _source_record_ratio_number_display(quotient),
                    "RoundedQuotient": str(rounded),
                    "QuotientDisplay": f"approximately ${rounded:,} per {unit_display.rstrip('s')}",
                    "BoundNote": bound_note,
                    "CalculationExpression": f"{_source_record_ratio_money_display(float(money['Value']))} / {int(round(float(count['Value']))):,}",
                    "FullAnswerDisplay": (
                        f"{_source_record_ratio_count_display(float(count['Value']), qualifier=qualifier)} {unit_display}; "
                        f"{_source_record_ratio_money_display(float(money['Value']))} / {int(round(float(count['Value']))):,} = "
                        f"approximately ${rounded:,} per {unit_display.rstrip('s')}"
                    ),
                    "MatchScore": str(score),
                    "SupportClass": "deterministic-source-record-summary",
                }
            )
    if not rows:
        return None
    rows.sort(key=lambda row: (-int(row.get("MatchScore", "0")), _source_row_sort_key(row.get("NumeratorSourceRow", "")), _source_row_sort_key(row.get("DenominatorSourceRow", ""))))
    summary = {
        "SupportKind": "source_record_ratio_calculation_summary",
        "CalculationCount": str(len(rows)),
        "CalculationsDisplay": "; ".join(row["FullAnswerDisplay"] for row in rows[:5]),
        "SupportClass": "deterministic-source-record-summary",
    }
    return {
        "query": "source_record_ratio_calculation_support(NumeratorSourceRow, DenominatorSourceRow, QuotientValue).",
        "result": {
            "status": "success",
            "predicate": "source_record_ratio_calculation_support",
            "prolog_query": "source_record_ratio_calculation_support(NumeratorSourceRow, DenominatorSourceRow, QuotientValue).",
            "result_type": "table",
            "num_rows": len(rows) + 1,
            "variables": _row_variable_names([summary, *rows]),
            "rows": [summary, *rows[:20]],
            "reasoning_basis": {
                "kind": "core-local",
                "note": (
                    "query-only ratio-calculation support divided source-stated money amounts by source-stated "
                    "counts after structured query-intent activation; no durable arithmetic fact was written"
                ),
                "query_intent": intent,
            },
        },
        "derived_from_queries": ["source_record_text_atom(SourceRow, TextAtom)."],
    }


def _source_record_ratio_money_entries(
    *,
    source_row: str,
    text_atom: str,
    query_tokens: set[str],
) -> list[dict[str, Any]]:
    tokens = text_atom.split("_")
    out: list[dict[str, Any]] = []
    for index in range(len(tokens) - 1):
        parsed = _source_record_ratio_scaled_number(tokens, index)
        if not parsed:
            continue
        value, consumed = parsed
        following = tokens[index + consumed : index + consumed + 8]
        nearby = tokens[max(0, index - 8) : index + consumed + 10]
        if "penalty" not in nearby and not (set(nearby) & {"fine", "payment", "settlement"}):
            continue
        if not set(nearby) & (query_tokens | {"penalty", "civil"}):
            continue
        out.append(
            {
                "SourceRow": source_row,
                "Value": value,
                "Score": len(set(nearby) & query_tokens) + (3 if "penalty" in following or "penalty" in nearby else 0),
            }
        )
    return out


def _source_record_ratio_count_entries(
    *,
    source_row: str,
    text_atom: str,
    query_tokens: set[str],
) -> list[dict[str, Any]]:
    tokens = text_atom.split("_")
    out: list[dict[str, Any]] = []
    for index, token in enumerate(tokens):
        qualifier = ""
        number_index = index
        if token in {"over", "about", "approximately"} and index + 1 < len(tokens):
            qualifier = token
            number_index = index + 1
        elif token == "at" and index + 2 < len(tokens) and tokens[index + 1] == "least":
            qualifier = "at_least"
            number_index = index + 2
        elif token.isdigit() and index > 0 and tokens[index - 1] in {"over", "about", "approximately"}:
            continue
        elif token.isdigit() and index > 1 and tokens[index - 2 : index] == ["at", "least"]:
            continue
        parsed = _source_record_ratio_grouped_integer(tokens, number_index)
        if not parsed:
            continue
        value, consumed = parsed
        unit_tokens = tokens[number_index + consumed : number_index + consumed + 6]
        unit_atom = _source_record_ratio_unit_atom(unit_tokens)
        if not unit_atom:
            continue
        nearby = tokens[max(0, index - 8) : number_index + consumed + 10]
        score = len((set(nearby) | set(_source_record_field_name_tokens(unit_atom))) & query_tokens)
        if not query_tokens:
            score = 1
        if score == 0:
            continue
        out.append(
            {
                "SourceRow": source_row,
                "Value": float(value),
                "Qualifier": qualifier,
                "UnitAtom": unit_atom,
                "UnitDisplay": _display_source_phrase(unit_atom),
                "Score": score,
            }
        )
    return out


def _source_record_ratio_scaled_number(tokens: list[str], index: int) -> tuple[float, int] | None:
    if index >= len(tokens) or not tokens[index].isdigit():
        return None
    if index > 0 and tokens[index - 1].isdigit() and index + 1 < len(tokens) and tokens[index + 1] in {
        "thousand",
        "million",
        "billion",
    }:
        return None
    if index + 2 < len(tokens) and tokens[index + 1].isdigit() and tokens[index + 2] in {"thousand", "million", "billion"}:
        value = float(f"{tokens[index]}.{tokens[index + 1]}")
        scale = {"thousand": 1_000, "million": 1_000_000, "billion": 1_000_000_000}[tokens[index + 2]]
        return value * scale, 3
    if index + 1 < len(tokens) and tokens[index + 1] in {"thousand", "million", "billion"}:
        value = float(tokens[index])
        scale = {"thousand": 1_000, "million": 1_000_000, "billion": 1_000_000_000}[tokens[index + 1]]
        return value * scale, 2
    return None


def _source_record_ratio_grouped_integer(tokens: list[str], index: int) -> tuple[int, int] | None:
    if index >= len(tokens) or not tokens[index].isdigit():
        return None
    parts = [tokens[index]]
    next_index = index + 1
    while next_index < len(tokens) and re.fullmatch(r"\d{3}", tokens[next_index]):
        parts.append(tokens[next_index])
        next_index += 1
    if len(parts) < 2:
        return None
    return int("".join(parts)), len(parts)


def _source_record_ratio_unit_atom(tokens: list[str]) -> str:
    stop = {"throughout", "during", "in", "under", "and", "or", "of", "to", "for", "with", "from"}
    unit: list[str] = []
    for token in tokens:
        if token in stop:
            break
        unit.append(token)
        if token in {"devices", "device", "units", "unit", "vehicles", "vehicle", "shares", "share", "employees", "employee"}:
            break
    if not unit:
        return ""
    if not set(unit) & {"devices", "device", "units", "unit", "vehicles", "vehicle", "shares", "share", "employees", "employee"}:
        return ""
    return "_".join(unit)


def _source_record_ratio_money_display(value: float) -> str:
    return f"${int(round(value)):,}"


def _source_record_ratio_count_display(value: float, *, qualifier: str) -> str:
    prefix = {"over": "over ", "at_least": "at least ", "about": "about ", "approximately": "approximately "}.get(qualifier, "")
    return f"{prefix}{int(round(value)):,}"


def _source_record_ratio_number_display(value: float) -> str:
    if abs(value - round(value)) < 0.005:
        return str(int(round(value)))
    return f"{value:.2f}"


def _source_record_duration_quantity_companion(
    runtime: CorePrologRuntime,
    *,
    utterance: str,
    query_intents: list[dict[str, Any]] | None = None,
) -> dict[str, Any] | None:
    intent = _first_query_intent(query_intents, "duration_quantity", "duration")
    if not intent:
        return None
    query_tokens = _query_intent_target_tokens(intent) | _query_intents_target_tokens(query_intents)
    support_rows: list[dict[str, str]] = []
    seen: set[tuple[str, str, str, str]] = set()
    for source_row, text_atom in _source_record_text_atoms(runtime):
        tokens = _query_atom_tokens(text_atom)
        for entry in _source_record_duration_quantity_entries(tokens, query_tokens=query_tokens):
            key = (source_row, entry["ReferentAtom"], entry["DurationValue"], entry["DurationUnit"])
            if key in seen:
                continue
            seen.add(key)
            support_rows.append(
                {
                    **entry,
                    "SupportKind": "source_record_duration_quantity",
                    "SourceRow": source_row,
                    "SourceTextAtom": text_atom,
                    "SourceTextDisplay": _display_source_phrase(text_atom),
                    "SupportClass": "deterministic-source-record-summary",
                }
            )
    if not support_rows:
        return None
    support_rows.sort(
        key=lambda row: (
            -int(row.get("QuestionOverlap", "0") or "0"),
            _source_row_sort_key(row.get("SourceRow", "")),
            int(row.get("DurationValue", "0") or "0"),
        )
    )
    summary = {
        "SupportKind": "source_record_duration_quantity_summary",
        "SourceRow": "source_record_duration_quantities",
        "QuantityCount": str(len(support_rows)),
        "QuantitiesDisplay": "; ".join(row["FullAnswerDisplay"] for row in support_rows[:12]),
        "SupportClass": "deterministic-source-record-summary",
    }
    rows = [summary, *support_rows[:40]]
    return {
        "query": "source_record_duration_quantity_support(SourceRow, Referent, DurationValue, DurationUnit).",
        "result": {
            "status": "success",
            "predicate": "source_record_duration_quantity_support",
            "prolog_query": "source_record_duration_quantity_support(SourceRow, Referent, DurationValue, DurationUnit).",
            "result_type": "table",
            "num_rows": len(rows),
            "variables": _row_variable_names(rows),
            "rows": rows,
            "reasoning_basis": {
                "kind": "core-local",
                "note": (
                    "query-only duration-quantity support extracted source-stated for/over/within N month/day/year "
                    "phrases from admitted source-record text after structured query-intent activation; "
                    "no durable duration fact was written"
                ),
                "query_intent": intent,
            },
        },
        "derived_from_queries": ["source_record_text_atom(SourceRow, TextAtom)."],
    }


def _source_record_duration_quantity_entries(
    tokens: list[str],
    *,
    query_tokens: set[str],
) -> list[dict[str, str]]:
    out: list[dict[str, str]] = []
    for index, token in enumerate(tokens):
        if token not in {"for", "over", "within"}:
            continue
        parsed = _source_record_parse_duration_quantity(tokens, index + 1)
        if not parsed:
            continue
        value, unit, consumed = parsed
        context_tokens = tokens[max(0, index - 10) : index]
        following_tokens = tokens[index + 1 + consumed : min(len(tokens), index + 1 + consumed + 10)]
        overlap_tokens = set(context_tokens + following_tokens + [unit])
        overlap = len(overlap_tokens & query_tokens)
        if query_tokens and overlap == 0:
            continue
        referent_tokens = _source_record_duration_referent_tokens(context_tokens, query_tokens=query_tokens)
        if not referent_tokens and "deadline" in query_tokens:
            referent_tokens = ["deadline"]
        referent = "_".join(referent_tokens) if referent_tokens else "duration_quantity"
        duration_display = f"{value} {_display_source_phrase(unit)}"
        referent_display = _display_source_phrase(referent)
        anchor_tokens = _source_record_duration_anchor_tokens(following_tokens)
        anchor = "_".join(anchor_tokens)
        anchor_display = _display_source_phrase(anchor) if anchor else ""
        full_answer = f"{referent_display}: {duration_display}"
        if anchor_display:
            full_answer = f"{full_answer} from {anchor_display}"
        out.append(
            {
                "ReferentAtom": referent,
                "ReferentDisplay": referent_display,
                "DurationValue": str(value),
                "DurationUnit": unit,
                "DurationDisplay": duration_display,
                "AnchorAtom": anchor,
                "AnchorDisplay": anchor_display,
                "QuestionOverlap": str(overlap),
                "FullAnswerDisplay": full_answer,
            }
        )
    return out


def _source_record_parse_duration_quantity(tokens: list[str], start: int) -> tuple[int, str, int] | None:
    if start >= len(tokens):
        return None
    first = tokens[start]
    value = _source_record_quantity_token_value(first)
    consumed = 1
    if value is None and start + 1 < len(tokens):
        combined = f"{first}_{tokens[start + 1]}"
        value = _source_record_quantity_token_value(combined)
        consumed = 2 if value is not None else 1
    if start + consumed < len(tokens) and tokens[start + consumed].isdigit():
        value = int(tokens[start + consumed])
        consumed += 1
    if value is None or start + consumed >= len(tokens):
        return None
    unit = tokens[start + consumed]
    if unit in {"business", "working"} and start + consumed + 1 < len(tokens) and tokens[start + consumed + 1] == "days":
        return value, f"{unit}_days", consumed + 2
    if unit in {"day", "days", "month", "months", "year", "years"}:
        normalized_unit = {"day": "days", "month": "months", "year": "years"}.get(unit, unit)
        return value, normalized_unit, consumed + 1
    return None


def _source_record_quantity_token_value(token: str) -> int | None:
    text = str(token or "").strip().lower()
    if text.isdigit():
        return int(text)
    values = {
        "one": 1,
        "two": 2,
        "three": 3,
        "four": 4,
        "five": 5,
        "six": 6,
        "seven": 7,
        "eight": 8,
        "nine": 9,
        "ten": 10,
        "eleven": 11,
        "twelve": 12,
        "thirteen": 13,
        "fourteen": 14,
        "fifteen": 15,
        "sixteen": 16,
        "seventeen": 17,
        "eighteen": 18,
        "nineteen": 19,
        "twenty": 20,
        "twenty_one": 21,
        "twenty_two": 22,
        "twenty_three": 23,
        "twenty_four": 24,
    }
    return values.get(text)


def _source_record_duration_referent_tokens(tokens: list[str], *, query_tokens: set[str]) -> list[str]:
    if not tokens:
        return []
    best: list[str] = []
    best_score = -1
    left = max(0, len(tokens) - 8)
    for start in range(left, len(tokens)):
        candidate = tokens[start:]
        if not candidate:
            continue
        score = len(set(candidate) & query_tokens)
        if score > best_score or (score == best_score and len(candidate) < len(best)):
            best = candidate
            best_score = score
    while best and best[0] in {"the", "a", "an", "and", "or", "shall", "will", "also", "pay", "paid"}:
        best = best[1:]
    return best[-6:]


def _source_record_duration_anchor_tokens(tokens: list[str]) -> list[str]:
    if not tokens:
        return []
    for marker in ("from", "after", "following"):
        if marker not in tokens:
            continue
        index = tokens.index(marker)
        anchor = tokens[index + 1 : index + 8]
        while anchor and anchor[0] in {"the", "a", "an", "date", "of"}:
            anchor = anchor[1:]
        cleaned: list[str] = []
        for token in anchor:
            if token in {"describing", "including", "and", "or", "to", "with", "in"}:
                break
            cleaned.append(token)
        return cleaned[:6]
    return []


def _source_record_amount_context_signal(atom: str) -> bool:
    tokens = set(_query_atom_tokens(atom))
    return bool(
        tokens
        & {
            "amount",
            "annual",
            "award",
            "benefit",
            "bonus",
            "cash",
            "fee",
            "fees",
            "gross",
            "par",
            "payment",
            "payments",
            "premium",
            "premiums",
            "reimbursement",
            "salary",
            "severance",
            "share",
            "value",
            "valued",
        }
    )


def _source_record_amount_mentions(atom: str) -> list[dict[str, str]]:
    out: list[dict[str, str]] = []
    text = _normalize_text_filter_atom(atom)
    for match in re.finditer(r"(?<!\d)(?P<value>\d+(?:_\d{2,3})*)(?!\d)", text):
        value = match.group("value")
        if _source_record_amount_is_plain_year(value):
            continue
        if _source_record_amount_is_date_fragment(text=text, start=match.start(), end=match.end(), value=value):
            continue
        window = _source_record_amount_window(text, match.start(), match.end())
        amount_kind = _source_record_amount_kind(value=value, window=window)
        if not amount_kind:
            continue
        referent = _source_record_amount_referent(
            text=text,
            start=match.start(),
            end=match.end(),
            window=window,
            amount_value=value,
            amount_kind=amount_kind,
        )
        if not referent:
            continue
        out.append(
            {
                "AmountKind": amount_kind,
                "AmountValue": value,
                "AmountDisplay": _source_record_amount_display(value=value, amount_kind=amount_kind),
                "ReferentAtom": referent,
            }
        )
    return out


def _source_record_amount_is_plain_year(value: str) -> bool:
    return bool(re.fullmatch(r"(?:19|20)\d{2}", value))


def _source_record_amount_is_date_fragment(*, text: str, start: int, end: int, value: str) -> bool:
    if re.fullmatch(r"(?:19|20)\d{2}_\d{2}_\d{2}", value):
        return True
    if re.fullmatch(r"\d{1,2}", value) and re.match(r"_(?:19|20)\d{2}(?:_|$)", text[end:]):
        return True
    if re.fullmatch(r"\d{1,2}", value) and re.match(r"_[a-z](?:_|$)", text[end:]):
        prefix = text[max(0, start - 48) : start]
        if re.search(r"(?:^|_)(?:item|rule|section|security|subsection|title)(?:_|$)", prefix):
            return True
    if re.fullmatch(r"\d{1,2}", value):
        prefix = text[max(0, start - 16) : start]
        if re.search(
            r"(?:^|_)(?:jan|january|feb|february|mar|march|apr|april|may|jun|june|jul|july|"
            r"aug|august|sep|sept|september|oct|october|nov|november|dec|december)_$",
            prefix,
        ):
            return True
    return False


def _source_record_amount_window(text: str, start: int, end: int, *, radius: int = 120) -> str:
    left = max(0, int(start) - radius)
    right = min(len(text), int(end) + radius)
    return text[left:right].strip("_")


def _source_record_amount_kind(*, value: str, window: str) -> str:
    if re.search(r"(?:^|_)(?:achievement|attainment|multiplier)(?:_|$)", window):
        return "percentage"
    if re.search(rf"(?:^|_)equal_to_{re.escape(value)}_of_the_sum(?:_|$)", window):
        return "percentage"
    if re.search(
        r"(?:^|_)(?:amount|annual|award|benefit|bonus|cash|fee|fees|par_value|payment|payments|premium|"
        r"premiums|reimbursement|salary|severance|share|value|valued)(?:_|$)",
        window,
    ):
        return "money"
    return ""


def _source_record_amount_referent(
    *,
    text: str,
    start: int,
    end: int,
    window: str,
    amount_value: str,
    amount_kind: str,
) -> str:
    local_text = _source_record_amount_window(text, start, end, radius=56)
    window_text = _normalize_text_filter_atom(window)
    value = re.escape(amount_value)
    patterns = [
        rf"(?:^|_)(?P<referent>common_stock_par_value_{value}_per_share)(?:_|$)",
        rf"(?:^|_)(?P<referent>cash_bonus_of_{value}(?:_[a-z0-9]+){{0,18}}?)(?:_|$)",
        rf"(?:^|_)(?P<referent>time_vesting_restricted_stock_unit_award_valued_at_{value}(?:_[a-z0-9]+){{0,18}}?)(?:_|$)",
        rf"(?:^|_)(?P<referent>cash_severance_equal_to_{value}_of_the_sum(?:_[a-z0-9]+){{0,18}}?)(?:_|$)",
        rf"(?:^|_)(?P<referent>{value}_achievement_of_the_individual_objectives)(?:_|$)",
        rf"(?:^|_)(?P<referent>continued_[a-z0-9_]*benefits(?:_[a-z0-9]+){{0,16}}?_up_to_{value})(?:_|$)",
        rf"(?:^|_)(?P<referent>annual_benefit_of_{value}(?:_[a-z0-9]+){{0,12}}?)(?:_|$)",
        rf"(?:^|_)(?P<referent>reimbursement_of_up_to_{value}(?:_[a-z0-9]+){{0,18}}?)(?:_|$)",
    ]
    for candidate_text in (local_text, window_text):
        for pattern in patterns:
            match = re.search(pattern, candidate_text)
            if match:
                return match.group("referent").strip("_")
    tokens = window_text.split("_")
    value_tokens = amount_value.split("_")
    for index in range(0, max(0, len(tokens) - len(value_tokens) + 1)):
        if tokens[index : index + len(value_tokens)] != value_tokens:
            continue
        left = max(0, index - 8)
        right = min(len(tokens), index + len(value_tokens) + 10)
        referent_tokens = tokens[left:right]
        referent = "_".join(token for token in referent_tokens if token)
        if amount_kind == "percentage" and not re.search(r"(achievement|attainment|severance|sum)", referent):
            return ""
        return referent
    return ""


def _source_record_amount_display(*, value: str, amount_kind: str) -> str:
    text = _normalize_text_filter_atom(value)
    if amount_kind == "percentage":
        return f"{text.replace('_', '.')}%"
    if re.fullmatch(r"\d+_\d{2}", text) and not text.endswith("_000"):
        whole, cents = text.split("_", 1)
        return f"${int(whole):,}.{cents}"
    number = int(text.replace("_", ""))
    return f"${number:,}"


def _source_record_restrictive_covenant_companion(
    runtime: CorePrologRuntime,
    *,
    utterance: str,
) -> dict[str, Any] | None:
    text = str(utterance or "").casefold()
    if not re.search(
        r"\b(?:restrictive|covenant|covenants|confidentiality|non[-\s]?competition|"
        r"non[-\s]?solicitation|non[-\s]?disparagement)\b",
        text,
    ):
        return None

    support_rows: list[dict[str, str]] = []
    seen: set[tuple[str, str]] = set()
    for source_row, text_atom in _source_record_text_atoms(runtime):
        atom = _normalize_text_filter_atom(text_atom)
        if not _source_record_restrictive_covenant_signal(atom):
            continue
        for term in _source_record_restrictive_covenant_terms(atom):
            key = (source_row, term["CovenantKind"])
            if key in seen:
                continue
            seen.add(key)
            support_rows.append(
                {
                    "SupportKind": "source_record_restrictive_covenant_item",
                    "CovenantKind": term["CovenantKind"],
                    "CovenantAtom": term["CovenantAtom"],
                    "CovenantDisplay": term["CovenantDisplay"],
                    "SourceRow": source_row,
                    "SourceTextAtom": text_atom,
                    "SourceTextDisplay": _display_source_phrase(text_atom),
                    "FullAnswerDisplay": term["CovenantDisplay"],
                    "SupportClass": "deterministic-source-record-summary",
                }
            )
    if not support_rows:
        return None
    support_rows.sort(
        key=lambda row: (
            _source_row_sort_key(row.get("SourceRow", "")),
            _source_record_restrictive_covenant_sort_key(row.get("CovenantKind", "")),
        )
    )
    summary = {
        "SupportKind": "source_record_restrictive_covenant_summary",
        "SourceRow": "source_record_restrictive_covenants",
        "CovenantCount": str(len(support_rows)),
        "CovenantsDisplay": "; ".join(row["FullAnswerDisplay"] for row in support_rows),
        "SupportClass": "deterministic-source-record-summary",
    }
    rows = [*support_rows, summary]
    return {
        "query": "source_record_restrictive_covenant_support(CovenantKind, CovenantAtom, SourceRow).",
        "result": {
            "status": "success",
            "predicate": "source_record_restrictive_covenant_support",
            "prolog_query": "source_record_restrictive_covenant_support(CovenantKind, CovenantAtom, SourceRow).",
            "result_type": "table",
            "num_rows": len(rows),
            "variables": _row_variable_names(rows),
            "rows": rows[:100],
            "reasoning_basis": {
                "kind": "core-local",
                "note": (
                    "query-only restrictive-covenant support extracted generic covenant and release terms "
                    "from admitted source-record text; no durable covenant fact was written"
                ),
                "utterance": utterance,
            },
        },
        "derived_from_queries": ["source_record_text_atom(SourceRow, TextAtom)."],
    }


def _source_record_restrictive_covenant_signal(atom: str) -> bool:
    text = _normalize_text_filter_atom(atom)
    return bool(
        re.search(
            r"(?:^|_)(?:confidentiality|non_competition|noncompetition|non_solicitation|"
            r"nonsolicitation|non_disparagement|nondisparagement|release_of_claims)(?:_|$)",
            text,
        )
    )


def _source_record_restrictive_covenant_terms(atom: str) -> list[dict[str, str]]:
    text = _normalize_text_filter_atom(atom)
    term_specs = [
        ("confidentiality", "confidentiality", "confidentiality"),
        ("non_competition", "non[_-]?competition|noncompetition", "non-competition"),
        ("non_solicitation", "non[_-]?solicitation|nonsolicitation", "non-solicitation"),
        ("non_disparagement", "non[_-]?disparagement|nondisparagement", "non-disparagement"),
        (
            "customary_terms_and_conditions",
            "other_customary_terms_and_conditions|customary_terms_and_conditions|customary_terms",
            "other customary terms and conditions",
        ),
    ]
    out: list[dict[str, str]] = []
    for kind, pattern, display in term_specs:
        if re.search(rf"(?:^|_)(?:{pattern})(?:_|$)", text):
            out.append({"CovenantKind": kind, "CovenantAtom": kind, "CovenantDisplay": display})
    if re.search(r"(?:^|_)release_of_claims(?:_|$)", text):
        display = "release of claims"
        if re.search(r"(?:^|_)each_of_[a-z0-9_]{1,160}_and_[a-z0-9_]{1,160}_is_providing_a_release_of_claims(?:_|$)", text):
            display = "bilateral release of claims"
        out.append(
            {
                "CovenantKind": "release_of_claims",
                "CovenantAtom": "release_of_claims",
                "CovenantDisplay": display,
            }
        )
    return out


def _source_record_restrictive_covenant_sort_key(kind: str) -> int:
    order = {
        "confidentiality": 0,
        "non_competition": 1,
        "non_solicitation": 2,
        "non_disparagement": 3,
        "customary_terms_and_conditions": 4,
        "release_of_claims": 5,
    }
    return order.get(str(kind), 99)


def _source_record_defined_term_contrast_companion(
    runtime: CorePrologRuntime,
    *,
    utterance: str,
) -> dict[str, Any] | None:
    text = str(utterance or "")
    folded = text.casefold()
    if not re.search(r"\b(?:difference|different|distinguish|contrast|relationship|relate|versus|vs)\b", folded):
        return None
    terms = _source_record_quoted_terms(text)
    if len(terms) < 2:
        return None

    support_rows: list[dict[str, str]] = []
    seen: set[tuple[str, str, str]] = set()
    for source_row, text_atom in _source_record_text_atoms(runtime):
        atom = _normalize_text_filter_atom(text_atom)
        for term_atom, term_display in terms:
            if not re.search(rf"(?:^|_)the_{re.escape(term_atom)}(?:_|$)", atom):
                continue
            for entry in _source_record_defined_term_entries(
                source_row=source_row,
                text_atom=text_atom,
                atom=atom,
                term_atom=term_atom,
                term_display=term_display,
            ):
                key = (entry["DefinitionKind"], entry["TermAtom"], entry["SourceRow"])
                if key in seen:
                    continue
                seen.add(key)
                support_rows.append(entry)
    relation = _source_record_defined_term_relation_row(support_rows)
    if relation:
        support_rows.append(relation)
    if not support_rows:
        return None
    support_rows.sort(
        key=lambda row: (
            1 if row.get("DefinitionKind") == "term_relationship" else 0,
            _source_row_sort_key(row.get("SourceRow", "")),
            row.get("TermAtom", ""),
            row.get("DefinitionKind", ""),
        )
    )
    summary = {
        "SupportKind": "source_record_defined_term_contrast_summary",
        "SourceRow": "source_record_defined_term_contrast",
        "TermCount": str(len({row.get("TermAtom") for row in support_rows if row.get("TermAtom")})),
        "DefinitionsDisplay": "; ".join(row["FullAnswerDisplay"] for row in support_rows),
        "SupportClass": "deterministic-source-record-summary",
    }
    rows = [*support_rows, summary]
    return {
        "query": "source_record_defined_term_contrast_support(Term, DefinitionKind, SourceRow).",
        "result": {
            "status": "success",
            "predicate": "source_record_defined_term_contrast_support",
            "prolog_query": "source_record_defined_term_contrast_support(Term, DefinitionKind, SourceRow).",
            "result_type": "table",
            "num_rows": len(rows),
            "variables": _row_variable_names(rows),
            "rows": rows[:100],
            "reasoning_basis": {
                "kind": "core-local",
                "note": (
                    "query-only defined-term contrast support extracted fixed-period and conditional-date "
                    "term definitions from admitted source-record text; no durable term fact was written"
                ),
                "utterance": utterance,
            },
        },
        "derived_from_queries": ["source_record_text_atom(SourceRow, TextAtom)."],
    }


def _source_record_quoted_terms(utterance: str) -> list[tuple[str, str]]:
    out: list[tuple[str, str]] = []
    seen: set[str] = set()
    for match in re.finditer(r"[\"'“”‘’]([^\"'“”‘’]{2,80})[\"'“”‘’]", str(utterance or "")):
        display = re.sub(r"\s+", " ", match.group(1)).strip()
        atom = _normalize_text_filter_atom(display)
        if not atom or atom in seen:
            continue
        seen.add(atom)
        out.append((atom, display))
    return out


def _source_record_defined_term_entries(
    *,
    source_row: str,
    text_atom: str,
    atom: str,
    term_atom: str,
    term_display: str,
) -> list[dict[str, str]]:
    out: list[dict[str, str]] = []
    fixed_period = re.search(
        rf"(?:^|_)(?P<context>[a-z0-9_]{{0,220}}?through_(?P<end>[a-z]+_\d{{1,2}}_\d{{4}})_the_{re.escape(term_atom)})(?:_|$)",
        atom,
    )
    if fixed_period:
        context = fixed_period.group("context").strip("_")
        dates = _source_record_defined_term_month_date_atoms(context)
        start_date = dates[0] if dates else ""
        end_date = fixed_period.group("end")
        display = f"{term_display}: fixed period"
        if start_date and end_date:
            display = f"{term_display}: fixed period from {_display_source_phrase(start_date)} through {_display_source_phrase(end_date)}"
        elif end_date:
            display = f"{term_display}: fixed period through {_display_source_phrase(end_date)}"
        out.append(
            {
                "SupportKind": "source_record_defined_term_contrast_item",
                "TermAtom": term_atom,
                "TermDisplay": term_display,
                "DefinitionKind": "fixed_period",
                "StartDate": start_date,
                "EndDate": end_date,
                "ConditionAtom": "",
                "DefinitionAtom": context,
                "DefinitionDisplay": _display_source_phrase(context),
                "SourceRow": source_row,
                "SourceTextAtom": text_atom,
                "SourceTextDisplay": _display_source_phrase(text_atom),
                "FullAnswerDisplay": display,
                "SupportClass": "deterministic-source-record-summary",
            }
        )
    conditional_date = re.search(
        rf"(?:^|_)(?P<context>[a-z0-9_]{{0,220}}?(?P<base>[a-z]+_\d{{1,2}}_\d{{4}})_or_such_earlier_date_that_(?P<condition>[a-z0-9_]{{3,180}}?)_the_{re.escape(term_atom)})(?:_|$)",
        atom,
    )
    if conditional_date:
        context = conditional_date.group("context").strip("_")
        base_date = conditional_date.group("base")
        condition = conditional_date.group("condition").strip("_")
        out.append(
            {
                "SupportKind": "source_record_defined_term_contrast_item",
                "TermAtom": term_atom,
                "TermDisplay": term_display,
                "DefinitionKind": "conditional_date",
                "StartDate": "",
                "EndDate": base_date,
                "ConditionAtom": condition,
                "DefinitionAtom": context,
                "DefinitionDisplay": _display_source_phrase(context),
                "SourceRow": source_row,
                "SourceTextAtom": text_atom,
                "SourceTextDisplay": _display_source_phrase(text_atom),
                "FullAnswerDisplay": (
                    f"{term_display}: {_display_source_phrase(base_date)} or an earlier date if "
                    f"{_display_source_phrase(condition)}"
                ),
                "SupportClass": "deterministic-source-record-summary",
            }
        )
    return out


def _source_record_defined_term_month_date_atoms(text: str) -> list[str]:
    return re.findall(
        r"(?:january|february|march|april|may|june|july|august|september|october|november|december)_\d{1,2}_\d{4}",
        _normalize_text_filter_atom(text),
    )


def _source_record_defined_term_relation_row(rows: list[dict[str, str]]) -> dict[str, str] | None:
    fixed = next((row for row in rows if row.get("DefinitionKind") == "fixed_period"), None)
    conditional = next((row for row in rows if row.get("DefinitionKind") == "conditional_date"), None)
    if not fixed or not conditional:
        return None
    fixed_end = fixed.get("EndDate", "")
    conditional_base = conditional.get("EndDate", "")
    if fixed_end and conditional_base and fixed_end != conditional_base:
        relation = "defined terms have different stated dates"
    else:
        relation = (
            "terms coincide at the fixed period end if no earlier triggering event occurs; "
            "the conditional date can move earlier if the stated event occurs"
        )
    return {
        "SupportKind": "source_record_defined_term_contrast_relation",
        "TermAtom": f"{fixed.get('TermAtom', '')}_vs_{conditional.get('TermAtom', '')}".strip("_"),
        "TermDisplay": f"{fixed.get('TermDisplay', '')} vs {conditional.get('TermDisplay', '')}".strip(),
        "DefinitionKind": "term_relationship",
        "StartDate": fixed.get("StartDate", ""),
        "EndDate": fixed_end or conditional_base,
        "ConditionAtom": conditional.get("ConditionAtom", ""),
        "DefinitionAtom": relation.replace(" ", "_").replace(";", ""),
        "DefinitionDisplay": relation,
        "SourceRow": "source_record_defined_term_contrast",
        "SourceTextAtom": "",
        "SourceTextDisplay": "",
        "FullAnswerDisplay": relation,
        "SupportClass": "deterministic-source-record-summary",
    }


def _source_record_signature_mismatch_companion(
    runtime: CorePrologRuntime,
    *,
    utterance: str,
) -> dict[str, Any] | None:
    text = str(utterance or "").casefold()
    if not re.search(r"\bsignature(?:s| block)?\b", text):
        return None
    if not re.search(r"\b(?:inconsistency|inconsistent|mismatch|disagree|disagreement|different|two lines)\b", text):
        return None

    rows_by_source: dict[str, dict[int, str]] = {}
    for row in _runtime_rows(runtime, "source_record_cell(SourceRow, Column, Value)."):
        if not isinstance(row, dict):
            continue
        source_row = str(row.get("SourceRow", "")).strip()
        column = _safe_int(row.get("Column"))
        value = _normalize_text_filter_atom(str(row.get("Value", "")))
        if not source_row or column is None or not value:
            continue
        rows_by_source.setdefault(source_row, {})[column] = value

    support_rows: list[dict[str, str]] = []
    sorted_rows = sorted(rows_by_source.items(), key=lambda item: _source_row_sort_key(item[0]))
    for index, (source_row, cells) in enumerate(sorted_rows):
        signed_name = _source_record_signature_signed_name(cells)
        if not signed_name:
            continue
        for printed_row, printed_cells in sorted_rows[index + 1 : index + 4]:
            printed_name = _source_record_signature_printed_name(printed_cells)
            if not printed_name:
                continue
            if not _source_record_signature_names_mismatch(signed_name, printed_name):
                continue
            support_rows.append(
                {
                    "SupportKind": "source_record_signature_mismatch",
                    "SignedSourceRow": source_row,
                    "PrintedSourceRow": printed_row,
                    "SignedNameAtom": signed_name,
                    "PrintedNameAtom": printed_name,
                    "SignedNameDisplay": _display_source_phrase(signed_name),
                    "PrintedNameDisplay": _display_source_phrase(printed_name),
                    "FullAnswerDisplay": (
                        f"signed name {_display_source_phrase(signed_name)} differs from printed name "
                        f"{_display_source_phrase(printed_name)}"
                    ),
                    "SupportClass": "deterministic-source-record-summary",
                }
            )
            break
    if not support_rows:
        return None
    summary = {
        "SupportKind": "source_record_signature_mismatch_summary",
        "SourceRow": "source_record_signature_mismatch",
        "MismatchCount": str(len(support_rows)),
        "MismatchesDisplay": "; ".join(row["FullAnswerDisplay"] for row in support_rows),
        "SupportClass": "deterministic-source-record-summary",
    }
    rows = [*support_rows, summary]
    return {
        "query": "source_record_signature_mismatch_support(SignedName, PrintedName, SignedSourceRow, PrintedSourceRow).",
        "result": {
            "status": "success",
            "predicate": "source_record_signature_mismatch_support",
            "prolog_query": (
                "source_record_signature_mismatch_support(SignedName, PrintedName, SignedSourceRow, PrintedSourceRow)."
            ),
            "result_type": "table",
            "num_rows": len(rows),
            "variables": _row_variable_names(rows),
            "rows": rows[:100],
            "reasoning_basis": {
                "kind": "core-local",
                "note": (
                    "query-only signature-mismatch support compared adjacent signed-name and printed-name "
                    "source-record table cells; no durable signatory fact was written"
                ),
                "utterance": utterance,
            },
        },
        "derived_from_queries": ["source_record_cell(SourceRow, Column, Value)."],
    }


def _source_record_signature_signed_name(cells: dict[int, str]) -> str:
    if not any(value == "by" for value in cells.values()):
        return ""
    for value in cells.values():
        normalized = _normalize_text_filter_atom(value)
        if normalized.startswith("s_") and len(normalized.split("_")) >= 3:
            return normalized.removeprefix("s_")
    return ""


def _source_record_signature_printed_name(cells: dict[int, str]) -> str:
    if not any(value == "name" for value in cells.values()):
        return ""
    for column, value in sorted(cells.items()):
        normalized = _normalize_text_filter_atom(value)
        if normalized == "name":
            continue
        if re.fullmatch(r"[a-z]+(?:_[a-z]+){1,4}", normalized):
            return normalized
    return ""


def _source_record_signature_names_mismatch(signed_name: str, printed_name: str) -> bool:
    signed = _normalize_text_filter_atom(signed_name)
    printed = _normalize_text_filter_atom(printed_name)
    if not signed or not printed or signed == printed:
        return False
    signed_tokens = signed.split("_")
    printed_tokens = printed.split("_")
    if len(signed_tokens) != len(printed_tokens):
        return False
    if signed_tokens[:-1] != printed_tokens[:-1]:
        return False
    return _source_record_signature_token_near_miss(signed_tokens[-1], printed_tokens[-1])


def _source_record_signature_token_near_miss(left: str, right: str) -> bool:
    if left == right or min(len(left), len(right)) < 4:
        return False
    if abs(len(left) - len(right)) > 2:
        return False
    common_prefix = 0
    for left_char, right_char in zip(left, right):
        if left_char != right_char:
            break
        common_prefix += 1
    if common_prefix < 4:
        return False
    return _small_edit_distance(left, right) <= 2


def _small_edit_distance(left: str, right: str, *, limit: int = 2) -> int:
    previous = list(range(len(right) + 1))
    for left_index, left_char in enumerate(left, start=1):
        current = [left_index]
        best = current[0]
        for right_index, right_char in enumerate(right, start=1):
            cost = 0 if left_char == right_char else 1
            current.append(min(previous[right_index] + 1, current[right_index - 1] + 1, previous[right_index - 1] + cost))
            best = min(best, current[-1])
        if best > limit:
            return best
        previous = current
    return previous[-1]


def _source_record_dated_event_inventory_companion(
    runtime: CorePrologRuntime,
    *,
    utterance: str,
    query_intents: list[dict[str, Any]] | None = None,
) -> dict[str, Any] | None:
    text = str(utterance or "").casefold()
    raw_inventory_trigger = bool(re.search(r"\b(?:list|every|all|inventory)\b", text)) and bool(
        re.search(
            r"\b(?:dated event|dated events|event date|event dates|dates? in .*order|order .*dates?|"
            r"dates? explicitly mentioned|explicitly mentioned dates?|all dates?)\b",
            text,
        )
    )
    structured_intent = _source_record_dated_event_inventory_intent(query_intents)
    if not raw_inventory_trigger and structured_intent is None:
        return None

    kind_by_row = {
        str(row.get("SourceRow", "")): str(row.get("Kind", ""))
        for row in _runtime_rows(runtime, "source_record_kind(SourceRow, Kind).")
        if isinstance(row, dict)
    }
    support_rows: list[dict[str, str]] = []
    seen: set[tuple[str, str, str]] = set()
    sequence = 1
    if raw_inventory_trigger:
        for source_row, text_atom in sorted(_source_record_text_atoms(runtime), key=lambda item: _source_row_sort_key(item[0])):
            atom = _normalize_text_filter_atom(text_atom)
            if _source_record_dated_event_skip_row(source_row=source_row, atom=atom, kind=kind_by_row.get(source_row, "")):
                continue
            for mention in _source_record_dated_event_mentions(atom):
                key = (source_row, mention["DateDisplay"], mention["EventAtom"])
                if key in seen:
                    continue
                seen.add(key)
                support_rows.append(
                    {
                        "SupportKind": "source_record_dated_event_inventory_item",
                        "SequenceIndex": str(sequence),
                        "EventDate": mention["DateAtom"],
                        "EventDateDisplay": mention["DateDisplay"],
                        "EventAtom": mention["EventAtom"],
                        "EventDisplay": mention["EventDisplay"],
                        "SourceRow": source_row,
                        "SourceTextAtom": text_atom,
                        "SourceTextDisplay": _display_source_phrase(text_atom),
                        "FullAnswerDisplay": f"{sequence}. {mention['DateDisplay']}: {mention['EventDisplay']}",
                        "SupportClass": "deterministic-source-record-summary",
                    }
                )
                sequence += 1
    if structured_intent is not None:
        for mention in _source_record_display_date_inventory_mentions(runtime):
            key = (mention["SourceRow"], mention["DateDisplay"], mention["EventAtom"])
            if key in seen:
                continue
            seen.add(key)
            support_rows.append(
                {
                    "SupportKind": "source_record_dated_event_inventory_item",
                    "SequenceIndex": str(sequence),
                    "EventDate": mention["DateAtom"],
                    "EventDateDisplay": mention["DateDisplay"],
                    "EventAtom": mention["EventAtom"],
                    "EventDisplay": mention["EventDisplay"],
                    "SourceRow": mention["SourceRow"],
                    "SourceSurfaceKind": mention["SourceSurfaceKind"],
                    "SourceCellIndex": mention["SourceCellIndex"],
                    "SourceTextAtom": "",
                    "SourceTextDisplay": mention["SourceTextDisplay"],
                    "FullAnswerDisplay": f"{sequence}. {mention['DateDisplay']}: {mention['EventDisplay']}",
                    "SupportClass": "deterministic-source-record-summary",
                }
            )
            sequence += 1
    if not support_rows:
        return None
    if structured_intent is not None:
        support_rows.sort(key=_source_record_dated_event_inventory_sort_key)
        for index, row in enumerate(support_rows, start=1):
            row["SequenceIndex"] = str(index)
            row["FullAnswerDisplay"] = f"{index}. {row['EventDateDisplay']}: {row['EventDisplay']}"
    reasoning_basis = {
        "kind": "core-local",
        "note": (
            "query-only dated-event inventory support listed date mentions in admitted source-record "
            "row order; no durable event fact was written"
        ),
        "activation": "structured_query_intent" if structured_intent is not None else "raw_inventory_question",
    }
    if raw_inventory_trigger:
        reasoning_basis["utterance"] = utterance
    if structured_intent is not None:
        reasoning_basis["query_intent"] = structured_intent
    summary = {
        "SupportKind": "source_record_dated_event_inventory_summary",
        "SourceRow": "source_record_dated_event_inventory",
        "EventCount": str(len(support_rows)),
        "SequenceDisplay": "; ".join(row["FullAnswerDisplay"] for row in support_rows),
        "SupportClass": "deterministic-source-record-summary",
    }
    rows = [*support_rows, summary]
    return {
        "query": "source_record_dated_event_inventory_support(SequenceIndex, EventDate, EventAtom, SourceRow).",
        "result": {
            "status": "success",
            "predicate": "source_record_dated_event_inventory_support",
            "prolog_query": "source_record_dated_event_inventory_support(SequenceIndex, EventDate, EventAtom, SourceRow).",
            "result_type": "table",
            "num_rows": len(rows),
            "variables": _row_variable_names(rows),
            "rows": rows[:120],
            "reasoning_basis": reasoning_basis,
        },
        "derived_from_queries": [
            "source_record_text_atom(SourceRow, TextAtom).",
            "source_record_text_display(SourceRow, Text).",
            "source_record_cell_display(SourceRow, CellIndex, Text).",
        ],
    }


def _source_record_dated_event_inventory_sort_key(row: dict[str, str]) -> tuple[int, int, int, int, tuple[int, int], str]:
    event_date = str(row.get("EventDate", "")).strip()
    full_key = _date_atom_sort_key(event_date)
    if full_key is not None:
        return (*full_key, 0, _source_row_sort_key(row.get("SourceRow", "")), row.get("EventDisplay", ""))
    match = re.fullmatch(r"(?P<year>(?:19|20)\d{2})_(?P<month>\d{2})", event_date)
    if match:
        return (
            int(match.group("year")),
            int(match.group("month")),
            0,
            0,
            _source_row_sort_key(row.get("SourceRow", "")),
            row.get("EventDisplay", ""),
        )
    return (9999, 99, 99, 1, _source_row_sort_key(row.get("SourceRow", "")), row.get("EventDisplay", ""))


def _source_record_dated_event_inventory_intent(
    query_intents: list[dict[str, Any]] | None,
) -> dict[str, Any] | None:
    for intent in query_intents or []:
        if not isinstance(intent, dict):
            continue
        intent_type = str(intent.get("intent_type", "")).strip()
        constraints = {
            token
            for value in intent.get("answer_constraints", []) or []
            for token in _query_atom_tokens(str(value))
        }
        if intent_type != "ordered_labeled_entry" and not (
            "chronology" in intent_type or "chronological" in constraints
        ):
            continue
        targets = [str(item or "").strip() for item in intent.get("target_terms", []) or [] if str(item or "").strip()]
        if len(targets) >= 2:
            return intent
    return None


def _source_record_display_date_inventory_mentions(runtime: CorePrologRuntime) -> list[dict[str, str]]:
    out: list[dict[str, str]] = []
    seen: set[tuple[str, str, str]] = set()
    default_year = _source_record_runtime_default_year(runtime)
    for source_row, surface_kind, cell_index, display in sorted(
        _source_record_display_surfaces(runtime),
        key=lambda item: (_source_row_sort_key(item[0]), item[1], item[2]),
    ):
        if surface_kind not in {"source_record_text_display", "source_record_cell_display"}:
            continue
        text = unicodedata.normalize("NFKC", str(display or "")).strip()
        if not text or len(text) > 1200:
            continue
        for mention in _source_record_display_date_mentions(text, default_year=default_year):
            key = (source_row, surface_kind, mention["DateDisplay"])
            if key in seen:
                continue
            seen.add(key)
            event_display = str(mention.get("EventDisplay") or text).strip() or text
            out.append(
                {
                    "SourceRow": source_row,
                    "SourceSurfaceKind": surface_kind,
                    "SourceCellIndex": cell_index,
                    "DateAtom": mention["DateAtom"],
                    "DateDisplay": mention["DateDisplay"],
                    "EventAtom": _normalize_text_filter_atom(event_display)[:160],
                    "EventDisplay": event_display,
                    "SourceTextDisplay": text,
                }
            )
    return out


def _source_record_display_date_mentions(text: str, *, default_year: str = "") -> list[dict[str, str]]:
    mentions: list[dict[str, str]] = []
    seen: set[tuple[int, str]] = set()
    occupied: list[tuple[int, int]] = []

    def overlaps(start: int, end: int) -> bool:
        return any(left < end and start < right for left, right in occupied)

    for match in re.finditer(r"(?<!\d)(?P<year>(?:19|20)\d{2})[-_/](?P<month>\d{1,2})[-_/](?P<day>\d{1,2})(?!\d)", text):
        year = match.group("year")
        month = match.group("month").lstrip("0") or "0"
        day = match.group("day").lstrip("0") or "0"
        key = (match.start(), f"{year}_{month}_{day}")
        if key in seen:
            continue
        seen.add(key)
        mentions.append(
            {
                "DateAtom": f"{year}_{month.zfill(2)}_{day.zfill(2)}",
                "DateDisplay": match.group(0),
                "EventDisplay": _source_record_display_date_context(text, match.start(), match.end()),
                "OccurrenceStart": str(match.start()),
            }
        )
        occupied.append((match.start(), match.end()))
    month_pattern = "|".join(re.escape(month) for month in _SOURCE_MONTHS)
    month_day_year = re.compile(
        rf"(?<![A-Za-z0-9])(?P<month>{month_pattern})\s+"
        r"(?P<day>[0-3]?\d)(?:st|nd|rd|th)?[,]?\s+"
        r"(?P<year>(?:19|20)\d{2})(?!\d)",
        flags=re.IGNORECASE | re.UNICODE,
    )
    for match in month_day_year.finditer(text):
        if overlaps(match.start(), match.end()):
            continue
        month_name = match.group("month").casefold()
        month_number = _SOURCE_MONTHS.get(month_name, "")
        if not month_number:
            continue
        day = int(match.group("day"))
        if day < 1 or day > 31:
            continue
        snippet = re.sub(r"\s+", " ", match.group(0)).strip(" ,.;:")
        key = (match.start(), snippet.casefold())
        if key in seen:
            continue
        seen.add(key)
        mentions.append(
            {
                "DateAtom": f"{match.group('year')}_{month_number}_{day:02d}",
                "DateDisplay": snippet,
                "EventDisplay": _source_record_display_date_context(text, match.start(), match.end()),
                "OccurrenceStart": str(match.start()),
            }
        )
        occupied.append((match.start(), match.end()))
    day_month_year = re.compile(
        rf"(?<![A-Za-z0-9])(?P<day>[0-3]?\d)(?:st|nd|rd|th)?\s+"
        rf"(?P<month>{month_pattern})\s+(?P<year>(?:19|20)\d{{2}})(?!\d)",
        flags=re.IGNORECASE | re.UNICODE,
    )
    for match in day_month_year.finditer(text):
        if overlaps(match.start(), match.end()):
            continue
        month_name = match.group("month").casefold()
        month_number = _SOURCE_MONTHS.get(month_name, "")
        if not month_number:
            continue
        day = int(match.group("day"))
        if day < 1 or day > 31:
            continue
        snippet = re.sub(r"\s+", " ", match.group(0)).strip(" ,.;:")
        key = (match.start(), snippet.casefold())
        if key in seen:
            continue
        seen.add(key)
        mentions.append(
            {
                "DateAtom": f"{match.group('year')}_{month_number}_{day:02d}",
                "DateDisplay": snippet,
                "EventDisplay": _source_record_display_date_context(text, match.start(), match.end()),
                "OccurrenceStart": str(match.start()),
            }
        )
        occupied.append((match.start(), match.end()))
    month_day = re.compile(
        rf"(?<![A-Za-z0-9])(?P<month>{month_pattern})\s+"
        r"(?P<day>[0-3]?\d)(?:st|nd|rd|th)?(?!\s*[,]?\s*(?:19|20)\d{2})(?![A-Za-z0-9])",
        flags=re.IGNORECASE | re.UNICODE,
    )
    for match in month_day.finditer(text):
        if overlaps(match.start(), match.end()):
            continue
        month_name = match.group("month").casefold()
        month_number = _SOURCE_MONTHS.get(month_name, "")
        if not month_number:
            continue
        day = int(match.group("day"))
        if day < 1 or day > 31:
            continue
        snippet = re.sub(r"\s+", " ", match.group(0)).strip(" ,.;:")
        key = (match.start(), snippet.casefold())
        if key in seen:
            continue
        seen.add(key)
        year_prefix = f"{int(default_year):04d}_" if str(default_year).isdigit() else ""
        mentions.append(
            {
                "DateAtom": f"{year_prefix}{month_number}_{day:02d}" if year_prefix else f"month_day_{month_number}_{day:02d}",
                "DateDisplay": snippet,
                "EventDisplay": _source_record_display_date_context(text, match.start(), match.end()),
                "OccurrenceStart": str(match.start()),
            }
        )
        occupied.append((match.start(), match.end()))
    month_year = re.compile(
        rf"(?<![A-Za-z0-9])(?P<month>{month_pattern})\s+(?P<year>(?:19|20)\d{{2}})(?!\d)",
        flags=re.IGNORECASE | re.UNICODE,
    )
    for match in month_year.finditer(text):
        if overlaps(match.start(), match.end()):
            continue
        month_name = match.group("month").casefold()
        month_number = _SOURCE_MONTHS.get(month_name, "")
        if not month_number:
            continue
        snippet = re.sub(r"\s+", " ", match.group(0)).strip(" ,.;:")
        key = (match.start(), snippet.casefold())
        if key in seen:
            continue
        seen.add(key)
        mentions.append(
            {
                "DateAtom": f"{match.group('year')}_{month_number}",
                "DateDisplay": snippet,
                "EventDisplay": _source_record_display_date_context(text, match.start(), match.end()),
                "OccurrenceStart": str(match.start()),
            }
        )
        occupied.append((match.start(), match.end()))
    text_date_pattern = re.compile(
        r"(?<![A-Za-z0-9])(?P<day>[0-3]?\d)(?![A-Za-z0-9])"
        r"(?P<middle>[^\d]{1,48}?)"
        r"(?P<year>(?:19|20)\d{2})(?!\d)",
        flags=re.UNICODE,
    )
    for match in text_date_pattern.finditer(text):
        if overlaps(match.start(), match.end()):
            continue
        day = int(match.group("day"))
        if day < 1 or day > 31:
            continue
        middle = match.group("middle")
        if not re.search(r"[^\W\d_]", middle, flags=re.UNICODE):
            continue
        middle_text = middle.casefold()
        if "and between" in middle_text:
            continue
        if not (
            re.search(rf"\b(?:{month_pattern})\b", middle, flags=re.IGNORECASE)
            or re.search(r"\bof\s+[^\W\d_]+", middle, flags=re.UNICODE)
        ):
            continue
        if re.search(r"[-_/]{2,}", middle):
            continue
        snippet = re.sub(r"\s+", " ", match.group(0)).strip(" ,.;:")
        key = (match.start(), snippet.casefold())
        if key in seen:
            continue
        seen.add(key)
        mentions.append(
            {
                "DateAtom": f"{match.group('year')}_day_{day:02d}",
                "DateDisplay": snippet,
                "EventDisplay": _source_record_display_date_context(text, match.start(), match.end()),
                "OccurrenceStart": str(match.start()),
            }
        )
    mentions.sort(key=lambda item: int(item.get("OccurrenceStart", "0") or "0"))
    return mentions


def _source_record_display_date_context(text: str, start: int, end: int, *, max_chars: int = 420) -> str:
    value = unicodedata.normalize("NFKC", str(text or ""))
    if not value:
        return ""
    start = max(0, min(start, len(value)))
    end = max(start, min(end, len(value)))
    left_candidates = [value.rfind(mark, 0, start) for mark in ("\n", ";", ".")]
    left = max(left_candidates)
    right_candidates = [pos for mark in ("\n", ";", ".") if (pos := value.find(mark, end)) >= 0]
    right = min(right_candidates) + 1 if right_candidates else len(value)
    context = re.sub(r"\s+", " ", value[left + 1 : right]).strip(" -\t\r\n")
    if len(context) <= max_chars:
        return context

    left_window = value[max(0, start - max_chars // 2) : start]
    right_window = value[end : min(len(value), end + max_chars // 2)]
    context = f"{left_window}{value[start:end]}{right_window}"
    context = re.sub(r"\s+", " ", context).strip(" -\t\r\n")
    if len(context) <= max_chars:
        return context
    overflow = len(context) - max_chars
    trim_left = overflow // 2
    trim_right = overflow - trim_left
    context = context[trim_left : len(context) - trim_right].strip(" -\t\r\n")
    return context


def _source_record_dated_event_skip_row(*, source_row: str, atom: str, kind: str) -> bool:
    if str(kind) == "heading":
        return True
    if re.match(r"^v_\d+(?:_\d+)?_", atom):
        return True
    if _source_row_sort_key(source_row)[0] <= 1:
        return True
    return False


def _source_record_dated_event_mentions(atom: str) -> list[dict[str, str]]:
    text = _normalize_text_filter_atom(atom)
    mentions: list[dict[str, str]] = []
    occupied: list[tuple[int, int]] = []
    duration_pattern = (
        r"(?P<duration>(?:seven_business_days|twenty_four_24_months|twenty_four_months)_from_"
        r"(?P<date>(?:january|february|march|april|may|june|july|august|september|october|november|december)_"
        r"\d{1,2}_\d{4}))"
    )
    for match in re.finditer(duration_pattern, text):
        duration = match.group("duration")
        date_atom = match.group("date")
        event_atom = _source_record_dated_event_window(text, match.start(), match.end())
        mentions.append(
            {
                "DateAtom": duration,
                "DateDisplay": _display_source_phrase(duration),
                "EventAtom": event_atom,
                "EventDisplay": _display_source_phrase(event_atom),
                "OccurrenceStart": str(match.start()),
            }
        )
        occupied.append((match.start(), match.end()))
    full_date_pattern = (
        r"(?P<date>(?:january|february|march|april|may|june|july|august|september|october|november|december)_"
        r"\d{1,2}_\d{4})"
    )
    for match in re.finditer(full_date_pattern, text):
        if any(start <= match.start() < end for start, end in occupied):
            continue
        if _source_record_dated_event_date_is_duration_tail(text, match.start()):
            continue
        date_atom = match.group("date")
        event_atom = _source_record_dated_event_window(text, match.start(), match.end())
        mentions.append(
            {
                "DateAtom": date_atom,
                "DateDisplay": _display_source_phrase(date_atom),
                "EventAtom": event_atom,
                "EventDisplay": _display_source_phrase(event_atom),
                "OccurrenceStart": str(match.start()),
            }
        )
    month_year_pattern = r"(?P<date>(?:january|february|march|april|may|june|july|august|september|october|november|december)_\d{4})"
    for match in re.finditer(month_year_pattern, text):
        if re.match(r"_\d{1,2}", text[match.end() :]):
            continue
        date_atom = match.group("date")
        event_atom = _source_record_dated_event_window(text, match.start(), match.end())
        if not re.search(r"(?:^|_)(?:since|served|appointed|effective|issued|executed|notified)(?:_|$)", event_atom):
            continue
        mentions.append(
            {
                "DateAtom": date_atom,
                "DateDisplay": _display_source_phrase(date_atom),
                "EventAtom": event_atom,
                "EventDisplay": _display_source_phrase(event_atom),
                "OccurrenceStart": str(match.start()),
            }
        )
    mentions.sort(key=lambda item: int(item.get("OccurrenceStart", "0") or "0"))
    return mentions


def _source_record_dated_event_date_is_duration_tail(text: str, start: int) -> bool:
    prefix = text[max(0, start - 40) : start]
    return bool(re.search(r"(?:seven_business_days|twenty_four_24_months|twenty_four_months)_from_$", prefix))


def _source_record_dated_event_window(text: str, start: int, end: int, *, before: int = 14, after: int = 24) -> str:
    tokens = [token for token in _normalize_text_filter_atom(text).split("_") if token]
    prefix = text[:start]
    token_index = len([token for token in prefix.split("_") if token])
    value_token_count = len([token for token in text[start:end].split("_") if token])
    left = max(0, token_index - before)
    right = min(len(tokens), token_index + value_token_count + after)
    window = "_".join(tokens[left:right])
    return _source_record_dated_event_trim_window(window)


def _source_record_dated_event_trim_window(value: str) -> str:
    text = _normalize_text_filter_atom(value).strip("_")
    text = re.sub(r"^(?:and|or|the|a|an)_", "", text)
    return text


def _source_record_negative_assertion_companion(
    runtime: CorePrologRuntime,
    *,
    utterance: str,
) -> dict[str, Any] | None:
    text = str(utterance or "").casefold()
    if not _source_record_negative_assertion_question(text):
        return None

    text_atoms = sorted(_source_record_text_atoms(runtime), key=lambda item: _source_row_sort_key(item[0]))
    support_rows: list[dict[str, str]] = []
    seen: set[tuple[str, str]] = set()
    for index, (source_row, _text_atom) in enumerate(text_atoms):
        row_window = text_atoms[index : index + 4]
        if not row_window:
            continue
        window_text = "_".join(_normalize_text_filter_atom(atom) for _row, atom in row_window if atom)
        window_sources = [row for row, _atom in row_window if row]
        for assertion in _source_record_negative_assertions_from_text(window_text):
            key = (assertion["AssertionKind"], assertion["SubjectAtom"])
            if key in seen:
                continue
            seen.add(key)
            support_rows.append(
                {
                    "SupportKind": "source_record_negative_assertion",
                    "AssertionKind": assertion["AssertionKind"],
                    "SubjectAtom": assertion["SubjectAtom"],
                    "SubjectDisplay": _display_source_phrase(assertion["SubjectAtom"]),
                    "AssertionAtom": assertion["AssertionAtom"],
                    "AssertionDisplay": assertion["AssertionDisplay"],
                    "SourceRows": ",".join(window_sources[:4]),
                    "SourceTextAtom": window_text,
                    "SourceTextDisplay": _display_source_phrase(window_text),
                    "FullAnswerDisplay": assertion["AssertionDisplay"],
                    "SupportClass": "deterministic-source-record-summary",
                }
            )
    if not support_rows:
        return None
    support_rows.sort(
        key=lambda row: (
            _source_row_sort_key(row.get("SourceRows", "").split(",", 1)[0]),
            _source_record_negative_assertion_sort_key(row.get("AssertionKind", "")),
        )
    )
    summary = {
        "SupportKind": "source_record_negative_assertion_summary",
        "SourceRow": "source_record_negative_assertions",
        "AssertionCount": str(len(support_rows)),
        "AssertionsDisplay": "; ".join(row["FullAnswerDisplay"] for row in support_rows),
        "SupportClass": "deterministic-source-record-summary",
    }
    rows = [*support_rows, summary]
    return {
        "query": "source_record_negative_assertion_support(AssertionKind, Subject, AssertionAtom, SourceRows).",
        "result": {
            "status": "success",
            "predicate": "source_record_negative_assertion_support",
            "prolog_query": "source_record_negative_assertion_support(AssertionKind, Subject, AssertionAtom, SourceRows).",
            "result_type": "table",
            "num_rows": len(rows),
            "variables": _row_variable_names(rows),
            "rows": rows[:80],
            "reasoning_basis": {
                "kind": "core-local",
                "note": (
                    "query-only negative-assertion support grouped source-stated no/does-not disclosure "
                    "claims from admitted source-record text; no durable absence fact was written"
                ),
                "utterance": utterance,
            },
        },
        "derived_from_queries": ["source_record_text_atom(SourceRow, TextAtom)."],
    }


_CURRENT_ADJUDICATION_INTENT_TYPES = {
    "status",
    "premise_check",
    "verification",
    "verify",
    "decision",
    "classification",
}

_CURRENT_ADJUDICATION_PREDICATES = {
    "case_metadata",
    "procedural_step",
    "order_annulment",
    "order_injunction",
    "cited_article",
    "article_applied_to",
}


def _current_adjudication_disposition_companion(
    runtime: CorePrologRuntime,
    *,
    query_intents: list[dict[str, Any]] | None = None,
) -> dict[str, Any] | None:
    if not _current_adjudication_intent_active(query_intents):
        return None
    predicate_names = {str(fact.get("predicate", "")).strip() for fact in _runtime_fact_rows(runtime)}
    if "procedural_step" not in predicate_names:
        return None
    if not (predicate_names & (_CURRENT_ADJUDICATION_PREDICATES - {"case_metadata", "procedural_step"})):
        return None

    case_rows = _current_adjudication_case_rows(runtime)
    step_rows = _current_adjudication_step_rows(runtime)
    order_rows = _current_adjudication_order_rows(runtime)
    article_rows = _current_adjudication_article_rows(runtime)
    if not any((case_rows, step_rows, order_rows, article_rows)):
        return None

    latest_case_date = _latest_date_atom(row.get("CaseDate", "") for row in case_rows)
    latest_step_date = _latest_date_atom(row.get("StepDate", "") for row in step_rows)
    latest_steps = [row for row in step_rows if row.get("StepDate") == latest_step_date] if latest_step_date else []
    for row in step_rows:
        row["ChronologyRole"] = "latest_procedural_step" if row.get("StepDate") == latest_step_date else "prior_procedural_step"
        if latest_case_date and row.get("StepDate") == latest_case_date:
            row["CaseDateRole"] = "matches_case_metadata_date"

    summary = {
        "SupportKind": "current_adjudication_disposition_summary",
        "SupportClass": "deterministic-adjudication-summary",
        "CaseDates": ",".join(_ordered_atom_unique([row.get("CaseDate", "") for row in case_rows if row.get("CaseDate")])),
        "LatestCaseDate": latest_case_date,
        "LatestCaseDateDisplay": _display_source_date_atom(latest_case_date) if latest_case_date else "",
        "LatestStepDate": latest_step_date,
        "LatestStepDateDisplay": _display_source_date_atom(latest_step_date) if latest_step_date else "",
        "LatestStepIds": ",".join(row.get("StepID", "") for row in latest_steps if row.get("StepID")),
        "LatestStepOutcomes": ",".join(_ordered_atom_unique([row.get("Outcome", "") for row in latest_steps if row.get("Outcome")])),
        "OrderPredicates": ",".join(_ordered_atom_unique([row.get("SourcePredicate", "") for row in order_rows if row.get("SourcePredicate")])),
        "LegalBasisArticles": ",".join(_ordered_atom_unique([row.get("Article", "") for row in article_rows if row.get("Article")])),
        "LegalBasisApplications": ",".join(_ordered_atom_unique([row.get("Application", "") for row in article_rows if row.get("Application")])),
    }
    sorted_steps = sorted(
        step_rows,
        key=lambda row: (_reverse_date_sort_key(row.get("StepDate", "")), row.get("StepID", "")),
    )[:14]
    sorted_articles = sorted(article_rows, key=_current_adjudication_article_sort_key)[:40]
    rows = [
        summary,
        *sorted(case_rows, key=lambda row: _reverse_date_sort_key(row.get("CaseDate", ""))),
        *sorted_steps,
        *order_rows,
        *sorted_articles,
    ]
    return {
        "query": "current_adjudication_disposition_support(SupportKind, SourcePredicate, Subject, Value).",
        "result": {
            "status": "success",
            "predicate": "current_adjudication_disposition_support",
            "prolog_query": "current_adjudication_disposition_support(SupportKind, SourcePredicate, Subject, Value).",
            "result_type": "table",
            "num_rows": len(rows),
            "variables": _row_variable_names(rows),
            "rows": rows[:96],
            "reasoning_basis": {
                "kind": "core-local",
                "note": (
                    "query-only current-adjudication disposition support inventoried admitted "
                    "case metadata, procedural steps, order rows, cited articles, and article "
                    "applications for status/premise questions; no durable fact was written"
                ),
                "query_intents": query_intents or [],
            },
        },
        "derived_from_queries": [
            "case_metadata(Case, Court, Date, Identifier, Type).",
            "procedural_step(Step, Court, Date, Type, Outcome).",
            "order_annulment(Order, Act).",
            "order_injunction(Order, Recipient, Obligation).",
            "cited_article(Article, Code).",
            "article_applied_to(Article, Subject, Application).",
            "source_record_text_atom(SourceRow, TextAtom).",
            "source_record_text_display(SourceRow, TextDisplay).",
        ],
    }


def _current_adjudication_intent_active(query_intents: list[dict[str, Any]] | None) -> bool:
    for intent in query_intents or []:
        if not isinstance(intent, dict):
            continue
        intent_type = str(intent.get("intent_type", "")).strip().casefold()
        if intent_type in _CURRENT_ADJUDICATION_INTENT_TYPES:
            return True
    return False


def _current_adjudication_case_rows(runtime: CorePrologRuntime) -> list[dict[str, str]]:
    out: list[dict[str, str]] = []
    for row in _runtime_rows(runtime, "case_metadata(Case, Court, Date, Identifier, Type)."):
        out.append(
            {
                "SupportKind": "case_metadata",
                "SupportClass": "deterministic-adjudication-summary",
                "SourcePredicate": "case_metadata",
                "CaseID": str(row.get("Case", "")),
                "Court": str(row.get("Court", "")),
                "CourtDisplay": _display_source_phrase(row.get("Court", "")),
                "CaseDate": str(row.get("Date", "")),
                "CaseDateDisplay": _display_source_date_atom(str(row.get("Date", ""))),
                "Identifier": str(row.get("Identifier", "")),
                "MatterType": str(row.get("Type", "")),
                "MatterTypeDisplay": _display_source_phrase(row.get("Type", "")),
            }
        )
    return _dedupe_current_adjudication_rows(out)


