def _source_record_dated_event_inventory_reference_supported_by_results(
    *,
    row: dict[str, Any],
    reference: str,
) -> bool:
    reference_text = unicodedata.normalize("NFKC", str(reference or "")).strip()
    reference_dates = _source_record_display_date_mentions(reference_text)
    if len(reference_dates) < 2:
        return False
    display_values: list[str] = []
    sequence_values: list[str] = []
    for query_result in row.get("query_results", []) or []:
        result = query_result.get("result") if isinstance(query_result, dict) else None
        if not isinstance(result, dict):
            continue
        if str(result.get("predicate", "")).strip() != "source_record_dated_event_inventory_support":
            continue
        for result_row in result.get("rows") or []:
            if not isinstance(result_row, dict):
                continue
            if str(result_row.get("SupportKind", "")) == "source_record_dated_event_inventory_item":
                sequence_display = _display_source_phrase(result_row.get("EventDateDisplay") or "")
                if sequence_display:
                    sequence_values.append(sequence_display)
            for value in _iter_scalar_values(result_row):
                displayed = _display_source_phrase(value)
                if displayed:
                    display_values.append(displayed)
    if not display_values:
        return False
    value_text = " ".join(display_values)
    value_tokens = _loose_atom_token_set(value_text)
    sequence_text = " ".join(sequence_values or display_values)
    if not _dated_event_reference_date_sequence_supported(value_text=sequence_text, reference_dates=reference_dates):
        return False
    for mention in reference_dates:
        date_tokens = _without_source_reference_stop_tokens(_loose_atom_token_set(mention["DateDisplay"]))
        if not date_tokens:
            continue
        if not _date_reference_supported(reference_tokens=date_tokens, value_tokens=value_tokens):
            return False
    reference_identifiers = _dated_event_reference_identifiers(reference_text)
    if reference_identifiers and not reference_identifiers.issubset(_dated_event_reference_identifiers(value_text)):
        return False
    reference_tokens = _without_source_reference_stop_tokens(_loose_atom_token_set(reference_text))
    if len(reference_tokens) < 6:
        return False
    covered = len(reference_tokens & value_tokens)
    return covered / len(reference_tokens) >= 0.85


def _dated_event_reference_date_sequence_supported(
    *,
    value_text: str,
    reference_dates: list[dict[str, str]],
) -> bool:
    haystack = unicodedata.normalize("NFKC", str(value_text or "")).casefold()
    cursor = 0
    for mention in reference_dates:
        needle = unicodedata.normalize("NFKC", str(mention.get("DateDisplay", "") or "")).casefold()
        if not needle:
            continue
        index = haystack.find(needle, cursor)
        if index < 0:
            return False
        cursor = index + len(needle)
    return True


def _dated_event_reference_identifiers(value: str) -> set[str]:
    return {
        re.sub(r"[^a-z0-9]+", "", match.group(0).casefold())
        for match in re.finditer(
            r"\b(?=[A-Za-z0-9._/-]*[A-Za-z])(?=[A-Za-z0-9._/-]*\d)[A-Za-z0-9]+(?:[-_/][A-Za-z0-9]+)+\b",
            str(value or ""),
        )
    }


def _source_record_parenthetical_role_name_reference_supported_by_results(
    *,
    row: dict[str, Any],
    reference: str,
) -> bool:
    chunks = _parenthetical_role_name_reference_chunks(reference)
    if not chunks:
        return False
    entries: list[dict[str, str]] = []
    entry_count = 0
    for query_result in row.get("query_results", []) or []:
        result = query_result.get("result") if isinstance(query_result, dict) else None
        if not isinstance(result, dict):
            continue
        if str(result.get("predicate", "")).strip() != "source_record_parenthetical_role_name_support":
            continue
        for result_row in result.get("rows") or []:
            if not isinstance(result_row, dict):
                continue
            if str(result_row.get("SupportKind", "")) == "source_record_parenthetical_role_name_summary":
                entry_count = max(entry_count, _safe_int(result_row.get("EntryCount")) or 0)
                continue
            person = str(result_row.get("PersonDisplay", "")).strip()
            entity = str(result_row.get("EntityDisplay", "")).strip()
            if not person or not entity:
                continue
            entries.append(
                {
                    "PersonDisplay": person,
                    "EntityDisplay": entity,
                    "ParentheticalRemainderDisplay": str(
                        result_row.get("ParentheticalRemainderDisplay", "")
                    ).strip(),
                }
            )
    if not entries:
        return False
    if len(chunks) > len(entries):
        return False
    if len(chunks) < 2 and (entry_count or len(entries)) > 1:
        return False
    matched_entry_indexes: set[int] = set()
    for chunk in chunks:
        matched_index = None
        for index, entry in enumerate(entries):
            if index in matched_entry_indexes:
                continue
            if _parenthetical_role_name_reference_chunk_matches_entry(chunk, entry):
                matched_index = index
                break
        if matched_index is None:
            return False
        matched_entry_indexes.add(matched_index)
    return True


def _parenthetical_role_name_reference_chunks(reference: str) -> list[dict[str, Any]]:
    chunks = re.split(r"[;\n\r]+", str(reference or ""))
    out: list[dict[str, Any]] = []
    for chunk in chunks:
        display = _display_source_phrase(chunk).strip(" .")
        compact = _compact_unicode_reference_text(display)
        if len(compact) < 3:
            continue
        if not any(char.isalpha() and not char.isascii() for char in compact):
            continue
        out.append(
            {
                "display": display,
                "compact": compact,
                "ascii_tokens": {
                    token.casefold()
                    for token in re.findall(r"[A-Za-z0-9]{2,}", display)
                    if token.casefold() not in {"and", "the"}
                },
                "non_ascii_chars": {
                    char for char in compact if char.isalpha() and not char.isascii()
                },
            }
        )
    return out


def _parenthetical_role_name_reference_chunk_matches_entry(
    chunk: dict[str, Any],
    entry: dict[str, str],
) -> bool:
    chunk_compact = str(chunk.get("compact", ""))
    person_compact = _compact_unicode_reference_text(entry.get("PersonDisplay", ""))
    if len(person_compact) < 2 or person_compact not in chunk_compact:
        return False
    entity_compact = _compact_unicode_reference_text(
        " ".join(
            part
            for part in [
                entry.get("EntityDisplay", ""),
                entry.get("ParentheticalRemainderDisplay", ""),
            ]
            if part
        )
    )
    entity_reference_compact = chunk_compact.replace(person_compact, "")
    if len(entity_reference_compact) < 2:
        return True
    if entity_reference_compact in entity_compact or entity_compact in entity_reference_compact:
        return True
    ascii_tokens = set(chunk.get("ascii_tokens") or set())
    ascii_ok = not ascii_tokens or any(token in entity_compact for token in ascii_tokens)
    non_ascii_entity_chars = {
        char for char in entity_reference_compact if char.isalpha() and not char.isascii()
    }
    non_ascii_ok = not non_ascii_entity_chars or len(non_ascii_entity_chars & set(entity_compact)) >= min(
        2,
        len(non_ascii_entity_chars),
    )
    return ascii_ok and non_ascii_ok


def _source_record_label_value_pair_reference_supported_by_results(
    *,
    row: dict[str, Any],
    reference: str,
) -> bool:
    reference_tokens = _loose_atom_token_set(_display_source_phrase(reference))
    utterance_tokens = _loose_atom_token_set(_display_source_phrase(row.get("utterance", "")))
    if not reference_tokens:
        return False
    for query_result in row.get("query_results", []) or []:
        result = query_result.get("result") if isinstance(query_result, dict) else None
        if not isinstance(result, dict):
            continue
        if str(result.get("predicate", "")).strip() != "source_record_label_value_pair_support":
            continue
        for result_row in result.get("rows") or []:
            if not isinstance(result_row, dict):
                continue
            field_tokens = _loose_atom_token_set(
                _display_source_phrase(
                    result_row.get("FieldDisplay")
                    or result_row.get("Field")
                    or ""
                )
            )
            value_tokens = _without_source_reference_stop_tokens(
                _loose_atom_token_set(
                    _display_source_phrase(
                        result_row.get("ValueDisplay")
                        or result_row.get("Value")
                        or ""
                    )
                )
            )
            value_tokens = {token for token in value_tokens if len(token) >= 3}
            if len(value_tokens) < 4:
                continue
            if field_tokens and not (field_tokens & (reference_tokens | utterance_tokens)):
                continue
            matched = value_tokens & reference_tokens
            if len(matched) >= max(4, math.ceil(len(value_tokens) * 0.8)):
                return True
    return False


def _source_record_summary_reference_supported_by_results(
    *,
    row: dict[str, Any],
    reference: str,
    predicates: set[str],
) -> bool:
    reference_display = _display_source_phrase(str(reference or "").strip())
    reference_tokens = _without_source_reference_stop_tokens(_loose_atom_token_set(reference))
    reference_tokens = {
        token
        for token in reference_tokens
        if token
        not in {
            "report",
            "according",
            "stated",
            "states",
            "however",
            "either",
            "note",
            "notes",
            "indicate",
            "indicates",
            "show",
            "shows",
            "does",
            "doe",
            "did",
            "value",
            "values",
            "two",
            "exception",
            "exceptions",
            "but",
        }
        and not token.isdigit()
    }
    if len(reference_tokens) < 4:
        return False
    for query_result in row.get("query_results", []) or []:
        result = query_result.get("result") if isinstance(query_result, dict) else None
        if not isinstance(result, dict):
            continue
        if str(result.get("predicate", "")).strip() not in predicates:
            continue
        rows = result.get("rows") if isinstance(result, dict) else None
        row_tokens: set[str] = set()
        row_values: list[str] = []
        for result_row in rows or []:
            for value in _iter_scalar_values(result_row):
                displayed = _display_source_phrase(value)
                row_values.append(displayed)
                row_tokens.update(_loose_atom_token_set(displayed))
        if _unicode_reference_fragments_supported(
            value=" ".join(row_values),
            reference_display=reference_display,
        ):
            return True
        if reference_tokens.issubset(row_tokens):
            return True
    return False


def _utterance_asks_for_count(utterance: str) -> bool:
    text = str(utterance or "").casefold()
    return bool(re.search(r"\b(?:how many|number of|count of|total(?: number)? of)\b", text))


def _reference_count_tokens(reference: str) -> set[str]:
    first_phrase = re.split(r"[—;,.()]", str(reference or "").casefold(), maxsplit=1)[0]
    raw_tokens = {token for token in re.split(r"[^a-z0-9]+", first_phrase) if token}
    if not raw_tokens:
        return set()
    for aliases in _COUNT_REFERENCE_CANONICALS.values():
        if raw_tokens & aliases:
            return set(aliases)
    return set()


def _count_scope_tokens(utterance: str) -> set[str]:
    stop = {
        "the",
        "that",
        "this",
        "what",
        "which",
        "whose",
        "how",
        "many",
        "number",
        "count",
        "total",
        "did",
        "does",
        "were",
        "was",
        "are",
        "for",
        "from",
        "with",
        "and",
        "at",
        "in",
        "on",
    }
    tokens = {
        token
        for token in _query_atom_tokens(utterance)
        if len(token) >= 4 and token not in stop and not token.isdigit()
    }
    singulars = {token[:-1] for token in tokens if token.endswith("s") and len(token) > 4}
    return tokens | singulars


def _source_record_reference_supported_by_results(*, row: dict[str, Any], reference: str) -> bool:
    reference_display = _display_source_phrase(str(reference or "").strip())
    if not reference_display or reference_display in {"yes", "no", "not", "none", "false", "true"}:
        return False
    reference_tokens = _loose_atom_token_set(reference_display)
    reference_tokens = _without_source_reference_stop_tokens(reference_tokens)
    if len(reference_tokens) < 2 and len(reference_display) < 4:
        return False
    for query_result in row.get("query_results", []) or []:
        result = query_result.get("result") if isinstance(query_result, dict) else None
        if not isinstance(result, dict):
            continue
        predicate = str(result.get("predicate", "")).strip()
        if predicate not in {
            "source_record_text_atom",
            "source_record_label",
            "source_record_text_display",
            "source_record_label_display",
            "source_record_section_display",
            "source_record_cell_display",
            "source_record_cell_header_display",
            "source_record_question_overlap_support",
            "source_record_semantic_target_display_support",
            "source_record_semantic_target_cell_value_support",
            "source_record_status_inline_field_support",
            "source_record_semantic_target_window_support",
            "source_record_count_breakdown_support",
            "source_record_identifier_set_support",
            "source_record_same_day_case_disposition_support",
            "source_record_address_line_support",
            "method_actor_frame_source_support",
        }:
            continue
        rows = result.get("rows") if isinstance(result, dict) else None
        for result_row in rows or []:
            for value in _iter_scalar_values(result_row):
                if _display_phrase_contains_reference(
                    value=value,
                    reference_display=reference_display,
                    reference_tokens=reference_tokens,
                ):
                    return True
    if _numeric_measure_reference_supported_by_display_results(
        row=row,
        reference_display=reference_display,
    ):
        return True
    return False


def _display_phrase_contains_reference(
    *,
    value: Any,
    reference_display: str,
    reference_tokens: set[str],
) -> bool:
    displayed = _display_source_phrase(str(value or ""))
    if not displayed:
        return False
    if reference_display and reference_display in displayed:
        return True
    if _unicode_reference_fragments_supported(value=displayed, reference_display=reference_display):
        return True
    value_tokens = _loose_atom_token_set(displayed)
    if _abbreviated_reference_supported(reference_tokens=reference_tokens, value_tokens=value_tokens):
        return True
    if _date_reference_supported(reference_tokens=reference_tokens, value_tokens=value_tokens):
        return True
    if _initialism_reference_supported(
        reference_tokens=reference_tokens,
        value_tokens=value_tokens,
        displayed=displayed,
    ):
        return True
    return bool(reference_tokens and reference_tokens.issubset(value_tokens))


def _numeric_measure_reference_supported_by_display_results(
    *,
    row: dict[str, Any],
    reference_display: str,
) -> bool:
    reference_numbers = _numeric_measure_surfaces(reference_display)
    if len(reference_numbers) < 2:
        return False
    display_values: list[str] = []
    for query_result in row.get("query_results", []) or []:
        result = query_result.get("result") if isinstance(query_result, dict) else None
        if not isinstance(result, dict) or result.get("status") != "success":
            continue
        predicate = str(result.get("predicate", "")).strip()
        if predicate not in {
            "source_record_semantic_target_display_support",
            "source_record_semantic_target_cell_value_support",
            "source_record_status_inline_field_support",
            "source_record_semantic_target_window_support",
            "source_record_count_breakdown_support",
        }:
            continue
        for result_row in result.get("rows") or []:
            if not isinstance(result_row, dict):
                continue
            for value in _iter_scalar_values(result_row):
                displayed = _display_source_phrase(value)
                if displayed:
                    display_values.append(displayed)
    if not display_values:
        return False
    display_numbers: set[str] = set()
    for value in display_values:
        display_numbers.update(_numeric_measure_surfaces(value))
    return bool(display_numbers) and reference_numbers <= display_numbers


def _numeric_measure_surfaces(value: str) -> set[str]:
    text = unicodedata.normalize("NFKC", str(value or ""))
    out: set[str] = set()
    for match in re.finditer(r"(?<!\d)[+-]?\d[\d,]*(?:\.\d+)?(?!\d)", text):
        raw = match.group(0)
        if "," not in raw and "." not in raw:
            continue
        normalized = raw.replace(",", "")
        try:
            if "." in normalized:
                normalized = normalized.rstrip("0").rstrip(".")
            if normalized in {"", "+", "-"}:
                continue
        except ValueError:
            continue
        out.add(normalized)
    return out


def _unicode_reference_fragments_supported(*, value: Any, reference_display: str) -> bool:
    reference_text = str(reference_display or "")
    if not _contains_non_ascii_letter(reference_text):
        return False
    value_compact = _compact_unicode_reference_text(str(value or ""))
    if not value_compact:
        return False
    fragments = _compact_unicode_reference_fragments(reference_text)
    if not fragments:
        return False
    return all(fragment in value_compact for fragment in fragments)


def _compact_unicode_reference_fragments(value: str) -> list[str]:
    chunks = re.split(r"(?:[+;,/]|->|→|=|\(|\)|\[|\]|\{|\}|:)", str(value or ""))
    out: list[str] = []
    seen: set[str] = set()
    for chunk in chunks:
        compact = _compact_unicode_reference_text(chunk)
        if len(compact) < 2:
            continue
        has_non_ascii = any(char.isalpha() and not char.isascii() for char in compact)
        has_digit = any(char.isdigit() for char in compact)
        if not has_non_ascii and not has_digit:
            continue
        if compact in seen:
            continue
        seen.add(compact)
        out.append(compact)
    return out


def _compact_unicode_reference_text(value: str) -> str:
    text = unicodedata.normalize("NFKC", str(value or "")).casefold()
    return "".join(char for char in text if char.isalnum())


def _iter_scalar_values(value: Any) -> list[str]:
    if isinstance(value, dict):
        values: list[str] = []
        for child in value.values():
            values.extend(_iter_scalar_values(child))
        return values
    if isinstance(value, list):
        values = []
        for child in value:
            values.extend(_iter_scalar_values(child))
        return values
    if value is None:
        return []
    return [str(value)]


def _abbreviated_reference_supported(*, reference_tokens: set[str], value_tokens: set[str]) -> bool:
    if {"central", "time", "ct"} <= reference_tokens and "ct" in value_tokens:
        return True
    return False


def _initialism_reference_supported(
    *,
    reference_tokens: set[str],
    value_tokens: set[str],
    displayed: str,
) -> bool:
    missing_tokens = {token for token in reference_tokens if token not in value_tokens}
    if not missing_tokens or len(missing_tokens) > 2:
        return False
    if not (reference_tokens - missing_tokens).issubset(value_tokens):
        return False
    for token in missing_tokens:
        if not re.fullmatch(r"[a-z]{2,6}", token):
            return False
        if not _display_text_supports_initialism(displayed=displayed, initialism=token):
            return False
    return True


def _display_text_supports_initialism(*, displayed: str, initialism: str) -> bool:
    folded = unicodedata.normalize("NFKD", str(displayed or "").casefold())
    folded = "".join(char for char in folded if not unicodedata.combining(char))
    words = [word for word in re.findall(r"[a-z0-9]+", folded) if len(word) > 2]
    if not words:
        return False
    initials = "".join(word[0] for word in words if word)
    return str(initialism or "").casefold() in initials


_SOURCE_REFERENCE_STOP_TOKENS = {
    "a",
    "an",
    "and",
    "as",
    "at",
    "by",
    "for",
    "from",
    "had",
    "has",
    "in",
    "into",
    "is",
    "it",
    "of",
    "on",
    "or",
    "that",
    "the",
    "to",
    "was",
    "were",
    "what",
    "where",
    "which",
    "who",
}


def _without_source_reference_stop_tokens(tokens: set[str]) -> set[str]:
    filtered = {token for token in tokens if token not in _SOURCE_REFERENCE_STOP_TOKENS}
    return filtered or tokens


def _date_reference_supported(*, reference_tokens: set[str], value_tokens: set[str]) -> bool:
    month_numbers = {
        "january": "1",
        "jan": "1",
        "february": "2",
        "feb": "2",
        "march": "3",
        "mar": "3",
        "april": "4",
        "apr": "4",
        "may": "5",
        "june": "6",
        "jun": "6",
        "july": "7",
        "jul": "7",
        "august": "8",
        "aug": "8",
        "september": "9",
        "sep": "9",
        "sept": "9",
        "october": "10",
        "oct": "10",
        "november": "11",
        "nov": "11",
        "december": "12",
        "dec": "12",
    }
    adjusted = set(reference_tokens)
    for month, number in month_numbers.items():
        if month in adjusted and number in value_tokens:
            adjusted.remove(month)
            adjusted.add(number)
    for token in list(adjusted):
        if re.fullmatch(r"20\d{2}", token):
            short_year = token[-2:].lstrip("0") or "0"
            if short_year in value_tokens:
                adjusted.remove(token)
                adjusted.add(short_year)
    return bool(adjusted and adjusted.issubset(value_tokens))


def _value_has_negative_surface(value: str) -> bool:
    text = str(value or "").casefold()
    normalized = re.sub(r"[^a-z0-9]+", "_", text).strip("_")
    if normalized in {"no", "not", "none", "false", "negative"}:
        return True
    negative_forms = (
        "no_",
        "not_",
        "none_",
        "without_",
        "lacks_",
        "lack_of_",
        "does_not_",
        "did_not_",
        "cannot_",
        "can_not_",
    )
    return any(normalized.startswith(form) or f"_{form}" in normalized for form in negative_forms)


def classify_failure_surface(
    *,
    row: dict[str, Any],
    kb_inventory: dict[str, Any],
    facts: list[str],
    rules: list[str],
    config: SemanticIRCallConfig,
) -> dict[str, Any]:
    judge = row.get("reference_judge") if isinstance(row.get("reference_judge"), dict) else {}
    verdict = str(judge.get("verdict", "")).strip()
    if verdict == "exact":
        return {
            "schema_version": "qa_failure_surface_v1",
            "surface": "not_applicable",
            "confidence": 1.0,
            "rationale": "Reference judge marked the row exact.",
            "suggested_next_action": "No failure-surface action needed.",
        }
    reference = str(row.get("reference_answer", "")).strip()
    if not reference:
        return {
            "schema_version": "qa_failure_surface_v1",
            "surface": "judge_uncertain",
            "confidence": 0.2,
            "rationale": "No reference answer was available for failure classification.",
            "suggested_next_action": "Supply a reference answer before classifying the failure surface.",
        }
    registered_missing_surface = _registered_missing_query_signature_failure_surface(
        row=row,
        kb_inventory=kb_inventory,
    )
    if registered_missing_surface is not None:
        return registered_missing_surface
    payload = {
        "task": "Classify the remaining failure surface for a post-ingestion symbolic QA row.",
        "authority": [
            "You are a scorer and diagnostician only.",
            "Do not answer the user.",
            "Do not propose facts, rules, corrections, or writes.",
            "Do not use the original source document; it is not available here.",
            "Use only the compiled KB inventory, admitted clauses, query plan, query results, and reference answer.",
        ],
        "surface_definitions": {
            "compile_surface_gap": "The query plan is reasonable, but the compiled KB appears to lack the facts/rules/relations needed to support the reference answer.",
            "query_surface_gap": "The compiled KB appears to contain useful support, but the emitted query plan did not retrieve it or used neighboring/wrong predicates or overbound constants.",
            "hybrid_join_gap": "Relevant rows were retrieved or appear available, but answering requires a multi-hop join, temporal virtual predicate, set difference, aggregation, arithmetic, or evidence bundle that the current query/runtime did not assemble.",
            "answer_surface_gap": "The query results contain enough support, but the final judge/answer rendering did not recognize or express it cleanly.",
            "judge_uncertain": "There is not enough information in this row to separate the failure surfaces confidently.",
        },
        "question_id": row.get("id", ""),
        "question": row.get("utterance", ""),
        "reference_answer": reference,
        "reference_judge": judge,
        "queries": row.get("queries", []),
        "query_results": row.get("query_results", []),
        "evidence_bundle_plan": row.get("evidence_bundle_plan", {}),
        "compiled_predicate_inventory": {
            "signatures": kb_inventory.get("signatures", [])[:120],
            "counts": kb_inventory.get("counts", {}),
            "examples": kb_inventory.get("examples", {}),
        },
        "relevant_clauses": [*facts[:600], *rules[:160]],
        "classification_policy": [
            "Choose compile_surface_gap when typed admitted facts/rules/relations shown here do not support the reference answer, even if source-display/provenance rows show that the source sentence was seen.",
            "Treat source_record_*_display and source_record_*_support rows as receipt/provenance or legacy diagnostic surfaces, not as proof of typed derivation. They may explain why an old product judge found text, but they do not by themselves make an answer_surface_gap.",
            "Choose query_surface_gap when relevant support appears in admitted clauses or inventory examples but the emitted query set did not retrieve it.",
            "Choose hybrid_join_gap when rows are present or retrieved but require joining, comparing, counting, set subtraction, temporal arithmetic, or aggregation.",
            "Choose answer_surface_gap only when returned rows are plainly sufficient and the remaining problem is interpretation or wording.",
            "If uncertain, use judge_uncertain with low confidence.",
        ],
    }
    payload = _failure_surface_payload(
        row=row,
        reference=reference,
        judge=judge,
        kb_inventory=kb_inventory,
        facts=facts,
        rules=rules,
    )
    messages = [
        {
            "role": "system",
            "content": (
                "You classify post-ingestion QA failure surfaces for a governed symbolic KB. "
                "Return qa_failure_surface_v1 JSON only. Do not use outside knowledge or the source document."
            ),
        },
        {"role": "user", "content": "INPUT_JSON:\n" + json.dumps(payload, ensure_ascii=False, indent=2)},
    ]
    try:
        return call_lmstudio_json_schema(
            config=config,
            messages=messages,
            schema_name="qa_failure_surface_v1",
            schema=FAILURE_SURFACE_SCHEMA,
            max_tokens=min(int(config.max_tokens), 1000),
        )
    except Exception as exc:
        return {
            "schema_version": "qa_failure_surface_v1",
            "surface": "judge_uncertain",
            "confidence": 0.0,
            "rationale": f"classifier error: {str(exc)[:440]}",
            "suggested_next_action": "Inspect the row manually or rerun the failure classifier.",
        }


def _registered_missing_query_signature_failure_surface(
    *,
    row: dict[str, Any],
    kb_inventory: dict[str, Any],
) -> dict[str, Any] | None:
    query_results = row.get("query_results")
    if not isinstance(query_results, list) or not query_results:
        return None
    if any(
        isinstance(item, dict)
        and isinstance(item.get("result"), dict)
        and item["result"].get("status") == "success"
        for item in query_results
    ):
        return None
    inventory_signatures = {
        str(item).strip()
        for item in kb_inventory.get("signatures", [])
        if str(item).strip()
    } if isinstance(kb_inventory.get("signatures"), list) else set()
    missing_signatures: list[str] = []
    seen: set[str] = set()
    for item in query_results:
        if not isinstance(item, dict):
            continue
        result = item.get("result")
        if not isinstance(result, dict) or result.get("status") != "error":
            continue
        message = str(result.get("message", ""))
        reasoning = result.get("reasoning_basis") if isinstance(result.get("reasoning_basis"), dict) else {}
        signature_candidates = [
            str(sig).strip()
            for sig in reasoning.get("query_signatures", [])
            if str(sig).strip()
        ] if isinstance(reasoning.get("query_signatures"), list) else []
        if not signature_candidates:
            parsed = parse_prolog_query(str(item.get("query", "")))
            if parsed is not None:
                predicate, args = parsed
                signature_candidates = [f"{predicate}/{len(args)}"]
        for signature in signature_candidates:
            if (
                signature
                and signature not in seen
                and signature not in inventory_signatures
                and carrier_contract(signature) is not None
                and "not in compiled inventory" in message
            ):
                seen.add(signature)
                missing_signatures.append(signature)
    if not missing_signatures:
        return None
    return {
        "schema_version": "qa_failure_surface_v1",
        "surface": "compile_surface_gap",
        "confidence": 0.9,
        "rationale": (
            "The atom-grounded query plan selected registered carrier signatures that are absent from the "
            f"compiled KB inventory: {', '.join(missing_signatures)}. This is compile-recall pressure, not a "
            "query-runtime failure."
        ),
        "suggested_next_action": (
            "Inspect registered-carrier delivery/accountability for the missing signatures and improve typed "
            "compile recall before adding query-side recovery."
        ),
    }


def call_lmstudio_json_schema(
    *,
    config: SemanticIRCallConfig,
    messages: list[dict[str, str]],
    schema_name: str,
    schema: dict[str, Any],
    max_tokens: int,
) -> dict[str, Any]:
    base_url = str(config.base_url or "").rstrip("/")
    endpoint = f"{base_url}/chat/completions" if base_url.endswith("/v1") else f"{base_url}/v1/chat/completions"
    request_messages = [dict(message) for message in messages]
    if not bool(config.think_enabled):
        for message in request_messages:
            if message.get("role") == "system":
                content = str(message.get("content") or "")
                if not content.lstrip().startswith("/no_think"):
                    message["content"] = "/no_think\n" + content
                break
    payload: dict[str, Any] = {
        "model": config.model,
        "messages": request_messages,
        "temperature": float(config.temperature),
        "top_p": float(config.top_p),
        "max_tokens": int(max_tokens),
        "think": bool(config.think_enabled),
        "thinking": bool(config.think_enabled),
        "response_format": {
            "type": "json_schema",
            "json_schema": {
                "name": schema_name,
                "strict": True,
                "schema": schema,
            },
        },
    }
    if str(config.reasoning_effort or "").strip():
        payload["reasoning_effort"] = str(config.reasoning_effort).strip()
    if _is_openrouter_base_url(config.base_url) and not bool(config.think_enabled):
        payload["reasoning"] = {"effort": "none", "exclude": True}
        payload["include_reasoning"] = False
        provider_routing = openrouter_provider_routing_from_env()
        if provider_routing:
            payload["provider"] = provider_routing
    req = urllib.request.Request(
        endpoint,
        data=json.dumps(payload).encode("utf-8"),
        headers=_chat_headers(config.api_key, base_url=config.base_url),
        method="POST",
    )
    raw = _urlopen_json_with_transient_retries(
        req,
        timeout=int(config.timeout),
        retry_transient=_is_openrouter_base_url(config.base_url),
    )
    openrouter_metadata = openrouter_generation_metadata(
        raw_response=raw,
        request_payload=payload,
        api_key=config.api_key,
        base_url=config.base_url,
        timeout=min(int(config.timeout), 30),
        call_role=schema_name,
    )
    if openrouter_metadata:
        OPENROUTER_CALL_METADATA_LOG.append(openrouter_metadata)
    choices = raw.get("choices", []) if isinstance(raw, dict) else []
    first = choices[0] if choices and isinstance(choices[0], dict) else {}
    message = first.get("message", {}) if isinstance(first, dict) else {}
    content = str(message.get("content", "") if isinstance(message, dict) else "").strip()
    parsed = json.loads(content)
    if not isinstance(parsed, dict):
        raise RuntimeError("structured judge returned non-object JSON")
    return parsed


TRANSIENT_HTTP_STATUS_CODES = {408, 409, 425, 429, 500, 502, 503, 504}


def _urlopen_json_with_transient_retries(
    req: urllib.request.Request,
    *,
    timeout: int,
    retry_transient: bool,
    max_attempts: int = 3,
) -> dict[str, Any]:
    attempts = max(1, int(max_attempts))
    for attempt in range(attempts):
        try:
            with urllib.request.urlopen(req, timeout=int(timeout)) as response:
                raw = json.loads(response.read().decode("utf-8"))
            if not isinstance(raw, dict):
                raise RuntimeError("model endpoint returned non-object JSON")
            return raw
        except urllib.error.HTTPError as exc:
            body = exc.read().decode("utf-8", errors="replace")
            if retry_transient and exc.code in TRANSIENT_HTTP_STATUS_CODES and attempt + 1 < attempts:
                time.sleep(min(2.0, 0.35 * (2**attempt)))
                continue
            raise RuntimeError(f"HTTP {exc.code}: {body}") from exc
        except urllib.error.URLError as exc:
            if retry_transient and attempt + 1 < attempts:
                time.sleep(min(2.0, 0.35 * (2**attempt)))
                continue
            raise RuntimeError(str(exc)) from exc
    raise RuntimeError("model endpoint failed after transient retries")


def _chat_headers(api_key: str = "", *, base_url: str = "") -> dict[str, str]:
    headers = {"Content-Type": "application/json"}
    openrouter_target = not str(base_url or "").strip() or _is_openrouter_base_url(base_url)
    if openrouter_target:
        key = openrouter_api_key(api_key)
    else:
        key = str(api_key or os.environ.get("PRETHINKER_API_KEY") or "").strip()
    if key:
        headers["Authorization"] = f"Bearer {key}"
    if openrouter_target:
        headers.update(openrouter_metadata_headers(base_url))
        referer = _openrouter_referer()
        if referer:
            headers["HTTP-Referer"] = referer
        title = _openrouter_title()
        if title:
            headers["X-Title"] = title
            headers["X-OpenRouter-Title"] = title
    return headers


def _configure_openrouter_title(out_dir: Path) -> None:
    if _openrouter_title():
        return
    os.environ["PRETHINKER_OPENROUTER_TITLE"] = _default_openrouter_title(out_dir)


def _openrouter_title() -> str:
    title = str(
        os.environ.get("PRETHINKER_OPENROUTER_TITLE")
        or os.environ.get("OPENROUTER_APP_TITLE")
        or os.environ.get("OPENROUTER_X_TITLE")
        or ""
    ).strip()
    return _sanitize_header_value(title)


def _openrouter_referer() -> str:
    referer = str(
        os.environ.get("PRETHINKER_OPENROUTER_REFERER")
        or os.environ.get("OPENROUTER_HTTP_REFERER")
        or os.environ.get("OPENROUTER_REFERER")
        or "https://github.com/dr3d/prethinker"
    ).strip()
    return _sanitize_header_value(referer)


def _default_openrouter_title(out_dir: Path) -> str:
    path = out_dir if out_dir.is_absolute() else (REPO_ROOT / out_dir).resolve()
    fixture = path.name or "run"
    return _sanitize_header_value(f"qa:{fixture}")


def _sanitize_header_value(value: str) -> str:
    cleaned = re.sub(r"[^A-Za-z0-9._:/ -]+", "-", str(value or "").strip())
    cleaned = re.sub(r"\s+", " ", cleaned).strip(" -")
    return cleaned[:120]


def _is_openrouter_base_url(base_url: str) -> bool:
    return "openrouter.ai" in str(base_url or "").lower()


def summarize(*, rows: list[dict[str, Any]], load_errors: list[str], elapsed_ms: int) -> dict[str, Any]:
    oracle_rows = [row for row in rows if isinstance(row.get("oracle_match"), bool)]
    judge_rows = [
        row.get("reference_judge")
        for row in rows
        if isinstance(row.get("reference_judge"), dict)
    ]
    failure_surface_counts: dict[str, int] = {}
    response_envelope_counts: dict[str, int] = {}
    for row in rows:
        failure = row.get("failure_surface")
        if not isinstance(failure, dict):
            surface = ""
        else:
            surface = str(failure.get("surface", "")).strip() or "unknown"
        if surface:
            failure_surface_counts[surface] = failure_surface_counts.get(surface, 0) + 1
        envelope = row.get("response_envelope")
        if isinstance(envelope, dict):
            status = str(envelope.get("status", "")).strip() or "unknown"
            response_envelope_counts[status] = response_envelope_counts.get(status, 0) + 1
    compatibility_row_summary = summarize_compatibility_rows(rows)
    return {
        "question_count": len(rows),
        "reference_answer_rows": sum(1 for row in rows if row.get("reference_answer")),
        "parsed_ok": sum(1 for row in rows if row.get("ok")),
        "query_rows": sum(1 for row in rows if row.get("queries")),
        "write_proposal_rows": sum(1 for row in rows if row.get("proposed_facts") or row.get("proposed_rules")),
        "oracle_rows": len(oracle_rows),
        "oracle_match": sum(1 for row in oracle_rows if row.get("oracle_match") is True),
        "judge_rows": len(judge_rows),
        "judge_exact": sum(1 for judge in judge_rows if judge.get("verdict") == "exact"),
        "judge_partial": sum(1 for judge in judge_rows if judge.get("verdict") == "partial"),
        "judge_miss": sum(1 for judge in judge_rows if judge.get("verdict") == "miss"),
        "failure_surface_counts": failure_surface_counts,
        "response_envelope_counts": response_envelope_counts,
        "compatibility_row_summary": compatibility_row_summary,
        "runtime_load_error_count": len(load_errors),
        "elapsed_ms": elapsed_ms,
    }


def summarize_compatibility_rows(rows: list[dict[str, Any]]) -> dict[str, Any]:
    companion_counts: dict[str, Counter[str]] = {}
    companion_rows: Counter[str] = Counter()
    total_counts: Counter[str] = Counter()
    for row in rows:
        for query_result in row.get("query_results", []) or []:
            if not isinstance(query_result, dict):
                continue
            result = query_result.get("result")
            if not isinstance(result, dict):
                continue
            result_rows = result.get("rows")
            if not isinstance(result_rows, list):
                continue
            if not _is_helper_query_result(query_result):
                continue
            classes = [
                _public_compatibility_row_class(str(result_row.get("HelperClass", "") or "unlabeled"))
                for result_row in result_rows
                if isinstance(result_row, dict)
            ]
            if not classes:
                continue
            predicate = str(result.get("predicate", "") or "unknown")
            companion_counts.setdefault(predicate, Counter()).update(classes)
            companion_rows[predicate] += len(classes)
            total_counts.update(classes)
    return {
        "row_count": int(sum(total_counts.values())),
        "row_class_counts": dict(sorted(total_counts.items())),
        "companion_row_totals": dict(sorted(companion_rows.items())),
        "companion_row_class_counts": {
            name: dict(sorted(counts.items()))
            for name, counts in sorted(companion_counts.items())
        },
    }


def _public_compatibility_row_class(row_class: str) -> str:
    if row_class == "clean-helper":
        return "direct"
    if row_class == "candidate-helper":
        return "tentative"
    return row_class or "unlabeled"


def write_summary(record: dict[str, Any], path: Path) -> None:
    summary = record.get("summary", {})
    compatibility_summary = summary.get("compatibility_row_summary", {})
    serving_path = record.get("model_serving_path") if isinstance(record.get("model_serving_path"), dict) else {}
    lines = [
        "# Domain Bootstrap QA Run",
        "",
        f"- Run JSON: `{record.get('run_json', '')}`",
        f"- QA file: `{record.get('qa_file', '')}`",
        f"- Model: `{record.get('model', '')}`",
        f"- Provider family: `{serving_path.get('provider_family', '')}`",
        f"- Base URL: `{serving_path.get('base_url', '')}`",
        f"- Provider routing: `{serving_path.get('provider_routing', {})}`",
        f"- Source facts/rules: `{record.get('source_fact_count', 0)}` / `{record.get('source_rule_count', 0)}`",
        f"- Questions: `{summary.get('question_count', 0)}`",
        f"- Parsed OK: `{summary.get('parsed_ok', 0)}`",
        f"- Rows with queries: `{summary.get('query_rows', 0)}`",
        f"- Rows with proposed writes: `{summary.get('write_proposal_rows', 0)}`",
        f"- Oracle rows/matches: `{summary.get('oracle_rows', 0)}` / `{summary.get('oracle_match', 0)}`",
        f"- Reference judge: exact=`{summary.get('judge_exact', 0)}` partial=`{summary.get('judge_partial', 0)}` miss=`{summary.get('judge_miss', 0)}`",
        f"- Failure surfaces: `{summary.get('failure_surface_counts', {})}`",
        f"- Response envelope statuses: `{summary.get('response_envelope_counts', {})}`",
        f"- Compatibility rows: `{compatibility_summary.get('row_class_counts', {})}` rows=`{compatibility_summary.get('row_count', 0)}`",
        f"- Cache: enabled=`{summary.get('cache_enabled', False)}` hits=`{summary.get('cache_hits', 0)}` misses=`{summary.get('cache_misses', 0)}`",
        "",
    ]
    companion_counts = compatibility_summary.get("companion_row_class_counts", {})
    if companion_counts:
        lines.extend(
            [
                "## Compatibility Rows",
                "",
                "| Companion | Rows | direct | tentative | unlabeled |",
                "| --- | ---: | ---: | ---: | ---: |",
            ]
        )
        row_totals = compatibility_summary.get("companion_row_totals", {})
        for companion, counts in sorted(companion_counts.items()):
            lines.append(
                "| {companion} | {rows} | {clean} | {candidate} | {unlabeled} |".format(
                    companion=companion,
                    rows=row_totals.get(companion, 0),
                    clean=counts.get("direct", 0),
                    candidate=counts.get("tentative", 0),
                    unlabeled=counts.get("unlabeled", 0),
                )
            )
        lines.append("")
    lines.extend([
        "## Rows",
        "",
    ])
    for row in record.get("rows", []):
        lines.extend(
            [
                f"### {row.get('id', '')} - {row.get('utterance', '')}",
                "",
                f"- Phase: `{row.get('phase', '')}`",
                f"- Decision: model=`{row.get('model_decision', '')}` projected=`{row.get('projected_decision', '')}`",
                f"- Response envelope: `{(row.get('response_envelope') or {}).get('status', None)}`",
                f"- Queries: `{row.get('queries', [])}`",
                f"- Proposed writes: facts=`{len(row.get('proposed_facts', []) or [])}` rules=`{len(row.get('proposed_rules', []) or [])}`",
                f"- Oracle match: `{row.get('oracle_match', None)}`",
                f"- Reference answer: {row.get('reference_answer', '') or '-'}",
                f"- Reference judge: `{(row.get('reference_judge') or {}).get('verdict', None)}`",
                f"- Failure surface: `{(row.get('failure_surface') or {}).get('surface', None)}`",
                "",
                "```json",
                json.dumps(row.get("query_results", []), ensure_ascii=False, indent=2),
                "```",
                "",
            ]
        )
    path.write_text("\n".join(lines), encoding="utf-8")


def _slug(value: str) -> str:
    text = re.sub(r"[^a-zA-Z0-9]+", "-", str(value or "").strip()).strip("-").lower()
    return text[:60] or "run"


if __name__ == "__main__":
    raise SystemExit(main())
